#[derive(Debug, Clone)]
pub struct ServiceConfig {
    pub listen_addr: SocketAddr,
    pub session_ttl_seconds: u64,
    pub sync_token_ttl_seconds: u64,
    pub sync_token_refresh_after_seconds: u64,
    pub sync_stream_grants: Vec<String>,
    pub hosted_nexus_relay_url: String,
    pub training_trn_identity_path: PathBuf,
    pub training_trn_relay_urls: Vec<String>,
    pub receipt_log_path: Option<PathBuf>,
    pub kernel_state_path: Option<PathBuf>,
    pub compute_enable_forward_physical: bool,
    pub compute_enable_future_cash: bool,
    pub compute_enable_structured_products: bool,
    pub compute_enable_reconciliation_diagnostics: bool,
    pub compute_policy_bundle_id: String,
    pub compute_policy_version: String,
    pub admin_bearer_token: Option<String>,
    pub starter_demand_budget_cap_sats: u64,
    pub starter_demand_dispatch_interval_seconds: u64,
    pub starter_demand_request_ttl_seconds: u64,
    pub starter_demand_max_active_offers_per_session: usize,
    pub starter_demand_start_confirm_seconds: u64,
    pub starter_demand_heartbeat_timeout_seconds: u64,
    pub provider_presence_stale_after_ms: u64,
    pub training_artifact_signed_url: Option<TrainingArtifactSignedUrlConfig>,
    pub treasury: TreasuryConfig,
}

impl ServiceConfig {
    pub fn from_env() -> Result<Self, String> {
        let listen_addr = std::env::var(ENV_LISTEN_ADDR)
            .ok()
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| DEFAULT_LISTEN_ADDR.to_string())
            .parse::<SocketAddr>()
            .map_err(|error| format!("invalid {ENV_LISTEN_ADDR}: {error}"))?;
        let session_ttl_seconds =
            parse_u64_env(ENV_SESSION_TTL_SECONDS, DEFAULT_SESSION_TTL_SECONDS)?;
        let sync_token_ttl_seconds =
            parse_u64_env(ENV_SYNC_TOKEN_TTL_SECONDS, DEFAULT_SYNC_TOKEN_TTL_SECONDS)?;
        let sync_token_refresh_after_seconds = parse_u64_env(
            ENV_SYNC_TOKEN_REFRESH_AFTER_SECONDS,
            DEFAULT_SYNC_TOKEN_REFRESH_AFTER_SECONDS,
        )?;
        if sync_token_refresh_after_seconds == 0 {
            return Err(format!(
                "{ENV_SYNC_TOKEN_REFRESH_AFTER_SECONDS} must be greater than zero"
            ));
        }
        if sync_token_refresh_after_seconds >= sync_token_ttl_seconds {
            return Err(format!(
                "{ENV_SYNC_TOKEN_REFRESH_AFTER_SECONDS} must be less than {ENV_SYNC_TOKEN_TTL_SECONDS}"
            ));
        }

        let sync_stream_grants = std::env::var(ENV_SYNC_STREAM_GRANTS)
            .ok()
            .map(|value| {
                value
                    .split(',')
                    .map(str::trim)
                    .filter(|item| !item.is_empty())
                    .map(ToOwned::to_owned)
                    .collect::<Vec<_>>()
            })
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| {
                DEFAULT_SYNC_STREAM_GRANTS
                    .iter()
                    .map(|value| value.to_string())
                    .collect()
            });

        let hosted_nexus_relay_url = std::env::var(ENV_HOSTED_NEXUS_RELAY_URL)
            .ok()
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| DEFAULT_HOSTED_NEXUS_RELAY_URL.to_string());
        let training_trn_identity_path = std::env::var(ENV_TRAINING_TRN_IDENTITY_PATH)
            .ok()
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
            .map(PathBuf::from)
            .unwrap_or_else(|| PathBuf::from(DEFAULT_TRAINING_TRN_IDENTITY_PATH));
        let training_trn_relay_urls = std::env::var(ENV_TRAINING_TRN_RELAY_URLS)
            .ok()
            .map(|value| {
                value
                    .split(',')
                    .map(str::trim)
                    .filter(|item| !item.is_empty())
                    .map(ToOwned::to_owned)
                    .collect::<Vec<_>>()
            })
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| vec![hosted_nexus_relay_url.clone()]);
        let receipt_log_path = std::env::var(ENV_RECEIPT_LOG_PATH)
            .ok()
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
            .map(PathBuf::from);
        let kernel_state_path = std::env::var(ENV_KERNEL_STATE_PATH)
            .ok()
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
            .map(PathBuf::from)
            .or_else(|| Some(PathBuf::from(DEFAULT_KERNEL_STATE_PATH)));
        let compute_enable_forward_physical =
            parse_bool_env(ENV_COMPUTE_ENABLE_FORWARD_PHYSICAL, true)?;
        let compute_enable_future_cash = parse_bool_env(ENV_COMPUTE_ENABLE_FUTURE_CASH, true)?;
        let compute_enable_structured_products =
            parse_bool_env(ENV_COMPUTE_ENABLE_STRUCTURED_PRODUCTS, true)?;
        let compute_enable_reconciliation_diagnostics =
            parse_bool_env(ENV_COMPUTE_ENABLE_RECONCILIATION_DIAGNOSTICS, true)?;
        let compute_policy_bundle_id = std::env::var(ENV_COMPUTE_POLICY_BUNDLE_ID)
            .ok()
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| DEFAULT_COMPUTE_POLICY_BUNDLE_ID.to_string());
        let compute_policy_version = std::env::var(ENV_COMPUTE_POLICY_VERSION)
            .ok()
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| DEFAULT_COMPUTE_POLICY_VERSION.to_string());
        let admin_bearer_token = std::env::var(ENV_ADMIN_BEARER_TOKEN)
            .ok()
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty());
        let starter_demand_budget_cap_sats = parse_u64_env(
            ENV_STARTER_DEMAND_BUDGET_CAP_SATS,
            DEFAULT_STARTER_DEMAND_BUDGET_CAP_SATS,
        )?
        .max(1);
        let starter_demand_dispatch_interval_seconds = parse_u64_env(
            ENV_STARTER_DEMAND_DISPATCH_INTERVAL_SECONDS,
            DEFAULT_STARTER_DEMAND_DISPATCH_INTERVAL_SECONDS,
        )?;
        let starter_demand_request_ttl_seconds = parse_u64_env(
            ENV_STARTER_DEMAND_REQUEST_TTL_SECONDS,
            DEFAULT_STARTER_DEMAND_REQUEST_TTL_SECONDS,
        )?;
        let starter_demand_max_active_offers_per_session = parse_usize_env(
            ENV_STARTER_DEMAND_MAX_ACTIVE_OFFERS_PER_SESSION,
            DEFAULT_STARTER_DEMAND_MAX_ACTIVE_OFFERS_PER_SESSION,
        )?;
        let starter_demand_start_confirm_seconds = parse_u64_env(
            ENV_STARTER_DEMAND_START_CONFIRM_SECONDS,
            DEFAULT_STARTER_DEMAND_START_CONFIRM_SECONDS,
        )?;
        let starter_demand_heartbeat_timeout_seconds = parse_u64_env(
            ENV_STARTER_DEMAND_HEARTBEAT_TIMEOUT_SECONDS,
            DEFAULT_STARTER_DEMAND_HEARTBEAT_TIMEOUT_SECONDS,
        )?;
        let provider_presence_stale_after_ms = parse_u64_env(
            ENV_PROVIDER_PRESENCE_STALE_AFTER_MS,
            DEFAULT_PROVIDER_PRESENCE_STALE_AFTER_MS,
        )?;
        let training_artifact_signed_url = training_artifact_signed_url_config_from_env()?;
        if starter_demand_dispatch_interval_seconds == 0 {
            return Err(format!(
                "{ENV_STARTER_DEMAND_DISPATCH_INTERVAL_SECONDS} must be greater than zero"
            ));
        }
        if starter_demand_request_ttl_seconds == 0 {
            return Err(format!(
                "{ENV_STARTER_DEMAND_REQUEST_TTL_SECONDS} must be greater than zero"
            ));
        }
        if starter_demand_max_active_offers_per_session == 0 {
            return Err(format!(
                "{ENV_STARTER_DEMAND_MAX_ACTIVE_OFFERS_PER_SESSION} must be greater than zero"
            ));
        }
        if starter_demand_start_confirm_seconds == 0 {
            return Err(format!(
                "{ENV_STARTER_DEMAND_START_CONFIRM_SECONDS} must be greater than zero"
            ));
        }
        if starter_demand_start_confirm_seconds >= starter_demand_request_ttl_seconds {
            return Err(format!(
                "{ENV_STARTER_DEMAND_START_CONFIRM_SECONDS} must be less than {ENV_STARTER_DEMAND_REQUEST_TTL_SECONDS}"
            ));
        }
        if starter_demand_heartbeat_timeout_seconds == 0 {
            return Err(format!(
                "{ENV_STARTER_DEMAND_HEARTBEAT_TIMEOUT_SECONDS} must be greater than zero"
            ));
        }
        if starter_demand_heartbeat_timeout_seconds >= starter_demand_request_ttl_seconds {
            return Err(format!(
                "{ENV_STARTER_DEMAND_HEARTBEAT_TIMEOUT_SECONDS} must be less than {ENV_STARTER_DEMAND_REQUEST_TTL_SECONDS}"
            ));
        }
        if provider_presence_stale_after_ms < DEFAULT_PROVIDER_PRESENCE_HEARTBEAT_INTERVAL_MS {
            return Err(format!(
                "{ENV_PROVIDER_PRESENCE_STALE_AFTER_MS} must be at least {DEFAULT_PROVIDER_PRESENCE_HEARTBEAT_INTERVAL_MS}"
            ));
        }
        let treasury = TreasuryConfig::from_env()?;

        Ok(Self {
            listen_addr,
            session_ttl_seconds,
            sync_token_ttl_seconds,
            sync_token_refresh_after_seconds,
            sync_stream_grants,
            hosted_nexus_relay_url,
            training_trn_identity_path,
            training_trn_relay_urls,
            receipt_log_path,
            kernel_state_path,
            compute_enable_forward_physical,
            compute_enable_future_cash,
            compute_enable_structured_products,
            compute_enable_reconciliation_diagnostics,
            compute_policy_bundle_id,
            compute_policy_version,
            admin_bearer_token,
            starter_demand_budget_cap_sats,
            starter_demand_dispatch_interval_seconds,
            starter_demand_request_ttl_seconds,
            starter_demand_max_active_offers_per_session,
            starter_demand_start_confirm_seconds,
            starter_demand_heartbeat_timeout_seconds,
            provider_presence_stale_after_ms,
            training_artifact_signed_url,
            treasury,
        })
    }
}

fn training_artifact_signed_url_config_from_env()
-> Result<Option<TrainingArtifactSignedUrlConfig>, String> {
    let bucket_uri = std::env::var(ENV_TRAINING_GCS_BUCKET_URI)
        .ok()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    let Some(bucket_uri) = bucket_uri else {
        return Ok(None);
    };
    let endpoint = std::env::var(ENV_TRAINING_GCS_ENDPOINT)
        .ok()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| DEFAULT_TRAINING_GCS_ENDPOINT.to_string());
    Url::parse(endpoint.as_str())
        .map_err(|error| format!("invalid {ENV_TRAINING_GCS_ENDPOINT}: {error}"))?;
    let default_ttl_seconds = parse_u64_env(
        ENV_TRAINING_GCS_SIGNED_URL_TTL_SECONDS,
        DEFAULT_TRAINING_GCS_SIGNED_URL_TTL_SECONDS,
    )?;
    let max_ttl_seconds = parse_u64_env(
        ENV_TRAINING_GCS_SIGNED_URL_MAX_TTL_SECONDS,
        DEFAULT_TRAINING_GCS_SIGNED_URL_MAX_TTL_SECONDS,
    )?;
    if default_ttl_seconds == 0 || max_ttl_seconds == 0 || default_ttl_seconds > max_ttl_seconds {
        return Err("training artifact signed-url ttl configuration is invalid".to_string());
    }
    let credentials_path = std::env::var(ENV_TRAINING_GCS_SIGNING_CREDENTIALS_PATH)
        .ok()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .or_else(|| {
            std::env::var(ENV_GOOGLE_APPLICATION_CREDENTIALS)
                .ok()
                .map(|value| value.trim().to_string())
                .filter(|value| !value.is_empty())
        })
        .map(PathBuf::from)
        .ok_or_else(|| {
            format!(
                "{ENV_TRAINING_GCS_SIGNING_CREDENTIALS_PATH} or {ENV_GOOGLE_APPLICATION_CREDENTIALS} must be set when {ENV_TRAINING_GCS_BUCKET_URI} is configured"
            )
        })?;
    Ok(Some(TrainingArtifactSignedUrlConfig {
        bucket_uri,
        endpoint,
        credentials_path,
        default_ttl_seconds,
        max_ttl_seconds,
    }))
}

fn issue_training_artifact_signed_access(
    config: &TrainingArtifactSignedUrlConfig,
    resolver: &PylonTrainingArtifactResolverResponse,
    request: &PylonTrainingArtifactSignedAccessRequest,
    issued_at_unix: u64,
) -> Result<PylonTrainingArtifactSignedAccessResponse, String> {
    let ttl_seconds =
        request.effective_ttl_seconds(config.default_ttl_seconds, config.max_ttl_seconds)?;
    let signed_url = build_google_cloud_storage_signed_url(
        config,
        resolver,
        request,
        issued_at_unix,
        ttl_seconds,
    )?;
    PylonTrainingArtifactSignedAccessResponse::new(
        resolver,
        request,
        signed_url,
        issued_at_unix,
        ttl_seconds,
    )
}

fn build_google_cloud_storage_signed_url(
    config: &TrainingArtifactSignedUrlConfig,
    resolver: &PylonTrainingArtifactResolverResponse,
    request: &PylonTrainingArtifactSignedAccessRequest,
    issued_at_unix: u64,
    ttl_seconds: u64,
) -> Result<String, String> {
    let credentials = load_training_artifact_signing_credentials(&config.credentials_path)?;
    let object_uri = pylon_training_artifact_object_uri(config.bucket_uri.as_str(), resolver)?;
    let bucket_name = parse_training_gcs_bucket_name(config.bucket_uri.as_str())?;
    let object_path = parse_training_gcs_object_path(object_uri.as_str(), bucket_name.as_str())?;
    let endpoint = Url::parse(config.endpoint.as_str()).map_err(|error| {
        format!("compute_training_artifact_signed_access_endpoint_invalid:{error}")
    })?;
    let host = endpoint.host_str().ok_or_else(|| {
        "compute_training_artifact_signed_access_endpoint_host_missing".to_string()
    })?;
    let authority = endpoint
        .port()
        .map_or_else(|| host.to_string(), |port| format!("{host}:{port}"));
    let endpoint_path = endpoint.path().trim_end_matches('/');
    let encoded_object_path = percent_encode_path(object_path.as_str());
    let canonical_uri = if endpoint_path.is_empty() || endpoint_path == "/" {
        format!("/{bucket_name}/{encoded_object_path}")
    } else {
        format!("{endpoint_path}/{bucket_name}/{encoded_object_path}")
    };
    let timestamp = Utc
        .timestamp_opt(issued_at_unix as i64, 0)
        .single()
        .ok_or_else(|| "compute_training_artifact_signed_access_time_invalid".to_string())?;
    let date_stamp = timestamp.format("%Y%m%d").to_string();
    let goog_date = timestamp.format("%Y%m%dT%H%M%SZ").to_string();
    let credential_scope = format!("{date_stamp}/auto/storage/goog4_request");
    let credential = format!("{}/{}", credentials.client_email, credential_scope);
    let mut query_pairs = vec![
        (
            "X-Goog-Algorithm".to_string(),
            "GOOG4-RSA-SHA256".to_string(),
        ),
        ("X-Goog-Credential".to_string(), credential),
        ("X-Goog-Date".to_string(), goog_date.clone()),
        ("X-Goog-Expires".to_string(), ttl_seconds.to_string()),
        ("X-Goog-SignedHeaders".to_string(), "host".to_string()),
    ];
    query_pairs.sort();
    let canonical_query = query_pairs
        .iter()
        .map(|(key, value)| {
            format!(
                "{}={}",
                percent_encode_query_component(key.as_str()),
                percent_encode_query_component(value.as_str())
            )
        })
        .collect::<Vec<_>>()
        .join("&");
    let canonical_headers = format!("host:{authority}\n");
    let method = match request.mode.method() {
        openagents_kernel_core::pylon_training::PylonTrainingArtifactSignedAccessMethod::Get => {
            "GET"
        }
        openagents_kernel_core::pylon_training::PylonTrainingArtifactSignedAccessMethod::Put => {
            "PUT"
        }
    };
    let canonical_request = format!(
        "{method}\n{canonical_uri}\n{canonical_query}\n{canonical_headers}\nhost\nUNSIGNED-PAYLOAD"
    );
    let canonical_request_hash = hex::encode(Sha256::digest(canonical_request.as_bytes()));
    let string_to_sign =
        format!("GOOG4-RSA-SHA256\n{goog_date}\n{credential_scope}\n{canonical_request_hash}");
    let signature =
        sign_google_storage_string(credentials.private_key.as_str(), string_to_sign.as_bytes())?;
    Ok(format!(
        "{}://{}{}?{}&X-Goog-Signature={signature}",
        endpoint.scheme(),
        authority,
        canonical_uri,
        canonical_query
    ))
}

fn load_training_artifact_signing_credentials(
    path: &PathBuf,
) -> Result<GoogleServiceAccountCredential, String> {
    let payload = fs::read_to_string(path).map_err(|error| {
        format!(
            "compute_training_artifact_signed_access_credentials_read_failed:{}:{error}",
            path.display()
        )
    })?;
    let credentials: GoogleServiceAccountCredential = serde_json::from_str(payload.as_str())
        .map_err(|error| {
            format!(
                "compute_training_artifact_signed_access_credentials_invalid:{}:{error}",
                path.display()
            )
        })?;
    if credentials.client_email.trim().is_empty() || credentials.private_key.trim().is_empty() {
        return Err(
            "compute_training_artifact_signed_access_credentials_fields_missing".to_string(),
        );
    }
    Ok(credentials)
}

fn parse_training_gcs_bucket_name(bucket_uri: &str) -> Result<String, String> {
    let normalized = bucket_uri.trim().trim_end_matches('/');
    let bucket_name = normalized
        .strip_prefix("gs://")
        .ok_or_else(|| "compute_training_artifact_bucket_uri_invalid".to_string())?;
    if bucket_name.is_empty() || bucket_name.contains('/') {
        return Err("compute_training_artifact_bucket_uri_invalid".to_string());
    }
    Ok(bucket_name.to_string())
}

fn parse_training_gcs_object_path(object_uri: &str, bucket_name: &str) -> Result<String, String> {
    let prefix = format!("gs://{bucket_name}/");
    let object_path = object_uri
        .strip_prefix(prefix.as_str())
        .ok_or_else(|| "compute_training_artifact_object_uri_invalid".to_string())?;
    if object_path.is_empty() {
        return Err("compute_training_artifact_object_path_missing".to_string());
    }
    Ok(object_path.to_string())
}

fn sign_google_storage_string(private_key_pem: &str, payload: &[u8]) -> Result<String, String> {
    let key_der = decode_private_key_der(private_key_pem)?;
    let key_pair = RsaKeyPair::from_pkcs8(key_der.as_slice())
        .map_err(|_| "compute_training_artifact_signing_key_invalid".to_string())?;
    let mut signature_bytes = vec![0_u8; key_pair.public().modulus_len()];
    key_pair
        .sign(
            &signature::RSA_PKCS1_SHA256,
            &SystemRandom::new(),
            payload,
            signature_bytes.as_mut_slice(),
        )
        .map_err(|_| "compute_training_artifact_signing_failed".to_string())?;
    Ok(hex::encode(signature_bytes))
}

fn decode_private_key_der(private_key_pem: &str) -> Result<Vec<u8>, String> {
    let payload = private_key_pem
        .lines()
        .map(str::trim)
        .filter(|line| !line.is_empty() && !line.starts_with("-----"))
        .collect::<String>();
    base64::engine::general_purpose::STANDARD
        .decode(payload.as_bytes())
        .map_err(|error| format!("compute_training_artifact_signing_key_base64_invalid:{error}"))
}

fn percent_encode_query_component(value: &str) -> String {
    percent_encode_bytes(value.as_bytes())
}

fn percent_encode_path(value: &str) -> String {
    value
        .split('/')
        .map(percent_encode_query_component)
        .collect::<Vec<_>>()
        .join("/")
}

fn percent_encode_bytes(bytes: &[u8]) -> String {
    let mut output = String::with_capacity(bytes.len());
    for byte in bytes {
        match byte {
            b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'-' | b'_' | b'.' | b'~' => {
                output.push(char::from(*byte));
            }
            _ => output.push_str(format!("%{:02X}", byte).as_str()),
        }
    }
    output
}

