fn provider_presence_record_is_inference_ready(record: &ProviderPresenceRecord) -> bool {
    let ready_model = record.ready_model.as_deref().or(record
        .hosting_telemetry
        .availability
        .local_gemma
        .ready_model
        .as_deref());
    if ready_model.is_none() {
        return false;
    }
    if record.hosting_telemetry.availability.local_gemma.ready {
        return true;
    }
    record.hosting_telemetry.inventory_rows.iter().any(|row| {
        row.backend_ready
            && row.eligible
            && row.available_quantity > 0
            && row.delivery_state.eq_ignore_ascii_case("open")
    })
}

fn provider_presence_host_fingerprint(record: &ProviderPresenceRecord) -> Option<String> {
    let host = record.hosting_telemetry.host.as_ref()?;
    let memory_total_bytes = host
        .memory
        .as_ref()
        .map(|memory| memory.total_bytes)
        .unwrap_or(0);
    let gpu_summary = host
        .gpus
        .iter()
        .map(|gpu| {
            format!(
                "{}:{}",
                gpu.model,
                gpu.memory_total_label.as_deref().unwrap_or("")
            )
        })
        .collect::<Vec<_>>()
        .join("|");
    let payload = format!(
        "{}|{}|{}|{}|{}|{}",
        host.host_name.as_deref().unwrap_or(""),
        host.cpu_brand.as_deref().unwrap_or(""),
        host.cpu_arch.as_deref().unwrap_or(""),
        host.logical_cpu_count,
        memory_total_bytes,
        gpu_summary
    );
    if payload
        .chars()
        .all(|ch| ch == '|' || ch == '0' || ch.is_ascii_whitespace())
    {
        return None;
    }
    Some(sha256_prefixed_bytes(payload.as_bytes()))
}

impl ProviderPresenceState {
    fn record_heartbeat(
        &mut self,
        request: ProviderPresenceHeartbeatRequest,
        recorded_at_unix_ms: u64,
    ) -> ProviderPresenceRecord {
        self.prune(recorded_at_unix_ms);
        let record = ProviderPresenceRecord {
            nostr_pubkey_hex: request.nostr_pubkey_hex,
            session_id: request.session_id,
            node_label: normalize_optional_field(request.node_label.as_deref()),
            client_version: normalize_optional_field(request.client_version.as_deref()),
            relay_urls: normalize_string_vec(request.relay_urls),
            products: normalize_string_vec(request.products),
            eligible_product_count: request.eligible_product_count,
            ready_model: normalize_optional_field(request.ready_model.as_deref()),
            runtime_state: normalize_optional_field(request.runtime_state.as_deref()),
            diagnostic_summaries: normalize_provider_diagnostic_summaries(
                request.diagnostic_summaries,
            ),
            hosting_telemetry: request.hosting_telemetry,
            training_capability_envelope_v2: request.training_capability_envelope_v2,
            online: true,
            last_seen_at_unix_ms: recorded_at_unix_ms,
        };
        self.rows_by_key.insert(
            provider_presence_key(record.nostr_pubkey_hex.as_str(), record.session_id.as_str()),
            record.clone(),
        );
        record
    }

    fn record_offline(
        &mut self,
        nostr_pubkey_hex: String,
        session_id: String,
        recorded_at_unix_ms: u64,
    ) -> ProviderPresenceRecord {
        self.prune(recorded_at_unix_ms);
        let key = provider_presence_key(nostr_pubkey_hex.as_str(), session_id.as_str());
        let mut record = self
            .rows_by_key
            .get(&key)
            .cloned()
            .unwrap_or(ProviderPresenceRecord {
                nostr_pubkey_hex,
                session_id,
                node_label: None,
                client_version: None,
                relay_urls: Vec::new(),
                products: Vec::new(),
                eligible_product_count: 0,
                ready_model: None,
                runtime_state: None,
                diagnostic_summaries: Vec::new(),
                hosting_telemetry: ProviderHostingTelemetrySnapshot::default(),
                training_capability_envelope_v2: None,
                online: false,
                last_seen_at_unix_ms: recorded_at_unix_ms,
            });
        record.online = false;
        record.last_seen_at_unix_ms = recorded_at_unix_ms;
        self.rows_by_key.insert(key, record.clone());
        record
    }

    fn prune(&mut self, now_unix_ms: u64) {
        let oldest_allowed = now_unix_ms.saturating_sub(PROVIDER_PRESENCE_RETENTION_WINDOW_MS);
        self.rows_by_key
            .retain(|_, record| record.last_seen_at_unix_ms >= oldest_allowed);
    }

    fn has_live_session(
        &self,
        nostr_pubkey_hex: &str,
        session_id: &str,
        now_unix_ms: u64,
        stale_after_ms: u64,
    ) -> bool {
        let stale_cutoff = now_unix_ms.saturating_sub(stale_after_ms);
        self.rows_by_key.values().any(|record| {
            record.nostr_pubkey_hex == nostr_pubkey_hex
                && record.session_id == session_id
                && record.online
                && record.last_seen_at_unix_ms >= stale_cutoff
        })
    }

    fn online_identities(&self, now_unix_ms: u64, stale_after_ms: u64) -> Vec<OnlinePylonIdentity> {
        let stale_cutoff = now_unix_ms.saturating_sub(stale_after_ms);
        let mut identities =
            BTreeMap::<String, (bool, Option<String>, bool, Option<String>, u64)>::new();
        for record in self.rows_by_key.values() {
            if !(record.online && record.last_seen_at_unix_ms >= stale_cutoff) {
                continue;
            }
            let inference_ready = provider_presence_record_is_inference_ready(record);
            let host_fingerprint = provider_presence_host_fingerprint(record);
            identities
                .entry(record.nostr_pubkey_hex.clone())
                .and_modify(
                    |(
                        sellable,
                        client_version,
                        aggregated_inference_ready,
                        aggregated_host_fingerprint,
                        last_seen_at_unix_ms,
                    )| {
                        *sellable |= record.eligible_product_count > 0;
                        *aggregated_inference_ready |= inference_ready;
                        if record.last_seen_at_unix_ms >= *last_seen_at_unix_ms {
                            *client_version = record.client_version.clone();
                            *aggregated_host_fingerprint = host_fingerprint.clone();
                            *last_seen_at_unix_ms = record.last_seen_at_unix_ms;
                        }
                    },
                )
                .or_insert((
                    record.eligible_product_count > 0,
                    record.client_version.clone(),
                    inference_ready,
                    host_fingerprint,
                    record.last_seen_at_unix_ms,
                ));
        }
        identities
            .into_iter()
            .map(
                |(
                    nostr_pubkey_hex,
                    (sellable, client_version, inference_ready, host_fingerprint, _),
                )| OnlinePylonIdentity {
                    nostr_pubkey_hex,
                    sellable,
                    client_version,
                    inference_ready,
                    host_fingerprint,
                },
            )
            .collect()
    }

    fn metrics(&self, now_unix_ms: u64, stale_after_ms: u64) -> ProviderPresenceMetrics {
        let stale_cutoff = now_unix_ms.saturating_sub(stale_after_ms);
        let seen_cutoff = now_unix_ms.saturating_sub(PROVIDER_PRESENCE_RETENTION_WINDOW_MS);
        let mut online_identities = HashSet::new();
        let mut seen_identities = HashSet::new();
        let mut sellable_identities = HashSet::new();
        let mut inference_ready_identities = HashSet::new();
        let mut pylon_sessions_online_now = 0u64;
        let mut inference_ready_pylon_sessions_online_now = 0u64;
        let mut pylon_sessions_missing_host_fingerprint_online_now = 0u64;
        let mut host_session_counts = BTreeMap::<String, u64>::new();
        let mut host_identity_sets = BTreeMap::<String, BTreeSet<String>>::new();

        for record in self.rows_by_key.values() {
            if record.last_seen_at_unix_ms >= seen_cutoff {
                seen_identities.insert(record.nostr_pubkey_hex.clone());
            }
            if record.online && record.last_seen_at_unix_ms >= stale_cutoff {
                let inference_ready = provider_presence_record_is_inference_ready(record);
                let host_fingerprint = provider_presence_host_fingerprint(record);
                online_identities.insert(record.nostr_pubkey_hex.clone());
                pylon_sessions_online_now = pylon_sessions_online_now.saturating_add(1);
                if record.eligible_product_count > 0 {
                    sellable_identities.insert(record.nostr_pubkey_hex.clone());
                }
                if inference_ready {
                    inference_ready_identities.insert(record.nostr_pubkey_hex.clone());
                    inference_ready_pylon_sessions_online_now =
                        inference_ready_pylon_sessions_online_now.saturating_add(1);
                }
                if let Some(host_fingerprint) = host_fingerprint {
                    *host_session_counts
                        .entry(host_fingerprint.clone())
                        .or_default() += 1;
                    host_identity_sets
                        .entry(host_fingerprint)
                        .or_default()
                        .insert(record.nostr_pubkey_hex.clone());
                } else {
                    pylon_sessions_missing_host_fingerprint_online_now =
                        pylon_sessions_missing_host_fingerprint_online_now.saturating_add(1);
                }
            }
        }
        let likely_same_host_pylon_sessions_online_now = host_session_counts
            .values()
            .map(|count| count.saturating_sub(1))
            .sum::<u64>();
        let likely_same_host_pylons_online_now = host_identity_sets
            .values()
            .map(|identities| identities.len().saturating_sub(1) as u64)
            .sum::<u64>();

        let mut recent_pylons = self.rows_by_key.values().cloned().collect::<Vec<_>>();
        recent_pylons.sort_by(|left, right| {
            right
                .last_seen_at_unix_ms
                .cmp(&left.last_seen_at_unix_ms)
                .then_with(|| left.session_id.cmp(&right.session_id))
        });
        recent_pylons.truncate(PUBLIC_RECENT_PYLON_LIMIT);

        let mut recent_pylon_diagnostics = Vec::new();
        for record in &recent_pylons {
            for diagnostic in &record.diagnostic_summaries {
                recent_pylon_diagnostics.push(PublicRecentPylonDiagnostic {
                    node_label: record.node_label.clone(),
                    nostr_pubkey_short: truncate_nostr_pubkey(record.nostr_pubkey_hex.as_str()),
                    last_seen_at_unix_ms: record.last_seen_at_unix_ms,
                    diagnostic_id: diagnostic.diagnostic_id.clone(),
                    model_id: diagnostic.model_id.clone(),
                    runtime_backend: diagnostic.runtime_backend.clone(),
                    status: diagnostic.status.clone(),
                    reason: diagnostic.reason.clone(),
                    measured_at_unix_ms: diagnostic.measured_at_unix_ms,
                    load_s: diagnostic.load_s,
                    mean_total_s: diagnostic.mean_total_s,
                    mean_ttft_s: diagnostic.mean_ttft_s,
                    mean_decode_tok_s: diagnostic.mean_decode_tok_s,
                    repeats: diagnostic.repeats,
                });
                if recent_pylon_diagnostics.len() >= PUBLIC_RECENT_PYLON_DIAGNOSTIC_LIMIT {
                    break;
                }
            }
            if recent_pylon_diagnostics.len() >= PUBLIC_RECENT_PYLON_DIAGNOSTIC_LIMIT {
                break;
            }
        }

        ProviderPresenceMetrics {
            pylons_online_now: online_identities.len() as u64,
            pylons_seen_24h: seen_identities.len() as u64,
            pylon_sessions_online_now,
            sellable_pylons_online_now: sellable_identities.len() as u64,
            recent_pylons: recent_pylons
                .into_iter()
                .map(|record| {
                    let inference_ready = provider_presence_record_is_inference_ready(&record);
                    let ready_model = record.ready_model.clone().or(record
                        .hosting_telemetry
                        .availability
                        .local_gemma
                        .ready_model
                        .clone());
                    PublicRecentPylon {
                        node_label: record.node_label,
                        nostr_pubkey_short: truncate_nostr_pubkey(record.nostr_pubkey_hex.as_str()),
                        last_seen_at_unix_ms: record.last_seen_at_unix_ms,
                        client_version: record.client_version,
                        relay_urls: record.relay_urls,
                        eligible_product_count: record.eligible_product_count,
                        products: record.products,
                        ready_model,
                        runtime_state: record.runtime_state,
                        inference_ready,
                        training_capability_envelope_v2: record.training_capability_envelope_v2,
                    }
                })
                .collect(),
            inference_ready_pylons_online_now: inference_ready_identities.len() as u64,
            inference_ready_pylon_sessions_online_now,
            pylon_reported_hosts_online_now: host_session_counts.len() as u64,
            pylon_sessions_missing_host_fingerprint_online_now,
            likely_same_host_pylon_sessions_online_now,
            likely_same_host_pylons_online_now,
            recent_pylon_diagnostics,
        }
    }
}

#[derive(Debug, Clone)]
struct ApiError {
    status: StatusCode,
    error: &'static str,
    reason: String,
}

impl IntoResponse for ApiError {
    fn into_response(self) -> Response {
        (
            self.status,
            Json(ErrorResponse {
                error: self.error.to_string(),
                reason: self.reason,
            }),
        )
            .into_response()
    }
}

pub fn build_router(config: ServiceConfig) -> Router {
    build_router_with_state(build_app_state(config))
}

pub fn build_api_router(config: ServiceConfig) -> Router {
    let state = build_app_state(config);
    spawn_treasury_dispatch_loop(state.clone());
    spawn_treasury_wallet_refresh_loop(state.clone());
    build_api_router_with_state(state)
}

fn build_app_state(config: ServiceConfig) -> AppState {
    let store = ControlStore::new(&config);
    let now = now_unix_ms();
    let launch_metrics = TrainingLaunchLiveMetricsSnapshot::default();
    let mut initial_public_stats =
        build_public_stats_snapshot(&config, &store, &launch_metrics, now);
    apply_public_stats_cache_context(&mut initial_public_stats, now, "live");
    let (kernel_receipt_tx, _) = broadcast::channel(256);
    let (kernel_snapshot_tx, _) = broadcast::channel(256);
    AppState {
        store: Arc::new(RwLock::new(store)),
        public_stats_cache: Arc::new(RwLock::new(initial_public_stats)),
        training_run_detail_cache: Arc::new(RwLock::new(HashMap::new())),
        training_launch_metrics: Arc::new(RwLock::new(TrainingLaunchLiveMetrics::default())),
        config,
        kernel_receipt_tx,
        kernel_snapshot_tx,
    }
}

fn build_router_with_state(state: AppState) -> Router {
    Router::new()
        .route("/healthz", get(healthz))
        .merge(build_api_router_with_state(state))
}

