async fn record_training_window_progress(
    State(state): State<AppState>,
    Json(mut request): Json<RecordTrainingWindowProgressRequest>,
) -> Result<Json<RecordTrainingWindowProgressResponse>, ApiError> {
    request.idempotency_key = normalize_required_field(
        request.idempotency_key.as_str(),
        "training_window_progress_idempotency_key_missing",
    )?;
    request.node_pubkey_hex = normalize_required_field(
        request.node_pubkey_hex.as_str(),
        "training_node_pubkey_missing",
    )?;
    request.training_run_id = normalize_required_field(
        request.training_run_id.as_str(),
        "compute_training_run_id_missing",
    )?;
    request.window_id = normalize_required_field(
        request.window_id.as_str(),
        "compute_adapter_window_id_missing",
    )?;
    request.window_state = normalize_required_field(
        request.window_state.as_str(),
        "training_window_state_missing",
    )?;
    request.recorded_at_ms = if request.recorded_at_ms <= 0 {
        now_unix_ms() as i64
    } else {
        request.recorded_at_ms
    };
    let response = {
        let mut store = state.store.write().map_err(|_| ApiError {
            status: StatusCode::INTERNAL_SERVER_ERROR,
            error: "internal_error",
            reason: "session_store_poisoned".to_string(),
        })?;
        let training_run = store
            .kernel
            .get_compute_training_run(request.training_run_id.as_str())
            .ok_or_else(|| kernel_api_error("compute_training_run_not_found".to_string()))?;
        let window = store
            .kernel
            .get_compute_adapter_training_window(request.window_id.as_str())
            .ok_or_else(|| kernel_api_error("training_window_not_found".to_string()))?;
        let mut updated_window = window.clone();
        let contribution_outcomes = store.kernel.list_compute_adapter_contribution_outcomes(
            Some(request.training_run_id.as_str()),
            Some(request.window_id.as_str()),
            None,
        );
        if let Some(local_checkpoint_ref) = request.local_checkpoint_ref.as_ref() {
            updated_window.output_checkpoint_pointer = Some(ComputeAdapterCheckpointPointer {
                scope_kind: "window".to_string(),
                scope_id: request.window_id.clone(),
                checkpoint_family: training_run.checkpoint_binding.checkpoint_family.clone(),
                checkpoint_ref: local_checkpoint_ref.clone(),
                manifest_digest: sha256_prefixed_bytes(local_checkpoint_ref.as_bytes()),
                updated_at_ms: request.recorded_at_ms,
                pointer_digest: sha256_prefixed_bytes(
                    format!("{}:{local_checkpoint_ref}", request.window_id).as_bytes(),
                ),
            });
        }
        updated_window.recorded_at_ms = request.recorded_at_ms;
        store
            .kernel
            .record_compute_adapter_window(
                &training_kernel_mutation_context(
                    training_window_caller_id(request.window_id.as_str()).as_str(),
                    request.recorded_at_ms as u64,
                ),
                training_window_record_request(
                    request.idempotency_key.clone(),
                    updated_window,
                    contribution_outcomes,
                ),
            )
            .map_err(kernel_api_error)?;
        let scheduled_run = store
            .training_scheduler
            .runs_by_training_run_id
            .get_mut(request.training_run_id.as_str())
            .ok_or_else(|| kernel_api_error("training_scheduler_run_not_found".to_string()))?;
        if let Some(assignment_id) = request.assignment_id.as_deref() {
            if let Some(assignment) =
                scheduled_run.assignment_for_id_mut(assignment_id, request.node_pubkey_hex.as_str())
            {
                assignment.state = TrainingAssignmentState::Active;
                assignment.expires_at_ms = Some(
                    request
                        .recorded_at_ms
                        .saturating_add(PYLON_TRAINING_LEASE_DURATION_MS as i64),
                );
            }
        }
        if let Some(window_state) =
            training_scheduler_window_state_from_label(request.window_state.as_str())
        {
            scheduled_run.window_state = window_state;
        }
        scheduled_run.updated_at_ms = request.recorded_at_ms;
        let window_state = scheduled_run.window_state.label().to_string();
        let _ = scheduled_run;
        store
            .persist_training_scheduler_state()
            .map_err(kernel_api_error)?;
        RecordTrainingWindowProgressResponse {
            ack: TrainingCoordinatorAck {
                idempotency_key: request.idempotency_key,
                recorded_at_ms: request.recorded_at_ms,
                authority_state: "window_progress_recorded".to_string(),
            },
            window_state,
        }
    };
    Ok(Json(response))
}

async fn publish_training_checkpoint(
    State(state): State<AppState>,
    Json(mut request): Json<PublishTrainingCheckpointRequest>,
) -> Result<Json<PublishTrainingCheckpointResponse>, ApiError> {
    request.idempotency_key = normalize_required_field(
        request.idempotency_key.as_str(),
        "training_checkpoint_publish_idempotency_key_missing",
    )?;
    request.node_pubkey_hex = normalize_required_field(
        request.node_pubkey_hex.as_str(),
        "training_node_pubkey_missing",
    )?;
    request.training_run_id = normalize_required_field(
        request.training_run_id.as_str(),
        "compute_training_run_id_missing",
    )?;
    request.window_id = normalize_required_field(
        request.window_id.as_str(),
        "compute_adapter_window_id_missing",
    )?;
    request.checkpoint_ref = normalize_required_field(
        request.checkpoint_ref.as_str(),
        "compute_adapter_checkpoint_ref_missing",
    )?;
    request.artifact_locator = normalize_required_field(
        request.artifact_locator.as_str(),
        "training_checkpoint_artifact_locator_missing",
    )?;
    request.artifact_digest = normalize_required_field(
        request.artifact_digest.as_str(),
        "training_checkpoint_artifact_digest_missing",
    )?;
    request.manifest_digest = normalize_optional_field(request.manifest_digest.as_deref());
    request.published_at_ms = if request.published_at_ms <= 0 {
        now_unix_ms() as i64
    } else {
        request.published_at_ms
    };
    let response = {
        let mut store = state.store.write().map_err(|_| ApiError {
            status: StatusCode::INTERNAL_SERVER_ERROR,
            error: "internal_error",
            reason: "session_store_poisoned".to_string(),
        })?;
        let training_run = store
            .kernel
            .get_compute_training_run(request.training_run_id.as_str())
            .ok_or_else(|| kernel_api_error("compute_training_run_not_found".to_string()))?;
        let window = store
            .kernel
            .get_compute_adapter_training_window(request.window_id.as_str())
            .ok_or_else(|| kernel_api_error("training_window_not_found".to_string()))?;
        let mut updated_window = window.clone();
        let contribution_outcomes = store.kernel.list_compute_adapter_contribution_outcomes(
            Some(request.training_run_id.as_str()),
            Some(request.window_id.as_str()),
            None,
        );
        let manifest_digest = request
            .manifest_digest
            .clone()
            .unwrap_or_else(|| request.artifact_digest.clone());
        updated_window.output_checkpoint_pointer = Some(ComputeAdapterCheckpointPointer {
            scope_kind: "window".to_string(),
            scope_id: request.window_id.clone(),
            checkpoint_family: training_run.checkpoint_binding.checkpoint_family.clone(),
            checkpoint_ref: request.checkpoint_ref.clone(),
            manifest_digest,
            updated_at_ms: request.published_at_ms,
            pointer_digest: sha256_prefixed_bytes(
                format!(
                    "{}:{}:{}",
                    request.window_id, request.checkpoint_ref, request.artifact_locator
                )
                .as_bytes(),
            ),
        });
        updated_window.recorded_at_ms = request.published_at_ms;
        store
            .kernel
            .record_compute_adapter_window(
                &training_kernel_mutation_context(
                    training_window_caller_id(request.window_id.as_str()).as_str(),
                    request.published_at_ms as u64,
                ),
                training_window_record_request(
                    request.idempotency_key.clone(),
                    updated_window,
                    contribution_outcomes,
                ),
            )
            .map_err(kernel_api_error)?;
        if let Some(scheduled_run) = store
            .training_scheduler
            .runs_by_training_run_id
            .get_mut(request.training_run_id.as_str())
        {
            scheduled_run.checkpoint_ref = Some(request.checkpoint_ref.clone());
            scheduled_run.updated_at_ms = request.published_at_ms;
            store
                .persist_training_scheduler_state()
                .map_err(kernel_api_error)?;
        }
        PublishTrainingCheckpointResponse {
            ack: TrainingCoordinatorAck {
                idempotency_key: request.idempotency_key,
                recorded_at_ms: request.published_at_ms,
                authority_state: "checkpoint_published".to_string(),
            },
            checkpoint_state: "published".to_string(),
            artifact_locator: Some(request.artifact_locator),
        }
    };
    Ok(Json(response))
}

async fn claim_training_run_lease(
    State(state): State<AppState>,
    Json(mut request): Json<RecordTrainingRunLeaseRequest>,
) -> Result<Json<RecordTrainingRunLeaseResponse>, ApiError> {
    request.idempotency_key = normalize_required_field(
        request.idempotency_key.as_str(),
        "training_scheduler_idempotency_key_missing",
    )?;
    request.node_pubkey_hex = normalize_required_field(
        request.node_pubkey_hex.as_str(),
        "training_node_pubkey_missing",
    )?;
    request.requested_at_ms = if request.requested_at_ms <= 0 {
        now_unix_ms() as i64
    } else {
        request.requested_at_ms
    };
    request.requested_network_id = request
        .requested_network_id
        .take()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    request.requested_training_run_id = request
        .requested_training_run_id
        .take()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    request.membership_revision = request
        .membership_revision
        .take()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());

    let response = {
        let mut store = state.store.write().map_err(|_| ApiError {
            status: StatusCode::INTERNAL_SERVER_ERROR,
            error: "internal_error",
            reason: "session_store_poisoned".to_string(),
        })?;
        let node = store
            .kernel
            .get_admitted_training_node(
                request.node_pubkey_hex.as_str(),
                request.requested_network_id.as_deref(),
                request.requested_at_ms,
            )
            .ok_or_else(|| kernel_api_error("training_node_not_found".to_string()))?;
        let node =
            training_authority_refresh_node_view(&store.kernel, node, request.requested_at_ms)
                .map_err(kernel_api_error)?;
        if !node.eligible {
            let reason = pylon_training_hard_gate_reason(&node.active_reputation_labels)
                .unwrap_or_else(|| "training_node_not_eligible".to_string());
            tracing::warn!(
                node_pubkey_hex = request.node_pubkey_hex.as_str(),
                requested_training_run_id = ?request.requested_training_run_id,
                requested_network_id = ?request.requested_network_id,
                active_reputation_labels = ?node.active_reputation_labels,
                hard_gate_reason = reason.as_str(),
                "training lease claim hard gated"
            );
            return Err(kernel_api_error(reason));
        }
        let candidate_runs = store.kernel.list_compute_training_runs(None, None, None);
        let run_definitions_by_training_run_id = candidate_runs
            .iter()
            .filter_map(|run| {
                training_scheduler_run_definition(&store.kernel, run)
                    .ok()
                    .map(|definition| (run.training_run_id.clone(), definition))
            })
            .collect::<HashMap<_, _>>();
        let abuse_snapshot = training_fleet_abuse_snapshot(
            &store.kernel,
            &store.training_scheduler,
            &store.training_scheduler.rollout_policy().abuse_controls,
            request.requested_at_ms as u64,
        );
        let response = store
            .training_scheduler
            .claim_lease(
                node,
                candidate_runs,
                &run_definitions_by_training_run_id,
                &abuse_snapshot,
                &request,
                request.requested_at_ms,
            )
            .map_err(kernel_api_error)?;
        store
            .persist_training_scheduler_state()
            .map_err(kernel_api_error)?;
        response
    };
    Ok(Json(response))
}

async fn plan_training_window(
    State(state): State<AppState>,
    Json(mut request): Json<PlanTrainingWindowRequest>,
) -> Result<Json<TrainingWindowCoordinatorResponse>, ApiError> {
    request.idempotency_key = normalize_required_field(
        request.idempotency_key.as_str(),
        "training_window_idempotency_key_missing",
    )?;
    request.training_run_id = normalize_required_field(
        request.training_run_id.as_str(),
        "compute_training_run_id_missing",
    )?;
    request.stage_id = normalize_required_field(
        request.stage_id.as_str(),
        "compute_adapter_stage_id_missing",
    )?;
    request.base_checkpoint_ref = normalize_required_field(
        request.base_checkpoint_ref.as_str(),
        "compute_adapter_base_checkpoint_ref_missing",
    )?;
    request.base_model_ref = normalize_required_field(
        request.base_model_ref.as_str(),
        "compute_adapter_base_model_ref_missing",
    )?;
    request.aggregation_rule = normalize_optional_field(request.aggregation_rule.as_deref());
    request.aggregation_weight_basis =
        normalize_optional_field(request.aggregation_weight_basis.as_deref());
    if request.planned_local_step_count == Some(0) {
        return Err(kernel_api_error(
            "compute_adapter_planned_local_step_count_invalid".to_string(),
        ));
    }
    if request.aggregation_rule.is_some() != request.aggregation_weight_basis.is_some() {
        return Err(kernel_api_error(
            "compute_adapter_aggregation_rule_missing".to_string(),
        ));
    }
    request.recorded_at_ms = if request.recorded_at_ms <= 0 {
        now_unix_ms() as i64
    } else {
        request.recorded_at_ms
    };

    let caller_id = training_window_caller_id(request.training_run_id.as_str());
    let (response, receipt_event, snapshot_event) = {
        let mut store = state.store.write().map_err(|_| ApiError {
            status: StatusCode::INTERNAL_SERVER_ERROR,
            error: "internal_error",
            reason: "session_store_poisoned".to_string(),
        })?;
        let training_run = store
            .kernel
            .get_compute_training_run(request.training_run_id.as_str())
            .ok_or_else(|| kernel_api_error("compute_training_run_not_found".to_string()))?;
        let scheduler_run = store
            .training_scheduler
            .runs_by_training_run_id
            .get(request.training_run_id.as_str())
            .cloned()
            .ok_or_else(|| {
                kernel_api_error("training_window_scheduler_run_not_found".to_string())
            })?;
        let scheduler_metadata =
            training_scheduler_metadata_from_run(&training_run).map_err(kernel_api_error)?;
        if request.source_checkpoint_pointer.checkpoint_family
            != training_run.checkpoint_binding.checkpoint_family
        {
            return Err(kernel_api_error(
                "training_window_checkpoint_mismatch".to_string(),
            ));
        }
        if request.base_checkpoint_ref != request.source_checkpoint_pointer.checkpoint_ref {
            return Err(kernel_api_error(
                "training_window_checkpoint_mismatch".to_string(),
            ));
        }
        if training_run
            .checkpoint_binding
            .latest_checkpoint_ref
            .as_deref()
            .is_some_and(|checkpoint_ref| {
                checkpoint_ref != request.source_checkpoint_pointer.checkpoint_ref
            })
        {
            return Err(kernel_api_error(
                "training_window_checkpoint_mismatch".to_string(),
            ));
        }
        if training_run.work_class == ComputeTrainingWorkClass::AdapterTraining {
            request.adapter_target_id = normalize_required_field(
                request.adapter_target_id.as_str(),
                "compute_adapter_target_id_missing",
            )?;
            request.adapter_family = normalize_required_field(
                request.adapter_family.as_str(),
                "compute_adapter_family_missing",
            )?;
            request.adapter_format = normalize_required_field(
                request.adapter_format.as_str(),
                "compute_adapter_format_missing",
            )?;
        } else {
            request.adapter_target_id =
                normalize_optional_field(Some(request.adapter_target_id.as_str()))
                    .unwrap_or_default();
            request.adapter_family =
                normalize_optional_field(Some(request.adapter_family.as_str())).unwrap_or_default();
            request.adapter_format =
                normalize_optional_field(Some(request.adapter_format.as_str())).unwrap_or_default();
        }
        let contributor_set_revision_id =
            pylon_training_membership_revision_label(scheduler_run.membership_revision);
        let assignment_plans = training_window_assignment_plans(
            &scheduler_run,
            request.dataset_slices.as_slice(),
            contributor_set_revision_id.as_str(),
        )
        .map_err(kernel_api_error)?;
        let metadata = TrainingWindowMetadata {
            network_id: scheduler_metadata.network_id,
            artifact_bucket_uri: scheduler_metadata.artifact_bucket_uri,
            environment_ref: training_run.environment_binding.environment_ref.clone(),
            backend_family: training_backend_family_for_environment_ref(
                training_run.environment_binding.environment_ref.as_str(),
            )
            .unwrap_or_default()
            .to_string(),
            membership_revision: contributor_set_revision_id,
            assignment_plans: assignment_plans.clone(),
            validation: None,
            planned_at_ms: request.recorded_at_ms,
            activated_at_ms: None,
            sealed_at_ms: None,
            reconciled_at_ms: None,
            defensibility: None,
            seal_deadline_ms: request.recorded_at_ms.saturating_add(
                (PYLON_TRAINING_WINDOW_MAX_DURATION_MS + PYLON_TRAINING_SEAL_GRACE_PERIOD_MS)
                    as i64,
            ),
        };
        let window = training_window_base_record(
            &training_run,
            &scheduler_run,
            &request,
            metadata,
            ComputeAdapterWindowStatus::Planned,
            request.recorded_at_ms,
        )
        .map_err(kernel_api_error)?;
        let result = store
            .kernel
            .record_compute_adapter_window(
                &training_kernel_mutation_context(&caller_id, request.recorded_at_ms as u64),
                training_window_record_request(request.idempotency_key.clone(), window, Vec::new()),
            )
            .map_err(kernel_api_error)?;
        (
            training_window_response(result.response, assignment_plans),
            result.receipt_event,
            result.snapshot_event,
        )
    };
    record_training_coordination_observability(
        &state,
        request.recorded_at_ms as u64,
        caller_id.as_str(),
        "kernel.training_window.planned",
        receipt_event,
        snapshot_event,
    );
    Ok(Json(response))
}

async fn activate_training_window(
    State(state): State<AppState>,
    Path(window_id): Path<String>,
    Json(mut request): Json<TransitionTrainingWindowRequest>,
) -> Result<Json<TrainingWindowCoordinatorResponse>, ApiError> {
    request.idempotency_key = normalize_required_field(
        request.idempotency_key.as_str(),
        "training_window_idempotency_key_missing",
    )?;
    request.window_id =
        normalize_required_field(window_id.as_str(), "compute_adapter_window_id_missing")?;
    request.recorded_at_ms = if request.recorded_at_ms <= 0 {
        now_unix_ms() as i64
    } else {
        request.recorded_at_ms
    };

    let caller_id = training_window_caller_id(request.window_id.as_str());
    let (response, receipt_event, snapshot_event) = {
        let mut store = state.store.write().map_err(|_| ApiError {
            status: StatusCode::INTERNAL_SERVER_ERROR,
            error: "internal_error",
            reason: "session_store_poisoned".to_string(),
        })?;
        let window = store
            .kernel
            .get_compute_adapter_training_window(request.window_id.as_str())
            .ok_or_else(|| kernel_api_error("training_window_not_found".to_string()))?;
        if window.status != ComputeAdapterWindowStatus::Planned {
            return Err(kernel_api_error(
                "training_window_status_invalid".to_string(),
            ));
        }
        let mut metadata =
            training_window_metadata_from_value(&window.metadata).map_err(kernel_api_error)?;
        metadata.activated_at_ms = Some(request.recorded_at_ms);
        let assignment_plans = metadata.assignment_plans.clone();
        let mut updated_window = window.clone();
        updated_window.status = ComputeAdapterWindowStatus::Active;
        updated_window.recorded_at_ms = request.recorded_at_ms;
        updated_window.metadata = training_window_metadata_value(&metadata);
        updated_window.window_summary_digest =
            training_window_summary_digest(&updated_window, &[], &metadata)
                .map_err(kernel_api_error)?;
        let result = store
            .kernel
            .record_compute_adapter_window(
                &training_kernel_mutation_context(&caller_id, request.recorded_at_ms as u64),
                training_window_record_request(
                    request.idempotency_key.clone(),
                    updated_window,
                    Vec::new(),
                ),
            )
            .map_err(kernel_api_error)?;
        if let Some(scheduled_run) = store
            .training_scheduler
            .runs_by_training_run_id
            .get_mut(window.training_run_id.as_str())
        {
            scheduled_run.window_state = TrainingSchedulerWindowState::Active;
            scheduled_run.updated_at_ms = request.recorded_at_ms;
        }
        store
            .persist_training_scheduler_state()
            .map_err(kernel_api_error)?;
        (
            training_window_response(result.response, assignment_plans),
            result.receipt_event,
            result.snapshot_event,
        )
    };
    record_training_coordination_observability(
        &state,
        request.recorded_at_ms as u64,
        caller_id.as_str(),
        "kernel.training_window.activated",
        receipt_event,
        snapshot_event,
    );
    Ok(Json(response))
}

async fn seal_training_window(
    State(state): State<AppState>,
    Path(window_id): Path<String>,
    Json(mut request): Json<SealTrainingWindowRequest>,
) -> Result<Json<TrainingWindowCoordinatorResponse>, ApiError> {
    request.idempotency_key = normalize_required_field(
        request.idempotency_key.as_str(),
        "training_window_idempotency_key_missing",
    )?;
    request.window_id =
        normalize_required_field(window_id.as_str(), "compute_adapter_window_id_missing")?;
    request.recorded_at_ms = if request.recorded_at_ms <= 0 {
        now_unix_ms() as i64
    } else {
        request.recorded_at_ms
    };

    let caller_id = training_window_caller_id(request.window_id.as_str());
    let (response, receipt_event, snapshot_event) = {
        let mut store = state.store.write().map_err(|_| ApiError {
            status: StatusCode::INTERNAL_SERVER_ERROR,
            error: "internal_error",
            reason: "session_store_poisoned".to_string(),
        })?;
        let window = store
            .kernel
            .get_compute_adapter_training_window(request.window_id.as_str())
            .ok_or_else(|| kernel_api_error("training_window_not_found".to_string()))?;
        if window.status != ComputeAdapterWindowStatus::Active {
            return Err(kernel_api_error(
                "training_window_status_invalid".to_string(),
            ));
        }
        let training_run = store
            .kernel
            .get_compute_training_run(window.training_run_id.as_str())
            .ok_or_else(|| kernel_api_error("compute_training_run_not_found".to_string()))?;
        let mut metadata =
            training_window_metadata_from_value(&window.metadata).map_err(kernel_api_error)?;
        let assignment_plans = metadata.assignment_plans.clone();
        let scheduled_run = store
            .training_scheduler
            .runs_by_training_run_id
            .get(window.training_run_id.as_str())
            .cloned();
        let mut contribution_outcomes = training_window_contribution_outcomes_from_inputs(
            &window,
            assignment_plans.as_slice(),
            scheduled_run.as_ref(),
            request.contribution_outcomes.as_slice(),
            request.recorded_at_ms,
            true,
        )
        .map_err(kernel_api_error)?;
        training_enrich_contribution_outcomes_with_node_tiers(
            &store.kernel,
            contribution_outcomes.as_mut_slice(),
            request.recorded_at_ms,
        );
        let validator_policy = store
            .kernel
            .get_compute_validator_policy(training_run.validator_policy_ref.as_str(), None)
            .ok_or_else(|| kernel_api_error("compute_validator_policy_not_found".to_string()))?;
        let (validation_state, schedule_requests) = training_window_validation_state_for_seal(
            &window,
            request.contribution_outcomes.as_slice(),
            training_run.product_id.as_deref().unwrap_or_default(),
            validator_policy.validator_pool_ref.as_str(),
            request.recorded_at_ms,
        )
        .map_err(kernel_api_error)?;
        for schedule_request in schedule_requests {
            store
                .kernel
                .schedule_validator_challenge(
                    &training_kernel_mutation_context(&caller_id, request.recorded_at_ms as u64),
                    schedule_request,
                )
                .map_err(kernel_api_error)?;
        }
        let (
            total_contributions,
            admitted_contributions,
            accepted_contributions,
            quarantined_contributions,
            rejected_contributions,
            replay_required_contributions,
            replay_checked_contributions,
        ) = training_window_counts(contribution_outcomes.as_slice());
        metadata.sealed_at_ms = Some(request.recorded_at_ms);
        metadata.validation = Some(validation_state);
        let mut updated_window = window.clone();
        updated_window.status = ComputeAdapterWindowStatus::Sealed;
        updated_window.total_contributions = total_contributions;
        updated_window.admitted_contributions = admitted_contributions;
        updated_window.accepted_contributions = accepted_contributions;
        updated_window.quarantined_contributions = quarantined_contributions;
        updated_window.rejected_contributions = rejected_contributions;
        updated_window.replay_required_contributions = replay_required_contributions;
        updated_window.replay_checked_contributions = replay_checked_contributions;
        updated_window.held_out_average_score_bps = None;
        updated_window.benchmark_pass_rate_bps = None;
        updated_window.runtime_smoke_passed = None;
        updated_window.gate_reason_codes = vec![
            ComputeAdapterWindowGateReasonCode::HeldOutEvalMissing,
            ComputeAdapterWindowGateReasonCode::BenchmarkMissing,
            ComputeAdapterWindowGateReasonCode::RuntimeSmokeRequired,
        ];
        updated_window.promotion_ready = false;
        updated_window.aggregated_delta_digest = None;
        updated_window.accepted_aggregate_id = None;
        updated_window.promoted_checkpoint_ref = None;
        updated_window.recorded_at_ms = request.recorded_at_ms;
        updated_window.metadata = training_window_metadata_value(&metadata);
        updated_window.window_summary_digest = training_window_summary_digest(
            &updated_window,
            contribution_outcomes.as_slice(),
            &metadata,
        )
        .map_err(kernel_api_error)?;
        let result = store
            .kernel
            .record_compute_adapter_window(
                &training_kernel_mutation_context(&caller_id, request.recorded_at_ms as u64),
                training_window_record_request(
                    request.idempotency_key.clone(),
                    updated_window,
                    contribution_outcomes,
                ),
            )
            .map_err(kernel_api_error)?;
        (
            training_window_response(result.response, assignment_plans),
            result.receipt_event,
            result.snapshot_event,
        )
    };
    record_training_coordination_observability(
        &state,
        request.recorded_at_ms as u64,
        caller_id.as_str(),
        "kernel.training_window.sealed",
        receipt_event,
        snapshot_event,
    );
    Ok(Json(response))
}

async fn reconcile_training_window(
    State(state): State<AppState>,
    Path(window_id): Path<String>,
    Json(mut request): Json<ReconcileTrainingWindowRequest>,
) -> Result<Json<TrainingWindowCoordinatorResponse>, ApiError> {
    request.idempotency_key = normalize_required_field(
        request.idempotency_key.as_str(),
        "training_window_idempotency_key_missing",
    )?;
    request.window_id =
        normalize_required_field(window_id.as_str(), "compute_adapter_window_id_missing")?;
    request.recorded_at_ms = if request.recorded_at_ms <= 0 {
        now_unix_ms() as i64
    } else {
        request.recorded_at_ms
    };

    let caller_id = training_window_caller_id(request.window_id.as_str());
    let (
        response,
        outcome_receipt_event,
        outcome_snapshot_event,
        window_receipt_event,
        window_snapshot_event,
    ) = {
        let mut store = state.store.write().map_err(|_| ApiError {
            status: StatusCode::INTERNAL_SERVER_ERROR,
            error: "internal_error",
            reason: "session_store_poisoned".to_string(),
        })?;
        let window = store
            .kernel
            .get_compute_adapter_training_window(request.window_id.as_str())
            .ok_or_else(|| kernel_api_error("training_window_not_found".to_string()))?;
        let replaying_reconciled_closeout =
            training_window_closeout_reconcile_replay_allowed(&store.kernel, &window);
        if !matches!(
            window.status,
            ComputeAdapterWindowStatus::Sealed | ComputeAdapterWindowStatus::Scored
        ) && !replaying_reconciled_closeout
        {
            return Err(kernel_api_error(
                "training_window_status_invalid".to_string(),
            ));
        }
        let training_run = store
            .kernel
            .get_compute_training_run(window.training_run_id.as_str())
            .ok_or_else(|| kernel_api_error("compute_training_run_not_found".to_string()))?;
        let mut metadata =
            training_window_metadata_from_value(&window.metadata).map_err(kernel_api_error)?;
        let validation = metadata
            .validation
            .clone()
            .ok_or_else(|| kernel_api_error("training_window_validation_missing".to_string()))?;
        let validation_summary = training_window_validation_summary(&store.kernel, &validation)
            .map_err(kernel_api_error)?;
        if !validation_summary.all_required_terminal {
            return Err(kernel_api_error(
                "training_window_validation_incomplete".to_string(),
            ));
        }
        let assignment_plans = metadata.assignment_plans.clone();
        let scheduled_run = store
            .training_scheduler
            .runs_by_training_run_id
            .get(window.training_run_id.as_str())
            .cloned();
        let mut contribution_outcomes = training_window_contribution_outcomes_from_inputs(
            &window,
            assignment_plans.as_slice(),
            scheduled_run.as_ref(),
            request.contribution_outcomes.as_slice(),
            request.recorded_at_ms,
            false,
        )
        .map_err(kernel_api_error)?;
        training_window_apply_validation_overrides(
            contribution_outcomes.as_mut_slice(),
            &validation_summary,
            window.window_summary_digest.as_str(),
        );
        training_enrich_contribution_outcomes_with_node_tiers(
            &store.kernel,
            contribution_outcomes.as_mut_slice(),
            request.recorded_at_ms,
        );
        let (
            total_contributions,
            admitted_contributions,
            accepted_contributions,
            quarantined_contributions,
            rejected_contributions,
            replay_required_contributions,
            replay_checked_contributions,
        ) = training_window_counts(contribution_outcomes.as_slice());
        let (held_out_threshold_bps, benchmark_threshold_bps) =
            training_window_thresholds(&store.kernel, &training_run);
        let gate_reason_codes = training_window_gate_reason_codes(
            request.held_out_average_score_bps,
            request.benchmark_pass_rate_bps,
            request.runtime_smoke_passed,
            held_out_threshold_bps,
            benchmark_threshold_bps,
        );
        let closeout_status = training_window_closeout_status(
            &validation_summary,
            gate_reason_codes.as_slice(),
            accepted_contributions,
            quarantined_contributions,
            rejected_contributions,
            replay_required_contributions,
        );
        metadata.reconciled_at_ms = Some(request.recorded_at_ms);
        let mut updated_window = window.clone();
        updated_window.status = ComputeAdapterWindowStatus::Reconciled;
        updated_window.total_contributions = total_contributions;
        updated_window.admitted_contributions = admitted_contributions;
        updated_window.accepted_contributions = accepted_contributions;
        updated_window.quarantined_contributions = quarantined_contributions;
        updated_window.rejected_contributions = rejected_contributions;
        updated_window.replay_required_contributions = replay_required_contributions;
        updated_window.replay_checked_contributions = replay_checked_contributions;
        updated_window.held_out_average_score_bps = request.held_out_average_score_bps;
        updated_window.benchmark_pass_rate_bps = request.benchmark_pass_rate_bps;
        updated_window.runtime_smoke_passed = request.runtime_smoke_passed;
        updated_window.gate_reason_codes = gate_reason_codes;
        updated_window.aggregated_delta_digest = request.aggregated_delta_digest.clone();
        updated_window.accepted_aggregate_id = request.accepted_aggregate_id.clone();
        updated_window.promoted_checkpoint_ref = request.promoted_checkpoint_ref.clone();
        updated_window.recorded_at_ms = request.recorded_at_ms;
        let mut closeout_status = closeout_status;
        let defensibility = training_window_defensibility_audit(
            &store.kernel,
            store
                .training_scheduler
                .runs_by_training_run_id
                .get(updated_window.training_run_id.as_str()),
            &updated_window,
            assignment_plans.as_slice(),
            contribution_outcomes.as_slice(),
            &validation,
            &validation_summary,
            closeout_status,
            request.recorded_at_ms,
        );
        if let Some(required_closeout_status) = defensibility.required_closeout_status() {
            closeout_status = match closeout_status {
                TrainingWindowCloseoutStatus::Held
                | TrainingWindowCloseoutStatus::Quarantined
                | TrainingWindowCloseoutStatus::Refused => closeout_status,
                TrainingWindowCloseoutStatus::Rewarded | TrainingWindowCloseoutStatus::NoReward => {
                    required_closeout_status
                }
            };
        }
        updated_window.promotion_ready = closeout_status == TrainingWindowCloseoutStatus::Rewarded;
        match closeout_status {
            TrainingWindowCloseoutStatus::Rewarded | TrainingWindowCloseoutStatus::NoReward => {
                updated_window.promotion_disposition = None;
                updated_window.hold_reason_codes.clear();
            }
            TrainingWindowCloseoutStatus::Held
            | TrainingWindowCloseoutStatus::Quarantined
            | TrainingWindowCloseoutStatus::Refused => {
                updated_window.promotion_disposition =
                    Some(ComputeAdapterPromotionDisposition::Held);
                updated_window.hold_reason_codes =
                    vec![ComputeAdapterPromotionHoldReasonCode::ValidatorWindowNotPromotionReady];
            }
        }
        metadata.defensibility = Some(defensibility.as_json());
        updated_window.metadata = training_window_metadata_value(&metadata);
        updated_window.window_summary_digest = training_window_summary_digest(
            &updated_window,
            contribution_outcomes.as_slice(),
            &metadata,
        )
        .map_err(kernel_api_error)?;
        let closeout_outcome = training_window_closeout_outcome(
            &training_run,
            &metadata,
            &validation,
            &validation_summary,
            &updated_window,
            contribution_outcomes.as_slice(),
            request.recorded_at_ms,
            closeout_status,
            &defensibility,
        );
        let abuse_controls = store
            .training_scheduler
            .rollout_policy()
            .abuse_controls
            .clone();
        let abuse_snapshot = training_fleet_abuse_snapshot(
            &store.kernel,
            &store.training_scheduler,
            &abuse_controls,
            request.recorded_at_ms.max(0) as u64,
        );
        let treasury_payout_requests = training_window_closeout_treasury_payout_requests(
            training_run_homework_payout_amount_sats(
                &training_run,
                state.config.treasury.payout_sats_per_window,
            ),
            &updated_window,
            contribution_outcomes.as_slice(),
            request.recorded_at_ms,
            closeout_status,
            &abuse_controls,
            &abuse_snapshot,
        );
        updated_window.accepted_outcome_id = Some(closeout_outcome.outcome_id.clone());
        let accepted_outcome_request = AcceptComputeOutcomeRequest {
            idempotency_key: format!("{}.closeout", request.idempotency_key),
            trace: TraceContext::default(),
            policy: PolicyContext::default(),
            outcome: closeout_outcome,
            evidence: Vec::new(),
            hints: ReceiptHints::default(),
        };
        let window_record_request = training_window_record_request(
            request.idempotency_key.clone(),
            updated_window.clone(),
            contribution_outcomes,
        );
        let accepted_outcome_result = if replaying_reconciled_closeout {
            store.kernel.accept_compute_outcome_deferred_projection(
                &training_kernel_mutation_context(&caller_id, request.recorded_at_ms as u64),
                accepted_outcome_request,
            )
        } else {
            store.kernel.accept_compute_outcome(
                &training_kernel_mutation_context(&caller_id, request.recorded_at_ms as u64),
                accepted_outcome_request,
            )
        }
        .map_err(kernel_api_error)?;
        let result = if replaying_reconciled_closeout {
            store
                .kernel
                .record_compute_adapter_window_deferred_projection(
                    &training_kernel_mutation_context(&caller_id, request.recorded_at_ms as u64),
                    window_record_request,
                )
        } else {
            store.kernel.record_compute_adapter_window(
                &training_kernel_mutation_context(&caller_id, request.recorded_at_ms as u64),
                window_record_request,
            )
        }
        .map_err(kernel_api_error)?;
        let deferred_snapshot_event = if replaying_reconciled_closeout
            && (accepted_outcome_result.receipt_event.is_some() || result.receipt_event.is_some())
        {
            Some(
                store
                    .kernel
                    .flush_deferred_projection_for(request.recorded_at_ms)
                    .map_err(kernel_api_error)?,
            )
        } else {
            None
        };
        let (outcome_snapshot_event, window_snapshot_event) =
            if let Some(snapshot_event) = deferred_snapshot_event {
                (None, Some(snapshot_event))
            } else {
                (
                    accepted_outcome_result.snapshot_event,
                    result.snapshot_event,
                )
            };
        if let Some(scheduled_run) = store
            .training_scheduler
            .runs_by_training_run_id
            .get_mut(updated_window.training_run_id.as_str())
        {
            scheduled_run.window_state = match closeout_status {
                TrainingWindowCloseoutStatus::Rewarded | TrainingWindowCloseoutStatus::NoReward => {
                    TrainingSchedulerWindowState::Accepted
                }
                TrainingWindowCloseoutStatus::Held => TrainingSchedulerWindowState::Held,
                TrainingWindowCloseoutStatus::Quarantined
                | TrainingWindowCloseoutStatus::Refused => TrainingSchedulerWindowState::Refused,
            };
            scheduled_run.updated_at_ms = request.recorded_at_ms;
            if scheduled_run.current_window_id == updated_window.window_id {
                scheduled_run.current_window_id =
                    training_window_next_id(updated_window.window_id.as_str());
            }
        }
        store
            .persist_training_scheduler_state()
            .map_err(kernel_api_error)?;
        if !treasury_payout_requests.is_empty() {
            store.treasury.queue_payout_requests(
                &state.config.treasury,
                treasury_payout_requests.as_slice(),
                request.recorded_at_ms as u64,
            );
        }
        (
            training_window_response(result.response, assignment_plans),
            accepted_outcome_result.receipt_event,
            outcome_snapshot_event,
            result.receipt_event,
            window_snapshot_event,
        )
    };
    record_training_coordination_observability(
        &state,
        request.recorded_at_ms as u64,
        caller_id.as_str(),
        "kernel.training_window.closeout",
        outcome_receipt_event,
        outcome_snapshot_event,
    );
    record_training_coordination_observability(
        &state,
        request.recorded_at_ms as u64,
        caller_id.as_str(),
        "kernel.training_window.reconciled",
        window_receipt_event,
        window_snapshot_event,
    );
    Ok(Json(response))
}

async fn claim_training_validator_challenge(
    State(state): State<AppState>,
    Json(mut request): Json<ClaimTrainingValidatorChallengeRequest>,
) -> Result<Json<TrainingValidatorChallengeCoordinatorResponse>, ApiError> {
    request.idempotency_key = normalize_required_field(
        request.idempotency_key.as_str(),
        "training_scheduler_idempotency_key_missing",
    )?;
    request.node_pubkey_hex = normalize_required_field(
        request.node_pubkey_hex.as_str(),
        "training_node_pubkey_missing",
    )?;
    request.requested_at_ms = if request.requested_at_ms <= 0 {
        now_unix_ms() as i64
    } else {
        request.requested_at_ms
    };
    request.requested_network_id = request
        .requested_network_id
        .take()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    request.requested_training_run_id = request
        .requested_training_run_id
        .take()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());

    let caller_id = training_node_caller_id(request.node_pubkey_hex.as_str());
    let (response, receipt_event, snapshot_event) = {
        let mut store = state.store.write().map_err(|_| ApiError {
            status: StatusCode::INTERNAL_SERVER_ERROR,
            error: "internal_error",
            reason: "session_store_poisoned".to_string(),
        })?;
        let node = store
            .kernel
            .get_admitted_training_node(
                request.node_pubkey_hex.as_str(),
                request.requested_network_id.as_deref(),
                request.requested_at_ms,
            )
            .ok_or_else(|| kernel_api_error("training_node_not_found".to_string()))?;
        let node =
            training_authority_refresh_node_view(&store.kernel, node, request.requested_at_ms)
                .map_err(kernel_api_error)?;
        if !node.role_claims.contains(&TrainingNodeRoleClaim::Validator) {
            return Err(kernel_api_error(
                "training_validator_role_not_admitted".to_string(),
            ));
        }
        if !node.online {
            return Err(kernel_api_error(
                "training_scheduler_node_offline".to_string(),
            ));
        }
        if !node.eligible {
            tracing::warn!(
                node_pubkey_hex = request.node_pubkey_hex.as_str(),
                requested_training_run_id = ?request.requested_training_run_id,
                requested_network_id = ?request.requested_network_id,
                active_reputation_labels = ?node.active_reputation_labels,
                "training validator claim rejected because node is ineligible"
            );
            return Err(kernel_api_error(
                "training_scheduler_node_ineligible".to_string(),
            ));
        }

        let mut windows = store
            .kernel
            .list_compute_adapter_training_windows(None, None);
        windows.sort_by(|left, right| {
            left.recorded_at_ms
                .cmp(&right.recorded_at_ms)
                .then_with(|| left.window_id.cmp(&right.window_id))
        });
        let mut selected = None::<(
            ComputeAdapterTrainingWindow,
            TrainingWindowMetadata,
            TrainingWindowValidationChallengePlan,
        )>;
        for window in windows {
            if request
                .requested_training_run_id
                .as_deref()
                .is_some_and(|expected| window.training_run_id != expected)
            {
                continue;
            }
            let metadata = match training_window_metadata_from_value(&window.metadata) {
                Ok(metadata) => metadata,
                Err(_) => continue,
            };
            if request
                .requested_network_id
                .as_deref()
                .is_some_and(|expected| metadata.network_id != expected)
            {
                continue;
            }
            if !training_validator_node_matches_window(
                &store.kernel,
                store.training_scheduler.rollout_policy(),
                &node,
                &window,
            ) {
                continue;
            }
            if !node.allowed_networks.is_empty()
                && !node
                    .allowed_networks
                    .iter()
                    .any(|value| value == metadata.network_id.as_str())
            {
                continue;
            }
            let Some(validation) = metadata.validation.as_ref() else {
                continue;
            };
            for challenge_plan in &validation.challenges {
                if training_validator_targets_own_assignments(
                    metadata.assignment_plans.as_slice(),
                    store
                        .training_scheduler
                        .runs_by_training_run_id
                        .get(window.training_run_id.as_str()),
                    challenge_plan,
                    node.node_pubkey_hex.as_str(),
                ) {
                    continue;
                }
                let Some(snapshot) = store
                    .kernel
                    .get_validator_challenge(challenge_plan.challenge_id.as_str())
                else {
                    return Err(kernel_api_error(
                        "training_window_validation_snapshot_missing".to_string(),
                    ));
                };
                if snapshot
                    .active_lease
                    .as_ref()
                    .is_some_and(|lease| lease.validator_id == node.node_pubkey_hex)
                {
                    selected = Some((window.clone(), metadata.clone(), challenge_plan.clone()));
                    break;
                }
                if selected.is_none()
                    && matches!(
                        snapshot.status,
                        validator_service::ValidatorChallengeStatus::Queued
                            | validator_service::ValidatorChallengeStatus::Retrying
                    )
                {
                    selected = Some((window.clone(), metadata.clone(), challenge_plan.clone()));
                }
            }
            if selected.is_some() {
                break;
            }
        }
        let Some((window, metadata, challenge_plan)) = selected else {
            return Err(kernel_api_error(
                "training_validator_challenge_unavailable".to_string(),
            ));
        };
        let result = store
            .kernel
            .lease_validator_challenge(
                &training_kernel_mutation_context(&caller_id, request.requested_at_ms as u64),
                LeaseValidatorChallengeRequest {
                    idempotency_key: request.idempotency_key.clone(),
                    trace: TraceContext::default(),
                    policy: PolicyContext::default(),
                    challenge_id: challenge_plan.challenge_id.clone(),
                    validator_id: node.node_pubkey_hex.clone(),
                    requested_at_ms: request.requested_at_ms as u64,
                    evidence: Vec::new(),
                    hints: ReceiptHints::default(),
                },
            )
            .map_err(kernel_api_error)?;
        let target_bindings = training_validator_target_bindings(
            &state.config,
            &store.kernel,
            &window,
            &metadata,
            &challenge_plan,
            challenge_plan.challenge_id.as_str(),
            Some(result.response.lease.expires_at_ms as i64),
        )
        .map_err(kernel_api_error)?;
        let response = TrainingValidatorChallengeCoordinatorResponse {
            ack: TrainingCoordinatorAck {
                idempotency_key: request.idempotency_key.clone(),
                recorded_at_ms: request.requested_at_ms,
                authority_state: "leased".to_string(),
            },
            network_id: metadata.network_id,
            training_run_id: window.training_run_id,
            window_id: window.window_id,
            challenge_id: challenge_plan.challenge_id.clone(),
            challenge_kind: challenge_plan.challenge_kind.label().to_string(),
            target_assignment_ids: challenge_plan.target_assignment_ids,
            expected_manifest_digests: challenge_plan.expected_manifest_digests,
            challenge: canonical_challenge_snapshot(result.response.challenge),
            lease: Some(ComputeValidatorChallengeLease {
                challenge_id: result.response.lease.challenge_id,
                attempt: result.response.lease.attempt,
                validator_id: result.response.lease.validator_id,
                leased_at_ms: result.response.lease.leased_at_ms,
                expires_at_ms: result.response.lease.expires_at_ms,
            }),
            result: None,
            challenge_receipt: result.response.receipt.clone(),
            window_receipt: None,
            window: None,
            contribution_outcomes: Vec::new(),
            target_bindings,
        };
        (response, result.receipt_event, result.snapshot_event)
    };
    record_training_coordination_observability(
        &state,
        request.requested_at_ms as u64,
        caller_id.as_str(),
        "kernel.training.validator_challenge.leased",
        receipt_event,
        snapshot_event,
    );
    Ok(Json(response))
}

async fn retry_training_validator_challenge(
    State(state): State<AppState>,
    Path(challenge_id): Path<String>,
    Json(mut request): Json<RetryTrainingValidatorChallengeRequest>,
) -> Result<Json<TrainingValidatorChallengeCoordinatorResponse>, ApiError> {
    let challenge_id =
        normalize_required_field(challenge_id.as_str(), "validator_challenge_id_missing")?;
    request.idempotency_key = normalize_required_field(
        request.idempotency_key.as_str(),
        "training_scheduler_idempotency_key_missing",
    )?;
    request.node_pubkey_hex = normalize_required_field(
        request.node_pubkey_hex.as_str(),
        "training_node_pubkey_missing",
    )?;
    request.detail = normalize_required_field(
        request.detail.as_str(),
        "validator_challenge_detail_missing",
    )?;
    request.recorded_at_ms = if request.recorded_at_ms <= 0 {
        now_unix_ms() as i64
    } else {
        request.recorded_at_ms
    };
    if !request.lease.challenge_id.trim().is_empty() && request.lease.challenge_id != challenge_id {
        return Err(kernel_api_error(
            "kernel_validator_challenge_id_mismatch".to_string(),
        ));
    }
    request.lease.challenge_id = challenge_id.clone();

    let caller_id = training_node_caller_id(request.node_pubkey_hex.as_str());
    let (
        response,
        retry_receipt_event,
        retry_snapshot_event,
        lease_receipt_event,
        lease_snapshot_event,
    ) = {
        let mut store = state.store.write().map_err(|_| ApiError {
            status: StatusCode::INTERNAL_SERVER_ERROR,
            error: "internal_error",
            reason: "session_store_poisoned".to_string(),
        })?;
        let node = store
            .kernel
            .get_admitted_training_node(
                request.node_pubkey_hex.as_str(),
                None,
                request.recorded_at_ms,
            )
            .ok_or_else(|| kernel_api_error("training_node_not_found".to_string()))?;
        if !node.role_claims.contains(&TrainingNodeRoleClaim::Validator) {
            return Err(kernel_api_error(
                "training_validator_role_not_admitted".to_string(),
            ));
        }
        if request.lease.validator_id != node.node_pubkey_hex {
            return Err(kernel_api_error(
                "training_validator_lease_invalid".to_string(),
            ));
        }
        let managed =
            training_find_managed_validator_challenge(&store.kernel, challenge_id.as_str())
                .map_err(kernel_api_error)?;
        let retry_result = store
            .kernel
            .retry_validator_challenge(
                &training_kernel_mutation_context(&caller_id, request.recorded_at_ms as u64),
                RetryValidatorChallengeRequest {
                    idempotency_key: request.idempotency_key.clone(),
                    trace: TraceContext::default(),
                    policy: PolicyContext::default(),
                    lease: service_challenge_lease(&request.lease),
                    finalized_at_ms: request.recorded_at_ms as u64,
                    detail: request.detail.clone(),
                    evidence: Vec::new(),
                    hints: ReceiptHints::default(),
                },
            )
            .map_err(kernel_api_error)?;
        let mut challenge = canonical_challenge_snapshot(retry_result.response.challenge);
        let mut lease = None;
        let mut lease_receipt_event = None;
        let mut lease_snapshot_event = None;
        if challenge.status == ComputeValidatorChallengeStatus::Retrying {
            let lease_result = store
                .kernel
                .lease_validator_challenge(
                    &training_kernel_mutation_context(&caller_id, request.recorded_at_ms as u64),
                    LeaseValidatorChallengeRequest {
                        idempotency_key: format!("{}.lease", request.idempotency_key),
                        trace: TraceContext::default(),
                        policy: PolicyContext::default(),
                        challenge_id: challenge_id.clone(),
                        validator_id: node.node_pubkey_hex.clone(),
                        requested_at_ms: request.recorded_at_ms as u64,
                        evidence: Vec::new(),
                        hints: ReceiptHints::default(),
                    },
                )
                .map_err(kernel_api_error)?;
            challenge = canonical_challenge_snapshot(lease_result.response.challenge);
            lease = Some(ComputeValidatorChallengeLease {
                challenge_id: lease_result.response.lease.challenge_id,
                attempt: lease_result.response.lease.attempt,
                validator_id: lease_result.response.lease.validator_id,
                leased_at_ms: lease_result.response.lease.leased_at_ms,
                expires_at_ms: lease_result.response.lease.expires_at_ms,
            });
            lease_receipt_event = lease_result.receipt_event;
            lease_snapshot_event = lease_result.snapshot_event;
        }
        let target_bindings = training_validator_target_bindings(
            &state.config,
            &store.kernel,
            &managed.window,
            &managed.metadata,
            &managed.challenge_plan,
            challenge_id.as_str(),
            lease
                .as_ref()
                .map(|leased| leased.expires_at_ms as i64)
                .or_else(|| i64::try_from(request.lease.expires_at_ms).ok()),
        )
        .map_err(kernel_api_error)?;
        let response = TrainingValidatorChallengeCoordinatorResponse {
            ack: TrainingCoordinatorAck {
                idempotency_key: request.idempotency_key.clone(),
                recorded_at_ms: request.recorded_at_ms,
                authority_state: challenge.status.label().to_string(),
            },
            network_id: managed.metadata.network_id,
            training_run_id: managed.window.training_run_id,
            window_id: managed.window.window_id,
            challenge_id: challenge_id.clone(),
            challenge_kind: managed.challenge_plan.challenge_kind.label().to_string(),
            target_assignment_ids: managed.challenge_plan.target_assignment_ids,
            expected_manifest_digests: managed.challenge_plan.expected_manifest_digests,
            challenge,
            lease,
            result: None,
            challenge_receipt: retry_result.response.receipt.clone(),
            window_receipt: None,
            window: None,
            contribution_outcomes: Vec::new(),
            target_bindings,
        };
        (
            response,
            retry_result.receipt_event,
            retry_result.snapshot_event,
            lease_receipt_event,
            lease_snapshot_event,
        )
    };
    record_training_coordination_observability(
        &state,
        request.recorded_at_ms as u64,
        caller_id.as_str(),
        "kernel.training.validator_challenge.retried",
        retry_receipt_event,
        retry_snapshot_event,
    );
    if let Some(receipt_event) = lease_receipt_event {
        record_training_coordination_observability(
            &state,
            request.recorded_at_ms as u64,
            caller_id.as_str(),
            "kernel.training.validator_challenge.released",
            Some(receipt_event),
            lease_snapshot_event,
        );
    }
    Ok(Json(response))
}

async fn finalize_training_validator_challenge(
    State(state): State<AppState>,
    Path(challenge_id): Path<String>,
    Json(mut request): Json<FinalizeTrainingValidatorChallengeRequest>,
) -> Result<Json<TrainingValidatorChallengeCoordinatorResponse>, ApiError> {
    let challenge_id =
        normalize_required_field(challenge_id.as_str(), "validator_challenge_id_missing")?;
    request.idempotency_key = normalize_required_field(
        request.idempotency_key.as_str(),
        "training_scheduler_idempotency_key_missing",
    )?;
    request.node_pubkey_hex = normalize_required_field(
        request.node_pubkey_hex.as_str(),
        "training_node_pubkey_missing",
    )?;
    request.recorded_at_ms = if request.recorded_at_ms <= 0 {
        now_unix_ms() as i64
    } else {
        request.recorded_at_ms
    };
    if !request.lease.challenge_id.trim().is_empty() && request.lease.challenge_id != challenge_id {
        return Err(kernel_api_error(
            "kernel_validator_challenge_id_mismatch".to_string(),
        ));
    }
    if !request.result.challenge_id.trim().is_empty() && request.result.challenge_id != challenge_id
    {
        return Err(kernel_api_error(
            "kernel_validator_challenge_result_id_mismatch".to_string(),
        ));
    }
    request.lease.challenge_id = challenge_id.clone();
    request.result.challenge_id = challenge_id.clone();

    let caller_id = training_node_caller_id(request.node_pubkey_hex.as_str());
    let (
        response,
        challenge_receipt_event,
        challenge_snapshot_event,
        window_receipt_event,
        window_snapshot_event,
    ) = {
        let mut store = state.store.write().map_err(|_| ApiError {
            status: StatusCode::INTERNAL_SERVER_ERROR,
            error: "internal_error",
            reason: "session_store_poisoned".to_string(),
        })?;
        let node = store
            .kernel
            .get_admitted_training_node(
                request.node_pubkey_hex.as_str(),
                None,
                request.recorded_at_ms,
            )
            .ok_or_else(|| kernel_api_error("training_node_not_found".to_string()))?;
        if !node.role_claims.contains(&TrainingNodeRoleClaim::Validator) {
            return Err(kernel_api_error(
                "training_validator_role_not_admitted".to_string(),
            ));
        }
        if request.lease.validator_id != node.node_pubkey_hex {
            return Err(kernel_api_error(
                "training_validator_lease_invalid".to_string(),
            ));
        }

        let managed =
            training_find_managed_validator_challenge(&store.kernel, challenge_id.as_str())
                .map_err(kernel_api_error)?;
        let finalize_result = store
            .kernel
            .finalize_validator_challenge(
                &training_kernel_mutation_context(&caller_id, request.recorded_at_ms as u64),
                FinalizeValidatorChallengeRequest {
                    idempotency_key: request.idempotency_key.clone(),
                    trace: TraceContext::default(),
                    policy: PolicyContext::default(),
                    lease: service_challenge_lease(&request.lease),
                    result: service_challenge_result(&request.result),
                    evidence: Vec::new(),
                    hints: ReceiptHints::default(),
                },
            )
            .map_err(kernel_api_error)?;

        let mut metadata = managed.metadata.clone();
        let training_disposition = training_validation_default_disposition(
            request.result.status,
            request.training_disposition,
        );
        let (challenge_kind, target_assignment_ids, expected_manifest_digests, challenge_attempt) = {
            let validation = metadata.validation.as_mut().ok_or_else(|| {
                kernel_api_error("training_window_validation_missing".to_string())
            })?;
            let challenge_index = validation
                .challenges
                .iter()
                .position(|plan| plan.challenge_id == challenge_id)
                .ok_or_else(|| {
                    kernel_api_error("training_validator_challenge_not_found".to_string())
                })?;
            validation.challenges[challenge_index].training_disposition =
                Some(training_disposition);
            validation.last_finalized_at_ms = Some(request.recorded_at_ms);
            let challenge_plan = validation.challenges[challenge_index].clone();
            (
                challenge_plan.challenge_kind,
                challenge_plan.target_assignment_ids,
                challenge_plan.expected_manifest_digests,
                challenge_plan.attempt,
            )
        };

        if challenge_kind == TrainingValidationChallengeKind::Aggregate
            && challenge_attempt == 1
            && matches!(
                training_disposition,
                ComputeAdapterContributionDisposition::Quarantined
                    | ComputeAdapterContributionDisposition::Rejected
                    | ComputeAdapterContributionDisposition::ReplayRequired
            )
        {
            let validation = metadata.validation.as_mut().ok_or_else(|| {
                kernel_api_error("training_window_validation_missing".to_string())
            })?;
            let second_challenge_id = training_validation_challenge_id(
                &managed.window,
                TrainingValidationChallengeKind::Aggregate,
                None,
                2,
            );
            if !validation
                .challenges
                .iter()
                .any(|plan| plan.challenge_id == second_challenge_id)
            {
                let training_product_id = store
                    .kernel
                    .get_compute_training_run(managed.window.training_run_id.as_str())
                    .and_then(|run| run.product_id)
                    .unwrap_or_default();
                let first_plan = validation
                    .challenges
                    .iter()
                    .find(|plan| {
                        plan.challenge_kind == TrainingValidationChallengeKind::Aggregate
                            && plan.attempt == 1
                    })
                    .cloned()
                    .ok_or_else(|| {
                        kernel_api_error("training_window_validation_missing".to_string())
                    })?;
                let second_plan = TrainingWindowValidationChallengePlan {
                    challenge_id: second_challenge_id.clone(),
                    challenge_kind: TrainingValidationChallengeKind::Aggregate,
                    attempt: 2,
                    target_assignment_ids: first_plan.target_assignment_ids.clone(),
                    expected_manifest_digests: first_plan.expected_manifest_digests.clone(),
                    training_disposition: None,
                };
                let schedule_request = training_validation_schedule_request(
                    &managed.window,
                    &second_plan,
                    training_product_id.as_str(),
                    validation.validator_pool_ref.as_str(),
                    managed.window.window_summary_digest.as_str(),
                    managed.window.window_summary_digest.as_str(),
                    request.recorded_at_ms as u64,
                )
                .map_err(kernel_api_error)?;
                store
                    .kernel
                    .schedule_validator_challenge(
                        &training_kernel_mutation_context(
                            &caller_id,
                            request.recorded_at_ms as u64,
                        ),
                        schedule_request,
                    )
                    .map_err(kernel_api_error)?;
                validation.challenges.push(second_plan);
            }
        }

        let validation_summary = {
            let validation = metadata.validation.as_ref().ok_or_else(|| {
                kernel_api_error("training_window_validation_missing".to_string())
            })?;
            training_window_validation_summary(&store.kernel, validation)
                .map_err(kernel_api_error)?
        };
        let mut contribution_outcomes = store.kernel.list_compute_adapter_contribution_outcomes(
            Some(managed.window.training_run_id.as_str()),
            Some(managed.window.window_id.as_str()),
            None,
        );
        training_window_apply_validation_overrides(
            contribution_outcomes.as_mut_slice(),
            &validation_summary,
            finalize_result.response.receipt.canonical_hash.as_str(),
        );
        let (
            total_contributions,
            admitted_contributions,
            accepted_contributions,
            quarantined_contributions,
            rejected_contributions,
            replay_required_contributions,
            replay_checked_contributions,
        ) = training_window_counts(contribution_outcomes.as_slice());
        let mut updated_window = managed.window.clone();
        updated_window.total_contributions = total_contributions;
        updated_window.admitted_contributions = admitted_contributions;
        updated_window.accepted_contributions = accepted_contributions;
        updated_window.quarantined_contributions = quarantined_contributions;
        updated_window.rejected_contributions = rejected_contributions;
        updated_window.replay_required_contributions = replay_required_contributions;
        updated_window.replay_checked_contributions = replay_checked_contributions;
        updated_window.promotion_ready = false;
        updated_window.recorded_at_ms = request.recorded_at_ms;
        updated_window.metadata = training_window_metadata_value(&metadata);
        let validation_held = validation_summary.held_challenge_present
            || matches!(
                validation_summary.aggregate_resolution,
                PylonTrainingAggregateResolution::Held
            );
        if validation_held {
            updated_window.hold_reason_codes =
                vec![ComputeAdapterPromotionHoldReasonCode::ValidatorWindowNotPromotionReady];
        } else if matches!(
            validation_summary.aggregate_terminal_disposition,
            Some(
                ComputeAdapterContributionDisposition::Quarantined
                    | ComputeAdapterContributionDisposition::Rejected
                    | ComputeAdapterContributionDisposition::ReplayRequired
            )
        ) {
            updated_window.promotion_disposition = Some(ComputeAdapterPromotionDisposition::Held);
            updated_window.hold_reason_codes =
                vec![ComputeAdapterPromotionHoldReasonCode::ValidatorWindowNotPromotionReady];
        } else {
            updated_window.promotion_disposition = None;
            updated_window.hold_reason_codes.clear();
        }
        if validation_summary.all_required_terminal && !validation_held {
            updated_window.status = ComputeAdapterWindowStatus::Scored;
        }
        updated_window.window_summary_digest = training_window_summary_digest(
            &updated_window,
            contribution_outcomes.as_slice(),
            &metadata,
        )
        .map_err(kernel_api_error)?;
        let window_result = store
            .kernel
            .record_compute_adapter_window(
                &training_kernel_mutation_context(&caller_id, request.recorded_at_ms as u64),
                training_window_record_request(
                    format!("{}.window", request.idempotency_key),
                    updated_window.clone(),
                    contribution_outcomes.clone(),
                ),
            )
            .map_err(kernel_api_error)?;
        if let Some(scheduled_run) = store
            .training_scheduler
            .runs_by_training_run_id
            .get_mut(updated_window.training_run_id.as_str())
        {
            if validation_held {
                scheduled_run.window_state = TrainingSchedulerWindowState::Held;
            } else {
                scheduled_run.window_state = TrainingSchedulerWindowState::Validating;
            }
            scheduled_run.updated_at_ms = request.recorded_at_ms;
        }
        store
            .persist_training_scheduler_state()
            .map_err(kernel_api_error)?;
        let target_bindings = training_validator_target_bindings(
            &state.config,
            &store.kernel,
            &updated_window,
            &metadata,
            &managed.challenge_plan,
            challenge_id.as_str(),
            i64::try_from(request.lease.expires_at_ms).ok(),
        )
        .map_err(kernel_api_error)?;

        let response = TrainingValidatorChallengeCoordinatorResponse {
            ack: TrainingCoordinatorAck {
                idempotency_key: request.idempotency_key.clone(),
                recorded_at_ms: request.recorded_at_ms,
                authority_state: canonical_challenge_snapshot(
                    finalize_result.response.challenge.clone(),
                )
                .status
                .label()
                .to_string(),
            },
            network_id: metadata.network_id,
            training_run_id: updated_window.training_run_id.clone(),
            window_id: updated_window.window_id.clone(),
            challenge_id: challenge_id.clone(),
            challenge_kind: challenge_kind.label().to_string(),
            target_assignment_ids,
            expected_manifest_digests,
            challenge: canonical_challenge_snapshot(finalize_result.response.challenge),
            lease: None,
            result: Some(request.result.clone()),
            challenge_receipt: finalize_result.response.receipt.clone(),
            window_receipt: Some(window_result.response.receipt.clone()),
            window: Some(updated_window),
            contribution_outcomes,
            target_bindings,
        };
        (
            response,
            finalize_result.receipt_event,
            finalize_result.snapshot_event,
            window_result.receipt_event,
            window_result.snapshot_event,
        )
    };
    record_training_coordination_observability(
        &state,
        request.recorded_at_ms as u64,
        caller_id.as_str(),
        "kernel.training.validator_challenge.finalized",
        challenge_receipt_event,
        challenge_snapshot_event,
    );
    record_training_coordination_observability(
        &state,
        request.recorded_at_ms as u64,
        caller_id.as_str(),
        "kernel.training.window.validation_applied",
        window_receipt_event,
        window_snapshot_event,
    );
    Ok(Json(response))
}

