async fn create_treasury_funding_target(
    State(state): State<AppState>,
    Json(request): Json<TreasuryFundingTargetRequest>,
) -> Result<Json<TreasuryFundingTargetResponse>, ApiError> {
    let normalized_request = TreasuryFundingTargetRequest {
        amount_sats: request.amount_sats.filter(|value| *value > 0),
        description: normalize_optional_field(request.description.as_deref()),
        expiry_seconds: request.expiry_seconds.filter(|value| *value > 0),
    };
    let material = create_live_funding_target(&state.config.treasury, normalized_request)
        .await
        .map_err(|error| ApiError {
            status: StatusCode::BAD_GATEWAY,
            error: "bad_gateway",
            reason: error.to_string(),
        })?;
    let now = now_unix_ms();
    {
        let mut store = state.store.write().map_err(|_| ApiError {
            status: StatusCode::INTERNAL_SERVER_ERROR,
            error: "internal_error",
            reason: "session_store_poisoned".to_string(),
        })?;
        let treasury_receipts = store
            .treasury
            .apply_wallet_snapshot(&material.wallet_snapshot, now);
        store
            .treasury
            .refresh_public_snapshot(&state.config.treasury, now);
        record_treasury_receipt_events(&mut store, treasury_receipts, now);
    }
    Ok(Json(TreasuryFundingTargetResponse {
        authority: "openagents-hosted-nexus".to_string(),
        wallet_runtime_status: material.wallet_snapshot.runtime_status,
        wallet_runtime_detail: material.wallet_snapshot.runtime_detail,
        wallet_hydration_mode: material.wallet_snapshot.wallet_hydration_mode,
        wallet_payment_scan_mode: material.wallet_snapshot.wallet_payment_scan_mode,
        wallet_balance_sats: material.wallet_snapshot.balance_sats,
        wallet_balance_updated_at_unix_ms: now,
        spark_address: material.spark_address,
        bitcoin_address: material.bitcoin_address,
        bolt11_invoice: material.bolt11_invoice,
    }))
}

async fn create_desktop_session(
    State(state): State<AppState>,
    Json(request): Json<DesktopSessionCreateRequest>,
) -> Result<Json<DesktopSessionResponse>, ApiError> {
    let desktop_client_id = normalize_required_field(
        request.desktop_client_id.as_str(),
        "desktop_client_id_missing",
    )?;
    let now = now_unix_ms();
    let access_token = random_token();
    let session_id = format!("sess_{}", random_token());
    let account_id = format!(
        "desktop:{}",
        sanitize_identifier(desktop_client_id.as_str())
    );
    let issued_at_unix_ms = now;
    let expires_at_unix_ms =
        now.saturating_add(state.config.session_ttl_seconds.saturating_mul(1_000));
    let record = DesktopSessionRecord {
        session_id: session_id.clone(),
        account_id: account_id.clone(),
        desktop_client_id: desktop_client_id.clone(),
        device_name: normalize_optional_field(request.device_name.as_deref()),
        bound_nostr_pubkey: normalize_optional_field(request.bound_nostr_pubkey.as_deref()),
        client_version: normalize_optional_field(request.client_version.as_deref()),
        issued_at_unix_ms,
        expires_at_unix_ms,
    };

    let mut store = state.store.write().map_err(|_| ApiError {
        status: StatusCode::INTERNAL_SERVER_ERROR,
        error: "internal_error",
        reason: "session_store_poisoned".to_string(),
    })?;
    store
        .sessions_by_access_token
        .insert(access_token.clone(), record.clone());
    store.economy.record(
        "desktop_session.created",
        now,
        desktop_session_receipt_context(&record),
    );
    drop(store);

    Ok(Json(DesktopSessionResponse {
        session_id,
        account_id,
        access_token,
        token_type: "Bearer".to_string(),
        desktop_client_id,
        device_name: record.device_name,
        bound_nostr_pubkey: record.bound_nostr_pubkey,
        client_version: record.client_version,
        issued_at_unix_ms,
        expires_at_unix_ms,
    }))
}

