fn build_public_stats_snapshot(
    config: &ServiceConfig,
    store: &ControlStore,
    launch_metrics: &TrainingLaunchLiveMetricsSnapshot,
    now_unix_ms: u64,
) -> PublicStatsSnapshot {
    let treasury_runtime = store.treasury.public_stats(&config.treasury, now_unix_ms);
    let training_payout_ledger_summary = store
        .treasury
        .status_response(&config.treasury, now_unix_ms)
        .training_payout_ledger_summary;
    let training_summary = training_operator_summary_snapshot(store, now_unix_ms);
    let mut training_public_state =
        training_public_stats_snapshot(store, now_unix_ms, &training_summary);
    training_public_state.launch_health = build_training_launch_health_snapshot(
        &training_summary,
        &treasury_runtime,
        &training_payout_ledger_summary,
        launch_metrics,
        now_unix_ms,
    );
    store.economy.snapshot(
        &runtime_snapshot(
            config,
            store,
            &treasury_runtime,
            &training_summary,
            training_public_state,
            now_unix_ms,
        ),
        now_unix_ms,
    )
}

fn training_closeout_status_label(outcome: &ComputeAcceptedOutcome) -> Option<&str> {
    outcome
        .metadata
        .get("closeout_status")
        .and_then(Value::as_str)
}

fn training_work_progress_class(work_class: ComputeTrainingWorkClass) -> TrainingWorkProgressClass {
    match work_class {
        ComputeTrainingWorkClass::ValidationReplay | ComputeTrainingWorkClass::Evaluation => {
            TrainingWorkProgressClass::ParticipationOnly
        }
        ComputeTrainingWorkClass::AdapterTraining
        | ComputeTrainingWorkClass::SmallModelLocalTraining
        | ComputeTrainingWorkClass::GroupedReplicaStageExecution
        | ComputeTrainingWorkClass::FullIslandLocalUpdateTraining => {
            TrainingWorkProgressClass::ModelUpdate
        }
        ComputeTrainingWorkClass::Aggregation | ComputeTrainingWorkClass::CheckpointPromotion => {
            TrainingWorkProgressClass::CheckpointAdvance
        }
    }
}

fn training_outcome_work_class(
    outcome: &ComputeAcceptedOutcome,
) -> Option<ComputeTrainingWorkClass> {
    outcome
        .metadata
        .get("work_class")
        .and_then(Value::as_str)
        .and_then(ComputeTrainingWorkClass::parse)
}

fn training_outcome_payout_eligible(outcome: &ComputeAcceptedOutcome) -> bool {
    outcome
        .metadata
        .get("payout_eligible")
        .and_then(Value::as_bool)
        .unwrap_or(false)
}

fn training_outcome_latest_payout_basis(outcome: &ComputeAcceptedOutcome) -> Option<String> {
    outcome
        .metadata
        .get("payout_projection")
        .and_then(|value| value.get("basis"))
        .and_then(Value::as_str)
        .map(str::to_string)
}

fn training_outcome_counts_as_accepted_closeout(outcome: &ComputeAcceptedOutcome) -> bool {
    match training_closeout_status_label(outcome) {
        Some("held" | "quarantined" | "refused") => false,
        Some(_) | None => true,
    }
}

fn training_outcome_counts_as_accepted_progress(outcome: &ComputeAcceptedOutcome) -> bool {
    training_outcome_counts_as_accepted_closeout(outcome)
        && training_outcome_work_class(outcome)
            .map(training_work_progress_class)
            .is_some_and(TrainingWorkProgressClass::progress_bearing)
}

fn training_work_class_weak_device_bearing(work_class: ComputeTrainingWorkClass) -> bool {
    training_scheduler_minimum_tier_for_work_class(TrainingNodeRoleClaim::Worker, work_class)
        .ordinal()
        < ProviderTrainingCapabilityTier::Tier3Island.ordinal()
}

fn training_contribution_counts_as_accepted_progress(
    contribution: &ComputeAdapterContributionOutcome,
) -> bool {
    training_work_progress_class(contribution.work_class).progress_bearing()
        && (contribution.accepted_for_aggregation
            || contribution.validator_disposition
                == ComputeAdapterContributionDisposition::Accepted
            || contribution.aggregation_eligibility
                == ComputeAdapterAggregationEligibility::Eligible)
}

fn training_outcome_advances_checkpoint_lineage(outcome: &ComputeAcceptedOutcome) -> bool {
    if !training_outcome_counts_as_accepted_progress(outcome) {
        return false;
    }

    let accepted_checkpoint_ref = outcome
        .training_summary
        .as_ref()
        .and_then(|summary| summary.accepted_checkpoint_ref.as_deref())
        .or_else(|| {
            outcome
                .metadata
                .get("promoted_checkpoint_ref")
                .and_then(Value::as_str)
        });
    accepted_checkpoint_ref.is_some_and(|accepted_checkpoint_ref| {
        outcome
            .checkpoint_binding
            .as_ref()
            .and_then(|binding| binding.latest_checkpoint_ref.as_deref())
            .is_none_or(|previous_checkpoint_ref| {
                previous_checkpoint_ref != accepted_checkpoint_ref
            })
    })
}

fn training_window_advances_checkpoint_lineage<'a>(
    window: &ComputeAdapterTrainingWindow,
    accepted_outcomes_by_id: &HashMap<&'a str, &'a ComputeAcceptedOutcome>,
) -> bool {
    if window
        .promoted_checkpoint_ref
        .as_deref()
        .is_some_and(|checkpoint_ref| checkpoint_ref != window.base_checkpoint_ref)
    {
        return true;
    }
    if window
        .output_checkpoint_pointer
        .as_ref()
        .is_some_and(|pointer| pointer.checkpoint_ref != window.base_checkpoint_ref)
    {
        return true;
    }

    window
        .accepted_outcome_id
        .as_deref()
        .and_then(|outcome_id| accepted_outcomes_by_id.get(outcome_id).copied())
        .is_some_and(training_outcome_advances_checkpoint_lineage)
}

fn training_rollout_policy_snapshot(
    store: &ControlStore,
    now_unix_ms: u64,
) -> TrainingRolloutPolicyResponse {
    let admitted_nodes = store.kernel.list_admitted_training_nodes(
        &TrainingNodeQuery {
            network_id: None,
            requested_network_id: None,
            role: None,
            online_only: false,
            eligible_only: false,
        },
        now_unix_ms as i64,
    );
    let policy = store.training_scheduler.rollout_policy().clone();
    let abuse_snapshot = training_fleet_abuse_snapshot(
        &store.kernel,
        &store.training_scheduler,
        &policy.abuse_controls,
        now_unix_ms,
    );
    let mut channels = [
        (
            TrainingRolloutChannel::Canary,
            TrainingRolloutChannelNodeSummary {
                channel: TrainingRolloutChannel::Canary.label().to_string(),
                nodes_total: 0,
                nodes_online: 0,
                nodes_eligible: 0,
            },
        ),
        (
            TrainingRolloutChannel::Beta,
            TrainingRolloutChannelNodeSummary {
                channel: TrainingRolloutChannel::Beta.label().to_string(),
                nodes_total: 0,
                nodes_online: 0,
                nodes_eligible: 0,
            },
        ),
        (
            TrainingRolloutChannel::Broad,
            TrainingRolloutChannelNodeSummary {
                channel: TrainingRolloutChannel::Broad.label().to_string(),
                nodes_total: 0,
                nodes_online: 0,
                nodes_eligible: 0,
            },
        ),
    ]
    .into_iter()
    .collect::<BTreeMap<_, _>>();
    for node in &admitted_nodes {
        let channel = training_rollout_channel_for_node(&policy, node);
        if let Some(summary) = channels.get_mut(&channel) {
            summary.nodes_total = summary.nodes_total.saturating_add(1);
            if node.online {
                summary.nodes_online = summary.nodes_online.saturating_add(1);
            }
            if node.eligible {
                summary.nodes_eligible = summary.nodes_eligible.saturating_add(1);
            }
        }
    }

    let cohorts = policy
        .cohorts
        .iter()
        .map(|cohort| {
            let matched_nodes = admitted_nodes
                .iter()
                .filter(|node| training_rollout_cohort_matches_node(cohort, node))
                .collect::<Vec<_>>();
            TrainingRolloutCohortResponse {
                cohort_id: cohort.cohort_id.clone(),
                channel: cohort.channel.label().to_string(),
                enabled: cohort.enabled,
                node_pubkey_hexes: cohort.node_pubkey_hexes.clone(),
                release_ids: cohort.release_ids.clone(),
                build_digests: cohort.build_digests.clone(),
                matched_nodes: matched_nodes.len() as u64,
                matched_online_nodes: matched_nodes.iter().filter(|node| node.online).count()
                    as u64,
                matched_eligible_nodes: matched_nodes.iter().filter(|node| node.eligible).count()
                    as u64,
            }
        })
        .collect::<Vec<_>>();

    TrainingRolloutPolicyResponse {
        revision: policy.revision,
        updated_at_unix_ms: u64::try_from(policy.updated_at_ms.max(0)).unwrap_or_default(),
        pause_new_leases: policy.pause_new_leases,
        pause_reason: policy.pause_reason.clone(),
        default_channel: TrainingRolloutChannel::Broad.label().to_string(),
        gates: policy
            .gates
            .iter()
            .map(|gate| TrainingRolloutGateResponse {
                target_kind: gate.target_kind.label().to_string(),
                target_ref: gate.target_ref.clone(),
                max_channel: gate.max_channel.label().to_string(),
                enabled: gate.enabled,
                reason: gate.reason.clone(),
            })
            .collect(),
        cohorts,
        blocked_release_ids: policy.blocked_release_ids.clone(),
        blocked_build_digests: policy.blocked_build_digests.clone(),
        abuse_controls: policy.abuse_controls.clone(),
        abuse_summary: training_rollout_abuse_summary_response(
            &policy.abuse_controls,
            &abuse_snapshot,
        ),
        channels: channels.into_values().collect(),
    }
}

fn training_operator_summary_snapshot(
    store: &ControlStore,
    now_unix_ms: u64,
) -> TrainingOperatorSummaryResponse {
    let admitted_nodes = store.kernel.list_admitted_training_nodes(
        &TrainingNodeQuery {
            network_id: None,
            requested_network_id: None,
            role: None,
            online_only: false,
            eligible_only: false,
        },
        now_unix_ms as i64,
    );
    let training_runs = store.kernel.list_compute_training_runs(None, None, None);
    let training_windows = store
        .kernel
        .list_compute_adapter_training_windows(None, None);
    let accepted_outcomes = store
        .kernel
        .list_compute_accepted_outcomes(Some(ComputeAcceptedOutcomeKind::TrainingRun), None);
    let contribution_outcomes = store
        .kernel
        .list_compute_adapter_contribution_outcomes(None, None, None);
    let validator_challenges = store.kernel.list_validator_challenges(None);
    let accepted_outcomes_by_id = accepted_outcomes
        .iter()
        .map(|outcome| (outcome.outcome_id.as_str(), outcome))
        .collect::<HashMap<_, _>>();

    let mut challenge_bindings = HashMap::<String, (String, String)>::new();
    for window in &training_windows {
        let Ok(metadata) = training_window_metadata_from_value(&window.metadata) else {
            continue;
        };
        if let Some(validation) = metadata.validation {
            for challenge in validation.challenges {
                challenge_bindings.insert(
                    challenge.challenge_id,
                    (window.training_run_id.clone(), window.window_id.clone()),
                );
            }
        }
    }

    let mut progress_contributor_ids = HashSet::<String>::new();
    let mut assigned_contributor_ids = HashSet::<String>::new();
    let mut weak_device_assigned_contributor_ids = HashSet::<String>::new();
    let mut accepted_contributor_ids = HashSet::<String>::new();
    let mut weak_device_accepted_contributor_ids = HashSet::<String>::new();
    let mut settlement_accepted_closeouts = 0u64;
    let mut settlement_payout_eligible_closeouts = 0u64;
    let mut settlement_weak_device_bearing_closeouts = 0u64;
    let mut work_class_summaries = BTreeMap::<String, TrainingOperatorWorkClassSummary>::new();
    let mut run_summaries = training_runs
        .iter()
        .map(|run| {
            let scheduler_state = store
                .training_scheduler
                .runs_by_training_run_id
                .get(run.training_run_id.as_str());
            let metadata = training_scheduler_metadata_from_run(run).ok();
            let network_id = metadata
                .as_ref()
                .map(|value| value.network_id.clone())
                .or_else(|| scheduler_state.map(|value| value.network_id.clone()))
                .unwrap_or_else(|| "unknown".to_string());
            let role_plan = scheduler_state
                .map(|value| value.role_plan)
                .or_else(|| {
                    metadata.as_ref().map(|value| TrainingSchedulerRolePlan {
                        worker_count: value.worker_count,
                        validator_count: value.validator_count,
                        recovery_source_count: value.recovery_source_count,
                    })
                })
                .unwrap_or(TrainingSchedulerRolePlan {
                    worker_count: 0,
                    validator_count: 0,
                    recovery_source_count: 0,
                });
            let run_nodes = admitted_nodes
                .iter()
                .filter(|node| {
                    (network_id != "unknown"
                        && node
                            .allowed_networks
                            .iter()
                            .any(|allowed| allowed == &network_id))
                        || node.last_training_run_id.as_deref()
                            == Some(run.training_run_id.as_str())
                })
                .collect::<Vec<_>>();
            let admitted_nodes = run_nodes.len() as u64;
            let admitted_nodes_online = run_nodes.iter().filter(|node| node.online).count() as u64;
            let worker_nodes_online = run_nodes
                .iter()
                .filter(|node| {
                    node.online && node.role_claims.contains(&TrainingNodeRoleClaim::Worker)
                })
                .count() as u64;
            let validator_nodes_online = run_nodes
                .iter()
                .filter(|node| {
                    node.online && node.role_claims.contains(&TrainingNodeRoleClaim::Validator)
                })
                .count() as u64;
            let recovery_source_nodes_online = run_nodes
                .iter()
                .filter(|node| {
                    node.online
                        && node
                            .role_claims
                            .contains(&TrainingNodeRoleClaim::RecoverySource)
                })
                .count() as u64;

            let run_windows = training_windows
                .iter()
                .filter(|window| window.training_run_id == run.training_run_id)
                .collect::<Vec<_>>();
            let run_window_metadata = run_windows
                .iter()
                .filter_map(|window| {
                    training_window_metadata_from_value(&window.metadata)
                        .ok()
                        .map(|metadata| (*window, metadata))
                })
                .collect::<Vec<_>>();
            let weak_device_bearing_run = training_work_class_weak_device_bearing(run.work_class);
            let mut run_assigned_contributor_ids = HashSet::<String>::new();
            for assignment in scheduler_state
                .into_iter()
                .flat_map(|value| value.assignments.iter())
                .filter(|assignment| assignment.role == TrainingNodeRoleClaim::Worker)
            {
                let Some(node_pubkey_hex) = assignment.node_pubkey_hex.as_deref() else {
                    continue;
                };
                let node_pubkey_hex = node_pubkey_hex.trim();
                if node_pubkey_hex.is_empty() {
                    continue;
                }
                run_assigned_contributor_ids.insert(node_pubkey_hex.to_string());
            }
            for (_, metadata) in &run_window_metadata {
                for assignment in &metadata.assignment_plans {
                    let contributor_node_id = if assignment.contributor_node_id.trim().is_empty() {
                        assignment.node_pubkey_hex.trim()
                    } else {
                        assignment.contributor_node_id.trim()
                    };
                    if contributor_node_id.is_empty() {
                        continue;
                    }
                    run_assigned_contributor_ids.insert(contributor_node_id.to_string());
                }
            }
            for contribution in contribution_outcomes
                .iter()
                .filter(|contribution| contribution.training_run_id == run.training_run_id)
            {
                let contributor_node_id = contribution.contributor_node_id.trim();
                if contributor_node_id.is_empty() {
                    continue;
                }
                run_assigned_contributor_ids.insert(contributor_node_id.to_string());
            }
            assigned_contributor_ids.extend(run_assigned_contributor_ids.iter().cloned());
            if weak_device_bearing_run {
                weak_device_assigned_contributor_ids
                    .extend(run_assigned_contributor_ids.iter().cloned());
            }
            let active_window_count = run_windows
                .iter()
                .filter(|window| window.status != ComputeAdapterWindowStatus::Reconciled)
                .count() as u64;
            let pending_validation_window_count = run_windows
                .iter()
                .filter(|window| {
                    matches!(
                        window.status,
                        ComputeAdapterWindowStatus::Sealed | ComputeAdapterWindowStatus::Scored
                    )
                })
                .count() as u64;
            let latest_window = run_windows
                .iter()
                .max_by(|lhs, rhs| {
                    lhs.recorded_at_ms
                        .cmp(&rhs.recorded_at_ms)
                        .then_with(|| lhs.window_id.cmp(&rhs.window_id))
                })
                .copied();

            let run_challenges = validator_challenges
                .iter()
                .filter(|snapshot| {
                    challenge_bindings
                        .get(snapshot.request.context.challenge_id.as_str())
                        .is_some_and(|(training_run_id, _)| training_run_id == &run.training_run_id)
                })
                .collect::<Vec<_>>();
            let queued_validator_challenges = run_challenges
                .iter()
                .filter(|snapshot| snapshot.status == ServiceValidatorChallengeStatus::Queued)
                .count() as u64;
            let open_validator_challenges = run_challenges
                .iter()
                .filter(|snapshot| {
                    matches!(
                        snapshot.status,
                        ServiceValidatorChallengeStatus::Queued
                            | ServiceValidatorChallengeStatus::Leased
                            | ServiceValidatorChallengeStatus::Retrying
                    )
                })
                .count() as u64;

            let run_outcomes = accepted_outcomes
                .iter()
                .filter(|outcome| outcome.source_run_id == run.training_run_id)
                .collect::<Vec<_>>();
            let accepted_terminal_outcomes = run_outcomes
                .iter()
                .copied()
                .filter(|outcome| training_outcome_counts_as_accepted_closeout(outcome))
                .collect::<Vec<_>>();
            let accepted_progress_outcomes = run_outcomes
                .iter()
                .copied()
                .filter(|outcome| training_outcome_counts_as_accepted_progress(outcome))
                .collect::<Vec<_>>();
            let accepted_terminal_window_ids = accepted_terminal_outcomes
                .iter()
                .filter_map(|outcome| outcome.metadata.get("window_id").and_then(Value::as_str))
                .collect::<HashSet<_>>();
            let accepted_progress_window_ids = accepted_progress_outcomes
                .iter()
                .filter_map(|outcome| outcome.metadata.get("window_id").and_then(Value::as_str))
                .collect::<HashSet<_>>();
            let accepted_contributors = contribution_outcomes
                .iter()
                .filter(|contribution| contribution.training_run_id == run.training_run_id)
                .filter(|contribution| {
                    accepted_terminal_window_ids.contains(contribution.window_id.as_str())
                })
                .filter(|contribution| training_contribution_counts_for_settlement(contribution))
                .filter_map(|contribution| {
                    let contributor_node_id = contribution.contributor_node_id.trim();
                    (!contributor_node_id.is_empty()).then(|| contributor_node_id.to_string())
                })
                .collect::<HashSet<_>>();
            accepted_contributor_ids.extend(accepted_contributors.iter().cloned());
            let weak_device_accepted_contributors = contribution_outcomes
                .iter()
                .filter(|contribution| contribution.training_run_id == run.training_run_id)
                .filter(|contribution| {
                    accepted_terminal_window_ids.contains(contribution.window_id.as_str())
                })
                .filter(|contribution| training_contribution_counts_for_settlement(contribution))
                .filter(|contribution| {
                    training_contribution_weak_device_bearing(contribution)
                        || training_work_class_weak_device_bearing(contribution.work_class)
                })
                .filter_map(|contribution| {
                    let contributor_node_id = contribution.contributor_node_id.trim();
                    (!contributor_node_id.is_empty()).then(|| contributor_node_id.to_string())
                })
                .collect::<HashSet<_>>();
            weak_device_accepted_contributor_ids
                .extend(weak_device_accepted_contributors.iter().cloned());
            let nodes_contributing_to_accepted_progress = contribution_outcomes
                .iter()
                .filter(|contribution| contribution.training_run_id == run.training_run_id)
                .filter(|contribution| {
                    accepted_progress_window_ids.contains(contribution.window_id.as_str())
                })
                .filter(|contribution| {
                    training_contribution_counts_as_accepted_progress(contribution)
                })
                .filter_map(|contribution| {
                    (!contribution.contributor_node_id.trim().is_empty())
                        .then(|| contribution.contributor_node_id.clone())
                })
                .collect::<HashSet<_>>();
            progress_contributor_ids
                .extend(nodes_contributing_to_accepted_progress.iter().cloned());
            let accepted_closeouts = accepted_progress_outcomes.len() as u64;
            let payout_eligible_closeouts = accepted_progress_outcomes
                .iter()
                .filter(|outcome| training_outcome_payout_eligible(outcome))
                .count() as u64;
            let settlement_closeouts = accepted_terminal_outcomes.len() as u64;
            let settlement_payout_eligible_run_closeouts = accepted_terminal_outcomes
                .iter()
                .filter(|outcome| training_outcome_payout_eligible(outcome))
                .count() as u64;
            let weak_device_bearing_run_closeouts = accepted_terminal_outcomes
                .iter()
                .filter(|outcome| training_outcome_weak_device_bearing(outcome))
                .count() as u64;
            settlement_accepted_closeouts =
                settlement_accepted_closeouts.saturating_add(settlement_closeouts);
            settlement_payout_eligible_closeouts = settlement_payout_eligible_closeouts
                .saturating_add(settlement_payout_eligible_run_closeouts);
            settlement_weak_device_bearing_closeouts = settlement_weak_device_bearing_closeouts
                .saturating_add(weak_device_bearing_run_closeouts);
            let work_class = run.work_class.label().to_string();
            let progress_class = training_work_progress_class(run.work_class)
                .label()
                .to_string();
            let participation_only_closeouts =
                settlement_closeouts.saturating_sub(accepted_closeouts);
            let work_class_summary = work_class_summaries
                .entry(work_class.clone())
                .or_insert_with(|| TrainingOperatorWorkClassSummary {
                    work_class: work_class.clone(),
                    progress_class: progress_class.clone(),
                    run_count: 0,
                    accepted_closeouts: 0,
                    payout_eligible_closeouts: 0,
                    weak_device_bearing_closeouts: 0,
                    progress_bearing_closeouts: 0,
                    participation_only_closeouts: 0,
                });
            work_class_summary.run_count = work_class_summary.run_count.saturating_add(1);
            work_class_summary.accepted_closeouts = work_class_summary
                .accepted_closeouts
                .saturating_add(settlement_closeouts);
            work_class_summary.payout_eligible_closeouts = work_class_summary
                .payout_eligible_closeouts
                .saturating_add(settlement_payout_eligible_run_closeouts);
            work_class_summary.weak_device_bearing_closeouts = work_class_summary
                .weak_device_bearing_closeouts
                .saturating_add(weak_device_bearing_run_closeouts);
            work_class_summary.progress_bearing_closeouts = work_class_summary
                .progress_bearing_closeouts
                .saturating_add(accepted_closeouts);
            work_class_summary.participation_only_closeouts = work_class_summary
                .participation_only_closeouts
                .saturating_add(participation_only_closeouts);
            let windows_advanced_checkpoint_lineage = run_windows
                .iter()
                .filter(|window| {
                    training_window_advances_checkpoint_lineage(window, &accepted_outcomes_by_id)
                })
                .count() as u64;
            let latest_closeout = run_outcomes
                .iter()
                .max_by(|lhs, rhs| {
                    lhs.accepted_at_ms
                        .cmp(&rhs.accepted_at_ms)
                        .then_with(|| lhs.outcome_id.cmp(&rhs.outcome_id))
                })
                .copied();
            let latest_checkpoint_ref = latest_closeout
                .and_then(|outcome| {
                    outcome
                        .training_summary
                        .as_ref()
                        .and_then(|summary| summary.accepted_checkpoint_ref.clone())
                        .or_else(|| {
                            outcome
                                .checkpoint_binding
                                .as_ref()
                                .and_then(|binding| binding.latest_checkpoint_ref.clone())
                        })
                })
                .or_else(|| run.final_checkpoint_ref.clone())
                .or_else(|| run.promotion_checkpoint_ref.clone())
                .or_else(|| {
                    run.summary
                        .as_ref()
                        .and_then(|summary| summary.accepted_checkpoint_ref.clone())
                })
                .or_else(|| run.checkpoint_binding.latest_checkpoint_ref.clone())
                .or_else(|| {
                    metadata
                        .as_ref()
                        .and_then(|value| value.checkpoint_ref.clone())
                })
                .or_else(|| scheduler_state.and_then(|value| value.checkpoint_ref.clone()));
            let latest_checkpoint_age_ms = latest_closeout
                .and_then(|outcome| u64::try_from(outcome.accepted_at_ms).ok())
                .or_else(|| {
                    run.finalized_at_ms
                        .and_then(|value| u64::try_from(value).ok())
                })
                .or_else(|| {
                    run.started_at_ms
                        .and_then(|value| u64::try_from(value).ok())
                })
                .or_else(|| Some(run.created_at_ms).and_then(|value| u64::try_from(value).ok()))
                .filter(|_| latest_checkpoint_ref.is_some())
                .map(|updated_at_ms| now_unix_ms.saturating_sub(updated_at_ms));
            let latest_closeout_status = latest_closeout.and_then(|outcome| {
                outcome
                    .metadata
                    .get("closeout_status")
                    .and_then(Value::as_str)
                    .map(str::to_string)
            });
            let settlement = TrainingOperatorRunSettlementSummary {
                work_class,
                replica_type: run.replica_type.label().to_string(),
                progress_class,
                accepted_closeouts: settlement_closeouts,
                payout_eligible_closeouts: settlement_payout_eligible_run_closeouts,
                weak_device_bearing_closeouts: weak_device_bearing_run_closeouts,
                latest_payout_basis: latest_closeout.and_then(training_outcome_latest_payout_basis),
            };
            let participation = TrainingOperatorRunParticipationSummary {
                admitted_nodes,
                assigned_contributors: run_assigned_contributor_ids.len() as u64,
                weak_device_assigned_contributors: if weak_device_bearing_run {
                    run_assigned_contributor_ids.len() as u64
                } else {
                    0
                },
                online_nodes: admitted_nodes_online,
                worker_nodes_online,
                validator_nodes_online,
                recovery_source_nodes_online,
                worker_target_count: role_plan.worker_count,
                validator_target_count: role_plan.validator_count,
                recovery_source_target_count: role_plan.recovery_source_count,
                active_window_count,
                pending_validation_window_count,
                open_validator_challenges,
                queued_validator_challenges,
            };
            let progress = TrainingOperatorRunProgressSummary {
                accepted_contributors: accepted_contributors.len() as u64,
                weak_device_accepted_contributors: weak_device_accepted_contributors.len() as u64,
                model_progress_contributors: nodes_contributing_to_accepted_progress.len() as u64,
                nodes_contributing_to_accepted_progress: nodes_contributing_to_accepted_progress
                    .len() as u64,
                windows_advanced_checkpoint_lineage,
                accepted_closeouts,
                payout_eligible_closeouts,
                latest_checkpoint_ref: latest_checkpoint_ref.clone(),
                latest_checkpoint_age_ms,
                artifact_failures_open: 0,
                latest_window_id: latest_window.map(|value| value.window_id.clone()),
                latest_window_status: latest_window.map(|value| value.status.label().to_string()),
                latest_closeout_status,
            };

            TrainingOperatorRunSummary {
                training_run_id: run.training_run_id.clone(),
                network_id,
                run_status: run.status.label().to_string(),
                scheduler_window_state: scheduler_state
                    .map(|value| value.window_state.label().to_string())
                    .or_else(|| latest_window.map(|value| value.status.label().to_string()))
                    .or_else(|| {
                        metadata.as_ref().map(|_| {
                            if training_run_schedulable(run) {
                                "active".to_string()
                            } else {
                                "unknown".to_string()
                            }
                        })
                    })
                    .unwrap_or_else(|| "unknown".to_string()),
                current_window_id: scheduler_state
                    .map(|value| value.current_window_id.clone())
                    .or_else(|| latest_window.map(|value| value.window_id.clone()))
                    .or_else(|| {
                        metadata
                            .as_ref()
                            .and_then(|value| value.initial_window_id.clone())
                    })
                    .unwrap_or_else(|| "unknown".to_string()),
                participation,
                progress: progress.clone(),
                settlement,
                admitted_nodes,
                assigned_contributors: run_assigned_contributor_ids.len() as u64,
                weak_device_assigned_contributors: if weak_device_bearing_run {
                    run_assigned_contributor_ids.len() as u64
                } else {
                    0
                },
                accepted_contributors: progress.accepted_contributors,
                weak_device_accepted_contributors: progress.weak_device_accepted_contributors,
                model_progress_contributors: progress.model_progress_contributors,
                admitted_nodes_online,
                worker_nodes_online,
                validator_nodes_online,
                recovery_source_nodes_online,
                worker_target_count: role_plan.worker_count,
                validator_target_count: role_plan.validator_count,
                recovery_source_target_count: role_plan.recovery_source_count,
                active_window_count,
                pending_validation_window_count,
                open_validator_challenges,
                queued_validator_challenges,
                accepted_closeouts,
                payout_eligible_closeouts,
                nodes_contributing_to_accepted_progress: progress
                    .nodes_contributing_to_accepted_progress,
                windows_advanced_checkpoint_lineage: progress.windows_advanced_checkpoint_lineage,
                latest_checkpoint_ref: progress.latest_checkpoint_ref.clone(),
                latest_checkpoint_age_ms: progress.latest_checkpoint_age_ms,
                artifact_failures_open: 0,
                latest_window_id: progress.latest_window_id.clone(),
                latest_window_status: progress.latest_window_status.clone(),
                latest_closeout_status: progress.latest_closeout_status.clone(),
            }
        })
        .collect::<Vec<_>>();
    run_summaries.sort_by(|lhs, rhs| lhs.training_run_id.cmp(&rhs.training_run_id));

    let checkpoint_max_age_ms = run_summaries
        .iter()
        .filter_map(|summary| summary.progress.latest_checkpoint_age_ms)
        .max();
    let metrics = TrainingOperatorMetrics {
        admitted_nodes: admitted_nodes.len() as u64,
        assigned_contributors: assigned_contributor_ids.len() as u64,
        weak_device_assigned_contributors: weak_device_assigned_contributor_ids.len() as u64,
        accepted_contributors: accepted_contributor_ids.len() as u64,
        weak_device_accepted_contributors: weak_device_accepted_contributor_ids.len() as u64,
        model_progress_contributors: progress_contributor_ids.len() as u64,
        admitted_nodes_online: admitted_nodes.iter().filter(|node| node.online).count() as u64,
        active_runs: training_runs
            .iter()
            .filter(|run| {
                matches!(
                    run.status,
                    ComputeTrainingRunStatus::Queued
                        | ComputeTrainingRunStatus::Preparing
                        | ComputeTrainingRunStatus::Running
                        | ComputeTrainingRunStatus::Finalizing
                )
            })
            .count() as u64,
        active_windows: run_summaries
            .iter()
            .map(|summary| summary.participation.active_window_count)
            .sum(),
        pending_validation_windows: run_summaries
            .iter()
            .map(|summary| summary.participation.pending_validation_window_count)
            .sum(),
        validator_challenges_open: run_summaries
            .iter()
            .map(|summary| summary.participation.open_validator_challenges)
            .sum(),
        validator_challenges_queued: run_summaries
            .iter()
            .map(|summary| summary.participation.queued_validator_challenges)
            .sum(),
        checkpoint_max_age_ms,
        artifact_failures_open: 0,
        accepted_closeouts: run_summaries
            .iter()
            .map(|summary| summary.progress.accepted_closeouts)
            .sum(),
        payout_eligible_closeouts: run_summaries
            .iter()
            .map(|summary| summary.progress.payout_eligible_closeouts)
            .sum(),
        nodes_contributing_to_accepted_progress: progress_contributor_ids.len() as u64,
        windows_advanced_checkpoint_lineage: run_summaries
            .iter()
            .map(|summary| summary.progress.windows_advanced_checkpoint_lineage)
            .sum(),
        runs_with_accepted_progress: run_summaries
            .iter()
            .filter(|summary| summary.progress.accepted_closeouts > 0)
            .count() as u64,
    };
    let participation = TrainingOperatorParticipationSummary {
        admitted_nodes: metrics.admitted_nodes,
        assigned_contributors: metrics.assigned_contributors,
        weak_device_assigned_contributors: metrics.weak_device_assigned_contributors,
        online_nodes: metrics.admitted_nodes_online,
        active_runs: metrics.active_runs,
        active_windows: metrics.active_windows,
        pending_validation_windows: metrics.pending_validation_windows,
        validator_challenges_open: metrics.validator_challenges_open,
        validator_challenges_queued: metrics.validator_challenges_queued,
    };
    let progress = TrainingOperatorProgressSummary {
        accepted_contributors: metrics.accepted_contributors,
        weak_device_accepted_contributors: metrics.weak_device_accepted_contributors,
        model_progress_contributors: metrics.model_progress_contributors,
        runs_with_accepted_progress: metrics.runs_with_accepted_progress,
        windows_advanced_checkpoint_lineage: metrics.windows_advanced_checkpoint_lineage,
        nodes_contributing_to_accepted_progress: metrics.model_progress_contributors,
        accepted_closeouts: metrics.accepted_closeouts,
        payout_eligible_closeouts: metrics.payout_eligible_closeouts,
        checkpoint_max_age_ms,
        artifact_failures_open: metrics.artifact_failures_open,
    };
    let settlement = TrainingOperatorSettlementSummary {
        accepted_closeouts: settlement_accepted_closeouts,
        payout_eligible_closeouts: settlement_payout_eligible_closeouts,
        weak_device_bearing_closeouts: settlement_weak_device_bearing_closeouts,
        work_classes: work_class_summaries.into_values().collect(),
    };

    TrainingOperatorSummaryResponse {
        generated_at_unix_ms: now_unix_ms,
        participation,
        progress,
        settlement,
        admitted_nodes: metrics.admitted_nodes,
        assigned_contributors: metrics.assigned_contributors,
        weak_device_assigned_contributors: metrics.weak_device_assigned_contributors,
        accepted_contributors: metrics.accepted_contributors,
        weak_device_accepted_contributors: metrics.weak_device_accepted_contributors,
        model_progress_contributors: metrics.model_progress_contributors,
        admitted_nodes_online: metrics.admitted_nodes_online,
        active_runs: metrics.active_runs,
        active_windows: metrics.active_windows,
        pending_validation_windows: metrics.pending_validation_windows,
        validator_challenges_open: metrics.validator_challenges_open,
        validator_challenges_queued: metrics.validator_challenges_queued,
        checkpoint_max_age_ms: metrics.checkpoint_max_age_ms,
        artifact_failures_open: metrics.artifact_failures_open,
        accepted_closeouts: metrics.accepted_closeouts,
        payout_eligible_closeouts: metrics.payout_eligible_closeouts,
        nodes_contributing_to_accepted_progress: metrics.model_progress_contributors,
        windows_advanced_checkpoint_lineage: metrics.windows_advanced_checkpoint_lineage,
        runs_with_accepted_progress: metrics.runs_with_accepted_progress,
        runs: run_summaries,
    }
}

fn training_operator_metrics_from_summary(
    summary: &TrainingOperatorSummaryResponse,
) -> TrainingOperatorMetrics {
    TrainingOperatorMetrics {
        admitted_nodes: summary.participation.admitted_nodes,
        assigned_contributors: summary.participation.assigned_contributors,
        weak_device_assigned_contributors: summary.participation.weak_device_assigned_contributors,
        accepted_contributors: summary.progress.accepted_contributors,
        weak_device_accepted_contributors: summary.progress.weak_device_accepted_contributors,
        model_progress_contributors: summary.progress.model_progress_contributors,
        admitted_nodes_online: summary.participation.online_nodes,
        active_runs: summary.participation.active_runs,
        active_windows: summary.participation.active_windows,
        pending_validation_windows: summary.participation.pending_validation_windows,
        validator_challenges_open: summary.participation.validator_challenges_open,
        validator_challenges_queued: summary.participation.validator_challenges_queued,
        checkpoint_max_age_ms: summary.progress.checkpoint_max_age_ms,
        artifact_failures_open: summary.progress.artifact_failures_open,
        accepted_closeouts: summary.progress.accepted_closeouts,
        payout_eligible_closeouts: summary.progress.payout_eligible_closeouts,
        nodes_contributing_to_accepted_progress: summary
            .progress
            .nodes_contributing_to_accepted_progress,
        windows_advanced_checkpoint_lineage: summary.progress.windows_advanced_checkpoint_lineage,
        runs_with_accepted_progress: summary.progress.runs_with_accepted_progress,
    }
}

fn training_run_state_preferred_as_default(run_status: &str) -> bool {
    matches!(
        run_status,
        "queued" | "preparing" | "running" | "finalizing"
    )
}

fn training_run_state_counts_as_active(
    run_status: &str,
    active_window_count: u64,
    pending_validation_window_count: u64,
) -> bool {
    training_run_state_preferred_as_default(run_status)
        || active_window_count > 0
        || pending_validation_window_count > 0
}

fn training_default_run<'a>(
    runs: &'a [TrainingOperatorRunSummary],
) -> Option<&'a TrainingOperatorRunSummary> {
    runs.iter()
        .find(|run| training_run_state_preferred_as_default(run.run_status.as_str()))
        .or_else(|| runs.first())
}

