fn push_training_run_caveat(
    caveats: &mut Vec<PublicTrainingRunCaveat>,
    seen: &mut HashSet<String>,
    caveat_id: impl Into<String>,
    severity: impl Into<String>,
    title: impl Into<String>,
    detail: impl Into<String>,
) {
    let caveat_id = caveat_id.into();
    if !seen.insert(caveat_id.clone()) {
        return;
    }
    caveats.push(PublicTrainingRunCaveat {
        caveat_id,
        severity: severity.into(),
        title: title.into(),
        detail: detail.into(),
    });
}

fn training_run_detail_caveats(
    context: &TrainingRunDetailContext,
    featured_window: Option<&PublicTrainingWindowState>,
) -> Vec<PublicTrainingRunCaveat> {
    let mut caveats = Vec::<PublicTrainingRunCaveat>::new();
    let mut seen = HashSet::<String>::new();

    for alert in &context.launch_health.alerts {
        push_training_run_caveat(
            &mut caveats,
            &mut seen,
            alert.alert_id.clone(),
            alert.severity.clone(),
            alert.title.clone(),
            alert.detail.clone(),
        );
    }

    if let Some(reason) = context.treasury.degraded_reason.as_deref() {
        push_training_run_caveat(
            &mut caveats,
            &mut seen,
            "treasury_degraded",
            "critical",
            "Treasury degraded",
            reason.to_string(),
        );
    }

    if let Some(status) = context.treasury.wallet_runtime_status.as_deref() {
        if status != "connected" {
            push_training_run_caveat(
                &mut caveats,
                &mut seen,
                "wallet_runtime",
                "warning",
                "Wallet runtime not fully healthy",
                context
                    .treasury
                    .wallet_last_error
                    .clone()
                    .unwrap_or_else(|| format!("wallet runtime status is {status}")),
            );
        }
    }

    if let Some(window) = featured_window {
        if window.status == "sealed" && window.reconciled_at_ms.is_none() {
            push_training_run_caveat(
                &mut caveats,
                &mut seen,
                "window_validation_pending",
                "warning",
                "Window validation still pending",
                format!(
                    "{} is sealed but not yet reconciled into a final closeout.",
                    window.window_id
                ),
            );
        }
    }

    caveats
}

fn training_run_detail_snapshot(
    store: &ControlStore,
    summary: &TrainingOperatorSummaryResponse,
    visualization: &TrainingVisualizationResponse,
    context: &TrainingRunDetailContext,
    now_unix_ms: u64,
    training_run_id: &str,
) -> Result<PublicTrainingRunDetailSnapshot, String> {
    let training_run_id =
        normalize_required_training_string(training_run_id, "training_run_id_missing")?;
    let summary_run = summary
        .runs
        .iter()
        .find(|run| run.training_run_id == training_run_id)
        .ok_or_else(|| "training_run_not_found".to_string())?;
    let visualization_run = visualization
        .runs
        .iter()
        .find(|run| run.training_run_id == training_run_id)
        .ok_or_else(|| "training_run_not_found".to_string())?;
    let run = training_public_run_state(summary_run, visualization_run);

    let mut windows = visualization
        .windows
        .iter()
        .filter(|window| window.training_run_id == training_run_id)
        .map(training_public_window_state)
        .collect::<Vec<_>>();
    windows.sort_by(|lhs, rhs| {
        training_window_sort_key(rhs)
            .cmp(&training_window_sort_key(lhs))
            .then_with(|| lhs.window_id.cmp(&rhs.window_id))
    });

    let mut admitted_nodes = store.kernel.list_admitted_training_nodes(
        &TrainingNodeQuery {
            network_id: None,
            requested_network_id: None,
            role: None,
            online_only: false,
            eligible_only: false,
        },
        now_unix_ms as i64,
    );
    admitted_nodes.sort_by(|lhs, rhs| {
        lhs.node_label
            .as_deref()
            .unwrap_or(lhs.node_pubkey_hex.as_str())
            .cmp(
                rhs.node_label
                    .as_deref()
                    .unwrap_or(rhs.node_pubkey_hex.as_str()),
            )
            .then_with(|| lhs.node_pubkey_hex.cmp(&rhs.node_pubkey_hex))
    });
    let admitted_nodes_by_id = admitted_nodes
        .iter()
        .map(|node| (node.node_pubkey_hex.as_str(), node))
        .collect::<HashMap<_, _>>();

    let mut contributions = store
        .kernel
        .list_compute_adapter_contribution_outcomes(Some(training_run_id.as_str()), None, None)
        .into_iter()
        .map(|contribution| {
            let node_label = admitted_nodes_by_id
                .get(contribution.contributor_node_id.as_str())
                .and_then(|node| node.node_label.as_deref());
            training_run_detail_contribution_row(&contribution, node_label)
        })
        .collect::<Vec<_>>();
    contributions.sort_by(|lhs, rhs| {
        rhs.recorded_at_ms
            .cmp(&lhs.recorded_at_ms)
            .then_with(|| lhs.contribution_id.cmp(&rhs.contribution_id))
    });

    let requested_featured_window_id = training_run_detail_featured_window_id(&run);
    let featured_window = requested_featured_window_id
        .as_deref()
        .and_then(|window_id| {
            windows
                .iter()
                .find(|window| window.window_id == window_id)
                .cloned()
        })
        .or_else(|| windows.first().cloned());
    let featured_window_id = featured_window
        .as_ref()
        .map(|window| window.window_id.clone())
        .or(requested_featured_window_id);

    let participant_node_ids = contributions
        .iter()
        .map(|contribution| contribution.contributor_node_id.as_str())
        .filter(|value| !value.trim().is_empty())
        .collect::<HashSet<_>>();
    let nodes = admitted_nodes
        .iter()
        .filter(|node| {
            participant_node_ids.contains(node.node_pubkey_hex.as_str())
                || node.last_training_run_id.as_deref() == Some(training_run_id.as_str())
                || node.last_successful_run_id.as_deref() == Some(training_run_id.as_str())
                || featured_window_id.as_deref() == node.last_window_id.as_deref()
                || featured_window_id.as_deref() == node.last_successful_window_id.as_deref()
        })
        .map(training_run_detail_node_row)
        .collect::<Vec<_>>();
    let caveats = training_run_detail_caveats(context, featured_window.as_ref());
    let launch = training_launch_public_state(store, training_run_id.as_str());

    Ok(PublicTrainingRunDetailSnapshot {
        generated_at_unix_ms: now_unix_ms,
        training_run_id,
        run,
        featured_window_id,
        featured_window,
        queue_pressure: context.queue_pressure.clone(),
        launch_health: context.launch_health.clone(),
        treasury: context.treasury.clone(),
        launch,
        windows,
        contributions,
        nodes,
        caveats,
    })
}

fn training_queue_pressure_state(summary: &TrainingOperatorSummaryResponse) -> &'static str {
    if summary.validator_challenges_queued > 0 || summary.pending_validation_windows > 0 {
        "pending_validation"
    } else if summary.validator_challenges_open > 0 {
        "validating"
    } else if summary.active_windows > 0 {
        "executing"
    } else if summary.active_runs > 0 {
        "standing_by"
    } else {
        "none"
    }
}

fn training_queue_pressure_snapshot(
    summary: &TrainingOperatorSummaryResponse,
) -> PublicTrainingQueuePressure {
    PublicTrainingQueuePressure {
        state: training_queue_pressure_state(summary).to_string(),
        active_windows: summary.active_windows,
        pending_validation_windows: summary.pending_validation_windows,
        validator_challenges_open: summary.validator_challenges_open,
        validator_challenges_queued: summary.validator_challenges_queued,
    }
}

#[derive(Debug, Clone)]
struct TrainingRunDetailContext {
    queue_pressure: PublicTrainingQueuePressure,
    launch_health: PublicTrainingLaunchHealthSnapshot,
    treasury: PublicTrainingRunTreasuryStatus,
}

fn training_run_detail_context(
    config: &ServiceConfig,
    store: &ControlStore,
    summary: &TrainingOperatorSummaryResponse,
    launch_metrics: &TrainingLaunchLiveMetricsSnapshot,
    now_unix_ms: u64,
) -> TrainingRunDetailContext {
    let treasury_runtime = store.treasury.public_stats(&config.treasury, now_unix_ms);
    let training_payout_ledger_summary = store
        .treasury
        .status_response(&config.treasury, now_unix_ms)
        .training_payout_ledger_summary;
    let launch_health = build_training_launch_health_snapshot(
        summary,
        &treasury_runtime,
        &training_payout_ledger_summary,
        launch_metrics,
        now_unix_ms,
    );

    TrainingRunDetailContext {
        queue_pressure: training_queue_pressure_snapshot(summary),
        launch_health,
        treasury: PublicTrainingRunTreasuryStatus {
            payout_loop_health: treasury_runtime.payout_loop_health,
            degraded_reason: treasury_runtime.degraded_reason,
            wallet_runtime_status: treasury_runtime.wallet_runtime_status,
            wallet_last_error: treasury_runtime.wallet_last_error,
        },
    }
}

fn training_public_stats_snapshot(
    store: &ControlStore,
    now_unix_ms: u64,
    summary: &TrainingOperatorSummaryResponse,
) -> PublicTrainingStatsSnapshot {
    const PUBLIC_TRAINING_RUN_LIMIT: usize = 8;
    const PUBLIC_TRAINING_WINDOW_LIMIT: usize = 12;

    let visualization =
        training_visualization_snapshot_with_summary(store, now_unix_ms, summary.clone());
    let default_run = training_default_run(summary.runs.as_slice());
    let active_run = summary.runs.iter().find(|run| {
        training_run_state_counts_as_active(
            run.run_status.as_str(),
            run.active_window_count,
            run.pending_validation_window_count,
        )
    });
    let default_run_id = default_run.map(|run| run.training_run_id.clone());
    let default_network_id = default_run.map(|run| run.network_id.clone());
    let active_run_id = active_run
        .map(|run| run.training_run_id.clone())
        .or_else(|| default_run_id.clone());
    let active_window_id = active_run
        .and_then(|run| match run.current_window_id.trim() {
            "" | "unknown" => None,
            value => Some(value.to_string()),
        })
        .or_else(|| default_run.and_then(|run| run.latest_window_id.clone()));
    let summary_runs_by_id = summary
        .runs
        .iter()
        .map(|run| (run.training_run_id.as_str(), run))
        .collect::<HashMap<_, _>>();
    let default_visualized_run = default_run.and_then(|run| {
        visualization
            .runs
            .iter()
            .find(|candidate| candidate.training_run_id == run.training_run_id)
    });

    let mut active_run_counts = BTreeMap::<String, u64>::new();
    for run in &summary.runs {
        if training_run_state_counts_as_active(
            run.run_status.as_str(),
            run.active_window_count,
            run.pending_validation_window_count,
        ) {
            *active_run_counts
                .entry(run.settlement.work_class.clone())
                .or_default() += 1;
        }
    }
    let work_classes = summary
        .settlement
        .work_classes
        .iter()
        .map(|work_class| PublicTrainingWorkClassState {
            work_class: work_class.work_class.clone(),
            progress_class: work_class.progress_class.clone(),
            run_count: work_class.run_count,
            active_run_count: active_run_counts
                .get(work_class.work_class.as_str())
                .copied()
                .unwrap_or(0),
            accepted_closeouts: work_class.accepted_closeouts,
            payout_eligible_closeouts: work_class.payout_eligible_closeouts,
            weak_device_bearing_closeouts: work_class.weak_device_bearing_closeouts,
            progress_bearing_closeouts: work_class.progress_bearing_closeouts,
            participation_only_closeouts: work_class.participation_only_closeouts,
        })
        .collect::<Vec<_>>();

    let mut runs = visualization
        .runs
        .iter()
        .filter(|run| {
            training_run_state_counts_as_active(
                run.run_status.as_str(),
                run.active_window_count,
                run.pending_validation_window_count,
            ) || default_run_id.as_deref() == Some(run.training_run_id.as_str())
        })
        .map(|run| {
            let summary_run = summary_runs_by_id
                .get(run.training_run_id.as_str())
                .copied();
            summary_run.map(|summary_run| training_public_run_state(summary_run, run))
        })
        .flatten()
        .collect::<Vec<_>>();
    runs.sort_by(|lhs, rhs| {
        let lhs_default = default_run_id.as_deref() == Some(lhs.training_run_id.as_str());
        let rhs_default = default_run_id.as_deref() == Some(rhs.training_run_id.as_str());
        let lhs_active = training_run_state_counts_as_active(
            lhs.run_status.as_str(),
            lhs.active_window_count,
            lhs.pending_validation_window_count,
        );
        let rhs_active = training_run_state_counts_as_active(
            rhs.run_status.as_str(),
            rhs.active_window_count,
            rhs.pending_validation_window_count,
        );
        rhs_default
            .cmp(&lhs_default)
            .then_with(|| rhs_active.cmp(&lhs_active))
            .then_with(|| lhs.training_run_id.cmp(&rhs.training_run_id))
    });
    runs.truncate(PUBLIC_TRAINING_RUN_LIMIT);
    let selected_run_ids = runs
        .iter()
        .map(|run| run.training_run_id.clone())
        .collect::<HashSet<_>>();

    let default_window_ids = [
        active_window_id.as_deref(),
        default_run.and_then(|run| run.latest_window_id.as_deref()),
    ]
    .into_iter()
    .flatten()
    .map(str::to_string)
    .collect::<HashSet<_>>();
    let mut windows = visualization
        .windows
        .iter()
        .filter(|window| {
            selected_run_ids.contains(window.training_run_id.as_str())
                && (window.status != "reconciled"
                    || default_window_ids.contains(window.window_id.as_str())
                    || window.closeout_status.is_some())
        })
        .map(training_public_window_state)
        .collect::<Vec<_>>();
    windows.sort_by(|lhs, rhs| {
        training_window_sort_key(rhs)
            .cmp(&training_window_sort_key(lhs))
            .then_with(|| lhs.training_run_id.cmp(&rhs.training_run_id))
            .then_with(|| lhs.window_id.cmp(&rhs.window_id))
    });
    windows.truncate(PUBLIC_TRAINING_WINDOW_LIMIT);

    PublicTrainingStatsSnapshot {
        generated_at_unix_ms: now_unix_ms,
        default_run_id,
        default_network_id,
        active_run_id,
        active_window_id,
        default_work_class: default_run.map(|run| run.settlement.work_class.clone()),
        default_progress_class: default_run.map(|run| run.settlement.progress_class.clone()),
        default_replica_type: default_run.map(|run| run.settlement.replica_type.clone()),
        latest_checkpoint_ref: default_visualized_run
            .and_then(|run| run.latest_checkpoint_ref.clone()),
        latest_checkpoint_age_ms: default_visualized_run
            .and_then(|run| run.latest_checkpoint_age_ms),
        latest_aggregate_ref: default_visualized_run
            .and_then(|run| run.latest_aggregate_ref.clone()),
        latest_promoted_checkpoint_ref: default_visualized_run
            .and_then(|run| run.latest_promoted_checkpoint_ref.clone()),
        latest_window_status: default_visualized_run
            .and_then(|run| run.latest_window_status.clone()),
        latest_closeout_status: default_visualized_run
            .and_then(|run| run.latest_closeout_status.clone()),
        queue_pressure: training_queue_pressure_snapshot(summary),
        launch_health: PublicTrainingLaunchHealthSnapshot::default(),
        work_classes,
        runs,
        windows,
    }
}

fn build_training_launch_health_snapshot(
    summary: &TrainingOperatorSummaryResponse,
    treasury_runtime: &TreasuryPublicStats,
    training_payout_ledger_summary: &TreasuryTrainingPayoutLedgerSummary,
    launch_metrics: &TrainingLaunchLiveMetricsSnapshot,
    now_unix_ms: u64,
) -> PublicTrainingLaunchHealthSnapshot {
    let run_backlog_slots = summary
        .runs
        .iter()
        .filter(|run| {
            training_run_state_counts_as_active(
                run.run_status.as_str(),
                run.active_window_count,
                run.pending_validation_window_count,
            )
        })
        .map(|run| u64::from(run.worker_target_count).saturating_sub(run.assigned_contributors))
        .sum();
    let mut health = PublicTrainingLaunchHealthSnapshot {
        generated_at_unix_ms: now_unix_ms,
        overall_status: "good".to_string(),
        public_snapshot_source: "live".to_string(),
        public_stats_age_ms: 0,
        public_state_drift_from_kernel_ms: 0,
        active_runs: summary.active_runs,
        run_backlog_slots,
        pending_validation_windows: summary.pending_validation_windows,
        validator_challenges_open: summary.validator_challenges_open,
        validator_challenges_queued: summary.validator_challenges_queued,
        accepted_work_pending_payout_count: training_payout_ledger_summary
            .accepted_work_pending_payout_count,
        accepted_work_attention_payout_count: training_payout_ledger_summary
            .accepted_work_attention_payout_count,
        payouts_failed_24h: treasury_runtime.payouts_failed_24h,
        payouts_skipped_24h: treasury_runtime.payouts_skipped_24h,
        resolver_lookup_latency_p95_ms: launch_metrics.resolver_lookup_latency_p95_ms,
        resolver_lookup_sample_count: launch_metrics.resolver_lookup_sample_count,
        signed_access_latency_p95_ms: launch_metrics.signed_access_latency_p95_ms,
        signed_access_sample_count: launch_metrics.signed_access_sample_count,
        active_alert_count: 0,
        critical_alert_count: 0,
        alerts: Vec::new(),
    };
    sync_training_launch_health_alerts(&mut health);
    health
}

fn serialized_label<T: Serialize>(value: &T) -> String {
    serde_json::to_value(value)
        .ok()
        .and_then(|value| value.as_str().map(str::to_string))
        .unwrap_or_else(|| "unknown".to_string())
}

fn training_capability_tier_label(tier: ProviderTrainingCapabilityTier) -> &'static str {
    match tier {
        ProviderTrainingCapabilityTier::Tier0Presence => "tier0_presence",
        ProviderTrainingCapabilityTier::Tier1Validation => "tier1_validation",
        ProviderTrainingCapabilityTier::Tier2Trainer => "tier2_trainer",
        ProviderTrainingCapabilityTier::Tier3Island => "tier3_island",
        ProviderTrainingCapabilityTier::Tier4Authority => "tier4_authority",
    }
}

fn training_capability_tier_from_label(label: &str) -> Option<ProviderTrainingCapabilityTier> {
    match label.trim() {
        "tier0_presence" => Some(ProviderTrainingCapabilityTier::Tier0Presence),
        "tier1_validation" => Some(ProviderTrainingCapabilityTier::Tier1Validation),
        "tier2_trainer" => Some(ProviderTrainingCapabilityTier::Tier2Trainer),
        "tier3_island" => Some(ProviderTrainingCapabilityTier::Tier3Island),
        "tier4_authority" => Some(ProviderTrainingCapabilityTier::Tier4Authority),
        _ => None,
    }
}

fn training_contribution_capability_tier_label(
    contribution: &ComputeAdapterContributionOutcome,
) -> Option<String> {
    contribution
        .metadata
        .get("contributor_capability_tier")
        .and_then(Value::as_str)
        .map(str::to_string)
}

fn training_contributor_tier_projection(
    contributions: &[ComputeAdapterContributionOutcome],
) -> Option<TrainingContributorTierProjection> {
    let mut counts = BTreeMap::<String, u64>::new();
    let mut minimum_tier: Option<ProviderTrainingCapabilityTier> = None;
    let mut maximum_tier: Option<ProviderTrainingCapabilityTier> = None;

    for contribution in contributions
        .iter()
        .filter(|contribution| training_contribution_counts_for_settlement(contribution))
    {
        let Some(tier_label) = training_contribution_capability_tier_label(contribution) else {
            continue;
        };
        *counts.entry(tier_label.clone()).or_default() += 1;
        if let Some(tier) = training_capability_tier_from_label(tier_label.as_str()) {
            minimum_tier = Some(match minimum_tier {
                Some(current) if current.ordinal() <= tier.ordinal() => current,
                _ => tier,
            });
            maximum_tier = Some(match maximum_tier {
                Some(current) if current.ordinal() >= tier.ordinal() => current,
                _ => tier,
            });
        }
    }

    if counts.is_empty() {
        return None;
    }

    let minimum_tier = minimum_tier
        .map(training_capability_tier_label)
        .map(str::to_string)
        .unwrap_or_else(|| counts.keys().next().cloned().unwrap_or_default());
    let maximum_tier = maximum_tier
        .map(training_capability_tier_label)
        .map(str::to_string)
        .unwrap_or_else(|| counts.keys().next_back().cloned().unwrap_or_default());
    let weak_device_bearing = training_capability_tier_from_label(minimum_tier.as_str())
        .is_some_and(|tier| tier.ordinal() < ProviderTrainingCapabilityTier::Tier3Island.ordinal());

    Some(TrainingContributorTierProjection {
        weak_device_bearing,
        minimum_tier,
        maximum_tier,
        tiers: counts
            .into_iter()
            .map(|(tier, participant_count)| TrainingContributorTierCount {
                tier,
                participant_count,
            })
            .collect(),
    })
}

fn training_outcome_contributor_tiers(
    outcome: &ComputeAcceptedOutcome,
) -> Option<TrainingContributorTierProjection> {
    outcome
        .metadata
        .get("contributor_tiers")
        .cloned()
        .and_then(|value| serde_json::from_value::<TrainingContributorTierProjection>(value).ok())
}

fn training_outcome_weak_device_bearing(outcome: &ComputeAcceptedOutcome) -> bool {
    training_outcome_contributor_tiers(outcome)
        .is_some_and(|projection| projection.weak_device_bearing)
}

fn training_visualization_required_tier(
    role: TrainingNodeRoleClaim,
    work_class: ComputeTrainingWorkClass,
    replica_type: ComputeTrainingReplicaType,
) -> ProviderTrainingCapabilityTier {
    let work_class_tier = training_scheduler_minimum_tier_for_work_class(role, work_class);
    let replica_tier = training_scheduler_minimum_tier_for_replica_type(role, replica_type);
    if work_class_tier.ordinal() >= replica_tier.ordinal() {
        work_class_tier
    } else {
        replica_tier
    }
}

fn training_visualization_increment_validator_status(
    summary: &mut TrainingVisualizationValidatorSummary,
    status: ServiceValidatorChallengeStatus,
) {
    match status {
        ServiceValidatorChallengeStatus::Queued => {
            summary.open = summary.open.saturating_add(1);
            summary.queued = summary.queued.saturating_add(1);
        }
        ServiceValidatorChallengeStatus::Leased => {
            summary.open = summary.open.saturating_add(1);
            summary.leased = summary.leased.saturating_add(1);
        }
        ServiceValidatorChallengeStatus::Retrying => {
            summary.open = summary.open.saturating_add(1);
            summary.retrying = summary.retrying.saturating_add(1);
        }
        ServiceValidatorChallengeStatus::Verified => {
            summary.verified = summary.verified.saturating_add(1);
        }
        ServiceValidatorChallengeStatus::Rejected => {
            summary.rejected = summary.rejected.saturating_add(1);
        }
        ServiceValidatorChallengeStatus::TimedOut => {
            summary.timed_out = summary.timed_out.saturating_add(1);
        }
    }
}

fn training_visualization_increment_window_validator_status(
    summary: &mut TrainingVisualizationValidatorWindowSummary,
    status: ServiceValidatorChallengeStatus,
) {
    match status {
        ServiceValidatorChallengeStatus::Queued => {
            summary.open = summary.open.saturating_add(1);
            summary.queued = summary.queued.saturating_add(1);
        }
        ServiceValidatorChallengeStatus::Leased => {
            summary.open = summary.open.saturating_add(1);
            summary.leased = summary.leased.saturating_add(1);
        }
        ServiceValidatorChallengeStatus::Retrying => {
            summary.open = summary.open.saturating_add(1);
            summary.retrying = summary.retrying.saturating_add(1);
        }
        ServiceValidatorChallengeStatus::Verified => {
            summary.verified = summary.verified.saturating_add(1);
        }
        ServiceValidatorChallengeStatus::Rejected => {
            summary.rejected = summary.rejected.saturating_add(1);
        }
        ServiceValidatorChallengeStatus::TimedOut => {
            summary.timed_out = summary.timed_out.saturating_add(1);
        }
    }
}

fn training_visualization_challenge_window_binding<'a>(
    challenge_id: &str,
    windows: &'a [ComputeAdapterTrainingWindow],
) -> Option<(&'a str, &'a str)> {
    windows.iter().find_map(|window| {
        let prefix = format!(
            "challenge.training.{}.{}.",
            window.training_run_id, window.window_id
        );
        challenge_id
            .starts_with(prefix.as_str())
            .then_some((window.training_run_id.as_str(), window.window_id.as_str()))
    })
}

fn training_visualization_snapshot(
    store: &ControlStore,
    now_unix_ms: u64,
) -> TrainingVisualizationResponse {
    let summary = training_operator_summary_snapshot(store, now_unix_ms);
    training_visualization_snapshot_with_summary(store, now_unix_ms, summary)
}

fn training_visualization_snapshot_with_summary(
    store: &ControlStore,
    now_unix_ms: u64,
    summary: TrainingOperatorSummaryResponse,
) -> TrainingVisualizationResponse {
    struct TierAccumulator {
        nodes_total: u64,
        nodes_online: u64,
        nodes_eligible: u64,
        roles: BTreeSet<String>,
        networks: BTreeSet<String>,
        backend_families: BTreeSet<String>,
        throughput_bands: BTreeSet<String>,
        replay_capabilities: BTreeSet<String>,
        artifact_upload_latency_classes: BTreeSet<String>,
    }

    let admitted_nodes = store.kernel.list_admitted_training_nodes(
        &TrainingNodeQuery {
            network_id: None,
            requested_network_id: None,
            role: None,
            online_only: false,
            eligible_only: false,
        },
        now_unix_ms as i64,
    );
    let mut training_runs = store.kernel.list_compute_training_runs(None, None, None);
    let mut training_windows = store
        .kernel
        .list_compute_adapter_training_windows(None, None);
    let mut accepted_outcomes = store
        .kernel
        .list_compute_accepted_outcomes(Some(ComputeAcceptedOutcomeKind::TrainingRun), None);
    let validator_challenges = store.kernel.list_validator_challenges(None);

    training_runs.sort_by(|lhs, rhs| lhs.training_run_id.cmp(&rhs.training_run_id));
    training_windows.sort_by(|lhs, rhs| {
        lhs.training_run_id
            .cmp(&rhs.training_run_id)
            .then_with(|| lhs.round_index.cmp(&rhs.round_index))
            .then_with(|| lhs.window_id.cmp(&rhs.window_id))
    });
    accepted_outcomes.sort_by(|lhs, rhs| {
        rhs.accepted_at_ms
            .cmp(&lhs.accepted_at_ms)
            .then_with(|| lhs.outcome_id.cmp(&rhs.outcome_id))
    });

    let run_summaries_by_id = summary
        .runs
        .iter()
        .cloned()
        .map(|run| (run.training_run_id.clone(), run))
        .collect::<HashMap<_, _>>();
    let accepted_outcomes_by_id = accepted_outcomes
        .iter()
        .map(|outcome| (outcome.outcome_id.as_str(), outcome))
        .collect::<HashMap<_, _>>();
    let runs_by_id = training_runs
        .iter()
        .map(|run| (run.training_run_id.as_str(), run))
        .collect::<HashMap<_, _>>();

    let mut window_metadata_by_id = HashMap::new();
    let mut outcomes_by_window_id: HashMap<String, Vec<&ComputeAcceptedOutcome>> = HashMap::new();
    let mut windows_by_run_id: HashMap<String, Vec<&ComputeAdapterTrainingWindow>> = HashMap::new();
    for window in &training_windows {
        if let Ok(metadata) = training_window_metadata_from_value(&window.metadata) {
            window_metadata_by_id.insert(window.window_id.clone(), metadata);
        }
        windows_by_run_id
            .entry(window.training_run_id.clone())
            .or_default()
            .push(window);
    }
    for outcome in &accepted_outcomes {
        if let Some(window_id) = outcome.metadata.get("window_id").and_then(Value::as_str) {
            outcomes_by_window_id
                .entry(window_id.to_string())
                .or_default()
                .push(outcome);
        }
    }

    let mut tier_accumulators: BTreeMap<String, TierAccumulator> = BTreeMap::new();
    for node in &admitted_nodes {
        let tier_label = training_capability_tier_label(node.capability_tier.tier).to_string();
        let entry = tier_accumulators
            .entry(tier_label)
            .or_insert_with(|| TierAccumulator {
                nodes_total: 0,
                nodes_online: 0,
                nodes_eligible: 0,
                roles: BTreeSet::new(),
                networks: BTreeSet::new(),
                backend_families: BTreeSet::new(),
                throughput_bands: BTreeSet::new(),
                replay_capabilities: BTreeSet::new(),
                artifact_upload_latency_classes: BTreeSet::new(),
            });
        entry.nodes_total = entry.nodes_total.saturating_add(1);
        if node.online {
            entry.nodes_online = entry.nodes_online.saturating_add(1);
        }
        if node.eligible {
            entry.nodes_eligible = entry.nodes_eligible.saturating_add(1);
        }
        entry
            .roles
            .extend(node.role_claims.iter().map(|role| role.label().to_string()));
        entry.networks.extend(
            node.allowed_networks
                .iter()
                .filter(|network_id| !network_id.trim().is_empty())
                .cloned(),
        );
        entry.backend_families.extend(
            node.capability_tier
                .backend_families
                .iter()
                .filter(|backend| !backend.trim().is_empty())
                .cloned(),
        );
        entry
            .throughput_bands
            .insert(serialized_label(&node.capability_tier.throughput_band));
        entry
            .replay_capabilities
            .insert(serialized_label(&node.capability_tier.replay_capability));
        entry
            .artifact_upload_latency_classes
            .insert(serialized_label(
                &node.capability_tier.artifact_upload_latency_class,
            ));
    }
    let tiers = tier_accumulators
        .into_iter()
        .map(|(tier, accumulator)| TrainingVisualizationTierSummary {
            tier,
            nodes_total: accumulator.nodes_total,
            nodes_online: accumulator.nodes_online,
            nodes_eligible: accumulator.nodes_eligible,
            roles: accumulator.roles.into_iter().collect(),
            networks: accumulator.networks.into_iter().collect(),
            backend_families: accumulator.backend_families.into_iter().collect(),
            throughput_bands: accumulator.throughput_bands.into_iter().collect(),
            replay_capabilities: accumulator.replay_capabilities.into_iter().collect(),
            artifact_upload_latency_classes: accumulator
                .artifact_upload_latency_classes
                .into_iter()
                .collect(),
        })
        .collect::<Vec<_>>();

    let mut validators = TrainingVisualizationValidatorSummary::default();
    let mut validator_windows: BTreeMap<
        (String, String),
        TrainingVisualizationValidatorWindowSummary,
    > = BTreeMap::new();
    for challenge in &validator_challenges {
        training_visualization_increment_validator_status(&mut validators, challenge.status);
        if let Some((training_run_id, window_id)) = training_visualization_challenge_window_binding(
            challenge.request.context.challenge_id.as_str(),
            training_windows.as_slice(),
        ) {
            let entry = validator_windows
                .entry((training_run_id.to_string(), window_id.to_string()))
                .or_insert_with(|| TrainingVisualizationValidatorWindowSummary {
                    training_run_id: training_run_id.to_string(),
                    window_id: window_id.to_string(),
                    validator_pool_ref: window_metadata_by_id.get(window_id).and_then(|metadata| {
                        metadata
                            .validation
                            .as_ref()
                            .map(|validation| validation.validator_pool_ref.clone())
                    }),
                    ..TrainingVisualizationValidatorWindowSummary::default()
                });
            if !entry
                .challenge_ids
                .iter()
                .any(|existing| existing == &challenge.request.context.challenge_id)
            {
                entry
                    .challenge_ids
                    .push(challenge.request.context.challenge_id.clone());
            }
            training_visualization_increment_window_validator_status(entry, challenge.status);
        }
    }
    validators.windows = validator_windows.into_values().collect();

    let mut closeouts = accepted_outcomes
        .iter()
        .map(|outcome| {
            let run = runs_by_id.get(outcome.source_run_id.as_str()).copied();
            let run_summary = run_summaries_by_id.get(outcome.source_run_id.as_str());
            let work_class = training_outcome_work_class(outcome)
                .or_else(|| run.map(|run| run.work_class))
                .unwrap_or(ComputeTrainingWorkClass::AdapterTraining);
            let progress_class = training_work_progress_class(work_class);
            let replica_type = outcome
                .metadata
                .get("replica_type")
                .and_then(Value::as_str)
                .map(str::to_string)
                .or_else(|| run.map(|run| run.replica_type.label().to_string()))
                .unwrap_or_else(|| ComputeTrainingReplicaType::SingleNode.label().to_string());
            let payout_projection = outcome
                .metadata
                .get("payout_projection")
                .cloned()
                .and_then(|value| serde_json::from_value::<TrainingPayoutProjection>(value).ok());
            let contributor_tiers = training_outcome_contributor_tiers(outcome);
            TrainingVisualizationCloseout {
                outcome_id: outcome.outcome_id.clone(),
                training_run_id: outcome.source_run_id.clone(),
                network_id: outcome
                    .metadata
                    .get("network_id")
                    .and_then(Value::as_str)
                    .map(str::to_string)
                    .or_else(|| run_summary.map(|summary| summary.network_id.clone())),
                window_id: outcome
                    .metadata
                    .get("window_id")
                    .and_then(Value::as_str)
                    .map(str::to_string),
                work_class: work_class.label().to_string(),
                replica_type,
                progress_class: progress_class.label().to_string(),
                closeout_status: training_closeout_status_label(outcome)
                    .unwrap_or("accepted")
                    .to_string(),
                payout_eligible: training_outcome_payout_eligible(outcome),
                payout_basis: payout_projection
                    .as_ref()
                    .map(|projection| projection.basis.clone())
                    .or_else(|| training_outcome_latest_payout_basis(outcome)),
                payout_projection,
                contributor_tiers: contributor_tiers.clone(),
                accepted_checkpoint_ref: outcome
                    .training_summary
                    .as_ref()
                    .and_then(|summary| summary.accepted_checkpoint_ref.clone())
                    .or_else(|| {
                        outcome
                            .metadata
                            .get("promoted_checkpoint_ref")
                            .and_then(Value::as_str)
                            .map(str::to_string)
                    }),
                weak_device_bearing: contributor_tiers
                    .as_ref()
                    .is_some_and(|projection| projection.weak_device_bearing),
                accepted_at_ms: outcome.accepted_at_ms,
            }
        })
        .collect::<Vec<_>>();
    closeouts.sort_by(|lhs, rhs| {
        rhs.accepted_at_ms
            .cmp(&lhs.accepted_at_ms)
            .then_with(|| lhs.outcome_id.cmp(&rhs.outcome_id))
    });

    let mut aggregates = training_windows
        .iter()
        .filter(|window| {
            window.accepted_aggregate_id.is_some() || window.aggregated_delta_digest.is_some()
        })
        .map(|window| {
            let latest_closeout = outcomes_by_window_id
                .get(window.window_id.as_str())
                .and_then(|outcomes| {
                    outcomes.iter().copied().max_by(|lhs, rhs| {
                        lhs.accepted_at_ms
                            .cmp(&rhs.accepted_at_ms)
                            .then_with(|| lhs.outcome_id.cmp(&rhs.outcome_id))
                    })
                });
            let contributor_tiers =
                latest_closeout.and_then(|outcome| training_outcome_contributor_tiers(outcome));
            TrainingVisualizationAggregate {
                aggregate_ref: window
                    .accepted_aggregate_id
                    .clone()
                    .or_else(|| window.aggregated_delta_digest.clone())
                    .unwrap_or_else(|| format!("window::{}", window.window_id)),
                training_run_id: window.training_run_id.clone(),
                window_id: window.window_id.clone(),
                work_class: window.work_class.label().to_string(),
                replica_type: window.replica_type.label().to_string(),
                progress_class: training_work_progress_class(window.work_class)
                    .label()
                    .to_string(),
                aggregation_rule: window.aggregation_rule.clone(),
                aggregation_weight_basis: window.aggregation_weight_basis.clone(),
                aggregated_delta_digest: window.aggregated_delta_digest.clone(),
                accepted_aggregate_id: window.accepted_aggregate_id.clone(),
                contribution_count: window.total_contributions,
                accepted_contributions: window.accepted_contributions,
                window_status: window.status.label().to_string(),
                closeout_status: latest_closeout
                    .and_then(training_closeout_status_label)
                    .map(str::to_string),
                payout_eligible: latest_closeout.is_some_and(training_outcome_payout_eligible),
                weak_device_bearing: contributor_tiers
                    .as_ref()
                    .is_some_and(|projection| projection.weak_device_bearing),
                promoted_checkpoint_ref: window.promoted_checkpoint_ref.clone(),
                accepted_outcome_id: window
                    .accepted_outcome_id
                    .clone()
                    .or_else(|| latest_closeout.map(|outcome| outcome.outcome_id.clone())),
                recorded_at_ms: window.recorded_at_ms,
            }
        })
        .collect::<Vec<_>>();
    aggregates.sort_by(|lhs, rhs| {
        rhs.recorded_at_ms
            .cmp(&lhs.recorded_at_ms)
            .then_with(|| lhs.aggregate_ref.cmp(&rhs.aggregate_ref))
    });

    let mut checkpoints = Vec::new();
    let mut checkpoint_keys = BTreeSet::new();
    let mut push_checkpoint = |checkpoint_ref: String,
                               checkpoint_role: &str,
                               training_run_id: &str,
                               window_id: Option<&str>,
                               outcome_id: Option<&str>,
                               canonical: bool,
                               recorded_at_ms: i64| {
        let key = (
            checkpoint_ref.clone(),
            checkpoint_role.to_string(),
            training_run_id.to_string(),
            window_id.map(str::to_string),
            outcome_id.map(str::to_string),
        );
        if checkpoint_keys.insert(key) {
            checkpoints.push(TrainingVisualizationCheckpoint {
                checkpoint_ref,
                checkpoint_role: checkpoint_role.to_string(),
                training_run_id: training_run_id.to_string(),
                window_id: window_id.map(str::to_string),
                outcome_id: outcome_id.map(str::to_string),
                canonical,
                recorded_at_ms,
            });
        }
    };

    for window in &training_windows {
        push_checkpoint(
            window.base_checkpoint_ref.clone(),
            "base",
            window.training_run_id.as_str(),
            Some(window.window_id.as_str()),
            None,
            false,
            window.recorded_at_ms,
        );
        if let Some(pointer) = window.output_checkpoint_pointer.as_ref() {
            push_checkpoint(
                pointer.checkpoint_ref.clone(),
                "output_pointer",
                window.training_run_id.as_str(),
                Some(window.window_id.as_str()),
                None,
                false,
                pointer.updated_at_ms,
            );
        }
        if let Some(checkpoint_ref) = window.promoted_checkpoint_ref.as_ref() {
            push_checkpoint(
                checkpoint_ref.clone(),
                "promoted",
                window.training_run_id.as_str(),
                Some(window.window_id.as_str()),
                window.accepted_outcome_id.as_deref(),
                true,
                window.recorded_at_ms,
            );
        }
    }
    for closeout in &closeouts {
        if let Some(checkpoint_ref) = closeout.accepted_checkpoint_ref.as_ref() {
            push_checkpoint(
                checkpoint_ref.clone(),
                "accepted_closeout",
                closeout.training_run_id.as_str(),
                closeout.window_id.as_deref(),
                Some(closeout.outcome_id.as_str()),
                closeout.payout_eligible,
                closeout.accepted_at_ms,
            );
        }
    }
    for run_summary in &summary.runs {
        if let Some(checkpoint_ref) = run_summary.latest_checkpoint_ref.as_ref() {
            push_checkpoint(
                checkpoint_ref.clone(),
                "run_latest",
                run_summary.training_run_id.as_str(),
                run_summary.latest_window_id.as_deref(),
                None,
                true,
                i64::try_from(
                    now_unix_ms.saturating_sub(run_summary.latest_checkpoint_age_ms.unwrap_or(0)),
                )
                .unwrap_or(i64::MAX),
            );
        }
    }
    checkpoints.sort_by(|lhs, rhs| {
        rhs.recorded_at_ms
            .cmp(&lhs.recorded_at_ms)
            .then_with(|| lhs.training_run_id.cmp(&rhs.training_run_id))
            .then_with(|| lhs.checkpoint_role.cmp(&rhs.checkpoint_role))
    });

    let runs = training_runs
        .iter()
        .map(|run| {
            let run_summary = run_summaries_by_id.get(run.training_run_id.as_str());
            let run_windows = windows_by_run_id
                .get(run.training_run_id.as_str())
                .cloned()
                .unwrap_or_default();
            let latest_window = run_windows.iter().copied().max_by(|lhs, rhs| {
                lhs.recorded_at_ms
                    .cmp(&rhs.recorded_at_ms)
                    .then_with(|| lhs.window_id.cmp(&rhs.window_id))
            });
            let latest_aggregate_ref = latest_window.and_then(|window| {
                window
                    .accepted_aggregate_id
                    .clone()
                    .or_else(|| window.aggregated_delta_digest.clone())
            });
            let latest_promoted_checkpoint_ref = latest_window.and_then(|window| {
                window.promoted_checkpoint_ref.clone().or_else(|| {
                    window
                        .output_checkpoint_pointer
                        .as_ref()
                        .map(|pointer| pointer.checkpoint_ref.clone())
                })
            });
            let window_ids = run_windows
                .iter()
                .map(|window| window.window_id.clone())
                .collect::<Vec<_>>();
            let required_worker_tier =
                training_capability_tier_label(training_visualization_required_tier(
                    TrainingNodeRoleClaim::Worker,
                    run.work_class,
                    run.replica_type,
                ))
                .to_string();
            let required_validator_tier =
                training_capability_tier_label(training_visualization_required_tier(
                    TrainingNodeRoleClaim::Validator,
                    run.work_class,
                    run.replica_type,
                ))
                .to_string();
            let required_recovery_source_tier =
                training_capability_tier_label(training_visualization_required_tier(
                    TrainingNodeRoleClaim::RecoverySource,
                    run.work_class,
                    run.replica_type,
                ))
                .to_string();
            TrainingVisualizationRun {
                training_run_id: run.training_run_id.clone(),
                display_name: training_run_display_name(run),
                network_id: run_summary
                    .map(|summary| summary.network_id.clone())
                    .or_else(|| {
                        run.metadata
                            .get("network_id")
                            .and_then(Value::as_str)
                            .map(str::to_string)
                    })
                    .unwrap_or_default(),
                run_status: run.status.label().to_string(),
                scheduler_window_state: run_summary
                    .map(|summary| summary.scheduler_window_state.clone())
                    .unwrap_or_else(|| "unknown".to_string()),
                current_window_id: run_summary
                    .map(|summary| summary.current_window_id.clone())
                    .or_else(|| latest_window.map(|window| window.window_id.clone()))
                    .unwrap_or_else(|| "unknown".to_string()),
                work_class: run.work_class.label().to_string(),
                replica_type: run.replica_type.label().to_string(),
                progress_class: training_work_progress_class(run.work_class)
                    .label()
                    .to_string(),
                required_worker_tier,
                required_validator_tier,
                required_recovery_source_tier,
                window_ids,
                admitted_nodes: run_summary.map_or(0, |summary| summary.admitted_nodes),
                assigned_contributors: run_summary
                    .map_or(0, |summary| summary.assigned_contributors),
                weak_device_assigned_contributors: run_summary
                    .map_or(0, |summary| summary.weak_device_assigned_contributors),
                accepted_contributors: run_summary
                    .map_or(0, |summary| summary.accepted_contributors),
                weak_device_accepted_contributors: run_summary
                    .map_or(0, |summary| summary.weak_device_accepted_contributors),
                model_progress_contributors: run_summary
                    .map_or(0, |summary| summary.model_progress_contributors),
                admitted_nodes_online: run_summary
                    .map_or(0, |summary| summary.admitted_nodes_online),
                worker_nodes_online: run_summary.map_or(0, |summary| summary.worker_nodes_online),
                validator_nodes_online: run_summary
                    .map_or(0, |summary| summary.validator_nodes_online),
                recovery_source_nodes_online: run_summary
                    .map_or(0, |summary| summary.recovery_source_nodes_online),
                active_window_count: run_summary.map_or(0, |summary| summary.active_window_count),
                pending_validation_window_count: run_summary
                    .map_or(0, |summary| summary.pending_validation_window_count),
                accepted_closeouts: run_summary.map_or(0, |summary| summary.accepted_closeouts),
                payout_eligible_closeouts: run_summary
                    .map_or(0, |summary| summary.payout_eligible_closeouts),
                weak_device_bearing_closeouts: run_summary.map_or(0, |summary| {
                    summary.settlement.weak_device_bearing_closeouts
                }),
                nodes_contributing_to_accepted_progress: run_summary
                    .map_or(0, |summary| summary.nodes_contributing_to_accepted_progress),
                windows_advanced_checkpoint_lineage: run_summary
                    .map_or(0, |summary| summary.windows_advanced_checkpoint_lineage),
                latest_checkpoint_ref: run_summary
                    .and_then(|summary| summary.latest_checkpoint_ref.clone()),
                latest_checkpoint_age_ms: run_summary
                    .and_then(|summary| summary.latest_checkpoint_age_ms),
                latest_window_status: run_summary
                    .and_then(|summary| summary.latest_window_status.clone()),
                latest_closeout_status: run_summary
                    .and_then(|summary| summary.latest_closeout_status.clone()),
                latest_aggregate_ref,
                latest_promoted_checkpoint_ref,
            }
        })
        .collect::<Vec<_>>();

    let mut windows = training_windows
        .iter()
        .map(|window| {
            let metadata = window_metadata_by_id.get(window.window_id.as_str());
            let latest_closeout = outcomes_by_window_id
                .get(window.window_id.as_str())
                .and_then(|outcomes| {
                    outcomes.iter().copied().max_by(|lhs, rhs| {
                        lhs.accepted_at_ms
                            .cmp(&rhs.accepted_at_ms)
                            .then_with(|| lhs.outcome_id.cmp(&rhs.outcome_id))
                    })
                });
            let contributor_tiers =
                latest_closeout.and_then(|outcome| training_outcome_contributor_tiers(outcome));
            let validator_summary = validators
                .windows
                .iter()
                .find(|summary| {
                    summary.training_run_id == window.training_run_id
                        && summary.window_id == window.window_id
                })
                .cloned();
            let aggregate_resolution = metadata.and_then(|metadata| {
                metadata
                    .defensibility
                    .as_ref()
                    .and_then(|value| value.get("validator_audit"))
                    .and_then(|value| value.get("aggregate_resolution"))
                    .and_then(Value::as_str)
                    .map(str::to_string)
            });
            let defensibility_status = metadata.and_then(|metadata| {
                metadata
                    .defensibility
                    .as_ref()
                    .and_then(|value| value.get("status"))
                    .and_then(Value::as_str)
                    .map(str::to_string)
            });
            TrainingVisualizationWindow {
                window_id: window.window_id.clone(),
                training_run_id: window.training_run_id.clone(),
                network_id: metadata
                    .map(|metadata| metadata.network_id.clone())
                    .or_else(|| {
                        run_summaries_by_id
                            .get(window.training_run_id.as_str())
                            .map(|summary| summary.network_id.clone())
                    })
                    .unwrap_or_default(),
                status: window.status.label().to_string(),
                stage_id: window.stage_id.clone(),
                work_class: window.work_class.label().to_string(),
                replica_type: window.replica_type.label().to_string(),
                progress_class: training_work_progress_class(window.work_class)
                    .label()
                    .to_string(),
                round_index: window.round_index,
                base_checkpoint_ref: window.base_checkpoint_ref.clone(),
                planned_local_step_count: window.planned_local_step_count,
                aggregation_rule: window.aggregation_rule.clone(),
                aggregation_weight_basis: window.aggregation_weight_basis.clone(),
                total_contributions: window.total_contributions,
                admitted_contributions: window.admitted_contributions,
                accepted_contributions: window.accepted_contributions,
                quarantined_contributions: window.quarantined_contributions,
                rejected_contributions: window.rejected_contributions,
                replay_required_contributions: window.replay_required_contributions,
                replay_checked_contributions: window.replay_checked_contributions,
                held_out_average_score_bps: window.held_out_average_score_bps,
                benchmark_pass_rate_bps: window.benchmark_pass_rate_bps,
                runtime_smoke_passed: window.runtime_smoke_passed,
                promotion_ready: window.promotion_ready,
                promotion_disposition: window
                    .promotion_disposition
                    .map(|disposition| serialized_label(&disposition)),
                gate_reason_codes: window
                    .gate_reason_codes
                    .iter()
                    .map(|reason| serialized_label(reason))
                    .collect(),
                hold_reason_codes: window
                    .hold_reason_codes
                    .iter()
                    .map(|reason| serialized_label(reason))
                    .collect(),
                validator_pool_ref: validator_summary
                    .as_ref()
                    .and_then(|summary| summary.validator_pool_ref.clone())
                    .or_else(|| {
                        metadata.and_then(|metadata| {
                            metadata
                                .validation
                                .as_ref()
                                .map(|validation| validation.validator_pool_ref.clone())
                        })
                    }),
                validator_challenge_ids: validator_summary
                    .as_ref()
                    .map(|summary| summary.challenge_ids.clone())
                    .or_else(|| {
                        metadata.map(|metadata| {
                            metadata
                                .validation
                                .as_ref()
                                .map(|validation| {
                                    validation
                                        .challenges
                                        .iter()
                                        .map(|challenge| challenge.challenge_id.clone())
                                        .collect::<Vec<_>>()
                                })
                                .unwrap_or_default()
                        })
                    })
                    .unwrap_or_default(),
                validator_challenges_open: validator_summary
                    .as_ref()
                    .map_or(0, |summary| summary.open),
                validator_challenges_queued: validator_summary
                    .as_ref()
                    .map_or(0, |summary| summary.queued),
                validator_challenges_verified: validator_summary
                    .as_ref()
                    .map_or(0, |summary| summary.verified),
                validator_challenges_rejected: validator_summary
                    .as_ref()
                    .map_or(0, |summary| summary.rejected),
                validator_challenges_timed_out: validator_summary
                    .as_ref()
                    .map_or(0, |summary| summary.timed_out),
                aggregate_resolution,
                defensibility_status,
                aggregated_delta_digest: window.aggregated_delta_digest.clone(),
                accepted_aggregate_id: window.accepted_aggregate_id.clone(),
                output_checkpoint_ref: window
                    .output_checkpoint_pointer
                    .as_ref()
                    .map(|pointer| pointer.checkpoint_ref.clone()),
                promoted_checkpoint_ref: window.promoted_checkpoint_ref.clone(),
                accepted_outcome_id: window
                    .accepted_outcome_id
                    .clone()
                    .or_else(|| latest_closeout.map(|outcome| outcome.outcome_id.clone())),
                closeout_status: latest_closeout
                    .and_then(training_closeout_status_label)
                    .map(str::to_string),
                payout_eligible: latest_closeout.is_some_and(training_outcome_payout_eligible),
                weak_device_bearing: contributor_tiers
                    .as_ref()
                    .is_some_and(|projection| projection.weak_device_bearing),
                contributor_tiers,
                lineage_advanced: training_window_advances_checkpoint_lineage(
                    window,
                    &accepted_outcomes_by_id,
                ),
                planned_at_ms: metadata
                    .map_or(window.recorded_at_ms, |metadata| metadata.planned_at_ms),
                activated_at_ms: metadata.and_then(|metadata| metadata.activated_at_ms),
                sealed_at_ms: metadata.and_then(|metadata| metadata.sealed_at_ms),
                reconciled_at_ms: metadata.and_then(|metadata| metadata.reconciled_at_ms),
            }
        })
        .collect::<Vec<_>>();
    windows.sort_by(|lhs, rhs| {
        lhs.training_run_id
            .cmp(&rhs.training_run_id)
            .then_with(|| lhs.round_index.cmp(&rhs.round_index))
            .then_with(|| lhs.window_id.cmp(&rhs.window_id))
    });

    TrainingVisualizationResponse {
        generated_at_unix_ms: now_unix_ms,
        participation: summary.participation.clone(),
        progress: summary.progress.clone(),
        settlement: summary.settlement.clone(),
        tiers,
        runs,
        windows,
        validators,
        aggregates,
        checkpoints,
        closeouts,
    }
}

fn build_homepage_snapshot(
    config: &ServiceConfig,
    store: &ControlStore,
    launch_metrics: &TrainingLaunchLiveMetricsSnapshot,
    now_unix_ms: u64,
) -> NexusHomepageResponse {
    let stats = build_public_stats_snapshot(config, store, launch_metrics, now_unix_ms);
    let training_summary = training_operator_summary_snapshot(store, now_unix_ms);
    let training_visualization =
        training_visualization_snapshot_with_summary(store, now_unix_ms, training_summary.clone());
    let training_nodes = training_authority_refresh_node_views(
        &store.kernel,
        store.kernel.list_admitted_training_nodes(
            &TrainingNodeQuery {
                network_id: None,
                requested_network_id: None,
                role: None,
                online_only: false,
                eligible_only: false,
            },
            now_unix_ms as i64,
        ),
        now_unix_ms as i64,
    )
    .unwrap_or_else(|reason| {
        tracing::warn!(
            reason = reason.as_str(),
            "failed to refresh homepage training node reputation"
        );
        store.kernel.list_admitted_training_nodes(
            &TrainingNodeQuery {
                network_id: None,
                requested_network_id: None,
                role: None,
                online_only: false,
                eligible_only: false,
            },
            now_unix_ms as i64,
        )
    });

    let default_run = training_default_run(training_summary.runs.as_slice());
    let default_run_id = default_run.map(|run| run.training_run_id.clone());
    let default_network_id = default_run.map(|run| run.network_id.clone()).or_else(|| {
        training_nodes
            .iter()
            .flat_map(|node| node.allowed_networks.iter())
            .find(|network_id| !network_id.trim().is_empty())
            .cloned()
    });

    NexusHomepageResponse {
        generated_at_unix_ms: now_unix_ms,
        stats,
        training_summary,
        training_visualization,
        training_nodes,
        default_run_id,
        default_network_id,
        recent_trn_publications: recent_homepage_training_publications(store),
    }
}

fn recent_homepage_training_publications(
    store: &ControlStore,
) -> Vec<NexusHomepageRecentTrainingPublication> {
    let mut records = store.kernel.list_training_trn_publication_records();
    records.sort_by(|lhs, rhs| {
        rhs.published_at_ms
            .unwrap_or(rhs.last_attempt_at_ms)
            .cmp(&lhs.published_at_ms.unwrap_or(lhs.last_attempt_at_ms))
            .then_with(|| rhs.last_attempt_at_ms.cmp(&lhs.last_attempt_at_ms))
            .then_with(|| lhs.publication_key.cmp(&rhs.publication_key))
    });
    records
        .into_iter()
        .take(12)
        .map(homepage_training_publication_from_record)
        .collect()
}

fn homepage_training_publication_from_record(
    record: TrainingTrnPublicationRecord,
) -> NexusHomepageRecentTrainingPublication {
    let publication_state = if record.pending_retry {
        "queued_retry".to_string()
    } else if record.published_at_ms.is_some() || record.event_id.is_some() {
        "published".to_string()
    } else if record.attempt_count > 0 {
        "attempted".to_string()
    } else {
        "pending".to_string()
    };
    NexusHomepageRecentTrainingPublication {
        publication_key: record.publication_key,
        subject_kind: record.subject_kind,
        subject_id: record.subject_id,
        event_kind: record.event_kind,
        publication_state,
        event_id: record.event_id,
        published_at_ms: record.published_at_ms,
        last_attempt_at_ms: record.last_attempt_at_ms,
        attempt_count: record.attempt_count,
        pending_retry: record.pending_retry,
        last_error: record.last_error,
    }
}

fn replace_public_stats_cache(state: &AppState, snapshot: PublicStatsSnapshot) {
    if let Ok(mut cache) = state.public_stats_cache.write() {
        *cache = snapshot;
    }
}

fn replace_training_run_detail_cache(state: &AppState, snapshot: PublicTrainingRunDetailSnapshot) {
    if snapshot.training_run_id.is_empty() {
        return;
    }
    if let Ok(mut cache) = state.training_run_detail_cache.write() {
        cache.insert(snapshot.training_run_id.clone(), snapshot);
    }
}

fn cached_training_run_detail_snapshot(
    state: &AppState,
    training_run_id: &str,
    now_unix_ms: u64,
) -> Option<PublicTrainingRunDetailSnapshot> {
    let snapshot = state
        .training_run_detail_cache
        .read()
        .ok()?
        .get(training_run_id)
        .cloned()?;
    if now_unix_ms.saturating_sub(snapshot.generated_at_unix_ms)
        > TRAINING_RUN_DETAIL_CACHE_MAX_AGE_MS
    {
        return None;
    }
    Some(snapshot)
}

fn record_training_launch_latency_sample(
    state: &AppState,
    kind: TrainingLaunchLatencyMetricKind,
    latency_ms: u64,
) {
    let Ok(mut metrics) = state.training_launch_metrics.write() else {
        return;
    };
    let samples = match kind {
        TrainingLaunchLatencyMetricKind::ResolverLookup => &mut metrics.resolver_lookup_latency_ms,
        TrainingLaunchLatencyMetricKind::SignedAccess => &mut metrics.signed_access_latency_ms,
    };
    if samples.len() >= TRAINING_LAUNCH_LATENCY_SAMPLE_LIMIT {
        samples.pop_front();
    }
    samples.push_back(latency_ms);
}

fn training_launch_latency_p95(samples: &VecDeque<u64>) -> Option<u64> {
    if samples.is_empty() {
        return None;
    }
    let mut values = samples.iter().copied().collect::<Vec<_>>();
    values.sort_unstable();
    let index = ((values.len() - 1) * 95) / 100;
    values.get(index).copied()
}

fn training_launch_live_metrics_snapshot(state: &AppState) -> TrainingLaunchLiveMetricsSnapshot {
    let Ok(metrics) = state.training_launch_metrics.read() else {
        return TrainingLaunchLiveMetricsSnapshot::default();
    };
    TrainingLaunchLiveMetricsSnapshot {
        resolver_lookup_latency_p95_ms: training_launch_latency_p95(
            &metrics.resolver_lookup_latency_ms,
        ),
        resolver_lookup_sample_count: metrics.resolver_lookup_latency_ms.len() as u64,
        signed_access_latency_p95_ms: training_launch_latency_p95(
            &metrics.signed_access_latency_ms,
        ),
        signed_access_sample_count: metrics.signed_access_latency_ms.len() as u64,
    }
}

fn sync_training_launch_health_alerts(health: &mut PublicTrainingLaunchHealthSnapshot) {
    let mut alerts = Vec::<PublicTrainingLaunchAlert>::new();

    if health.active_runs > 0 && health.run_backlog_slots > 0 {
        let severity = if health.run_backlog_slots >= health.active_runs {
            "critical"
        } else {
            "warning"
        };
        alerts.push(PublicTrainingLaunchAlert {
            alert_id: "run_backlog".to_string(),
            severity: severity.to_string(),
            title: "Run backlog".to_string(),
            detail: format!(
                "{} worker slots remain unfilled across {} active run(s).",
                health.run_backlog_slots, health.active_runs
            ),
        });
    }

    if health.pending_validation_windows > 0 || health.validator_challenges_queued > 0 {
        let severity = if health.pending_validation_windows > 0
            && health.validator_challenges_queued >= health.validator_challenges_open
        {
            "critical"
        } else {
            "warning"
        };
        alerts.push(PublicTrainingLaunchAlert {
            alert_id: "validator_backlog".to_string(),
            severity: severity.to_string(),
            title: "Validator backlog".to_string(),
            detail: format!(
                "{} pending window(s) // {} open challenge(s) // {} queued challenge(s).",
                health.pending_validation_windows,
                health.validator_challenges_open,
                health.validator_challenges_queued
            ),
        });
    }

    if health.accepted_work_attention_payout_count > 0
        || health.payouts_failed_24h > 0
        || health.payouts_skipped_24h > 0
    {
        alerts.push(PublicTrainingLaunchAlert {
            alert_id: "payout_lag".to_string(),
            severity: "critical".to_string(),
            title: "Payout attention required".to_string(),
            detail: format!(
                "{} accepted-work payout(s) need attention // failed 24h {} // skipped 24h {}.",
                health.accepted_work_attention_payout_count,
                health.payouts_failed_24h,
                health.payouts_skipped_24h
            ),
        });
    } else if health.accepted_work_pending_payout_count > 0 {
        alerts.push(PublicTrainingLaunchAlert {
            alert_id: "payout_pending".to_string(),
            severity: "warning".to_string(),
            title: "Accepted-work payouts pending".to_string(),
            detail: format!(
                "{} accepted-work payout(s) are still pending dispatch or confirmation.",
                health.accepted_work_pending_payout_count
            ),
        });
    }

    if health
        .resolver_lookup_latency_p95_ms
        .is_some_and(|value| value > TRAINING_ARTIFACT_RESOLVER_P95_MAX_MS)
    {
        alerts.push(PublicTrainingLaunchAlert {
            alert_id: "resolver_latency".to_string(),
            severity: if health
                .resolver_lookup_latency_p95_ms
                .is_some_and(|value| value > TRAINING_ARTIFACT_RESOLVER_P95_MAX_MS * 2)
            {
                "critical".to_string()
            } else {
                "warning".to_string()
            },
            title: "Artifact resolver latency".to_string(),
            detail: format!(
                "Resolver p95 is {} ms across {} recent sample(s).",
                health.resolver_lookup_latency_p95_ms.unwrap_or_default(),
                health.resolver_lookup_sample_count
            ),
        });
    }

    if health
        .signed_access_latency_p95_ms
        .is_some_and(|value| value > TRAINING_ARTIFACT_SIGNED_ACCESS_P95_MAX_MS)
    {
        alerts.push(PublicTrainingLaunchAlert {
            alert_id: "signed_access_latency".to_string(),
            severity: if health
                .signed_access_latency_p95_ms
                .is_some_and(|value| value > TRAINING_ARTIFACT_SIGNED_ACCESS_P95_MAX_MS * 2)
            {
                "critical".to_string()
            } else {
                "warning".to_string()
            },
            title: "Signed access latency".to_string(),
            detail: format!(
                "Signed-access p95 is {} ms across {} recent sample(s).",
                health.signed_access_latency_p95_ms.unwrap_or_default(),
                health.signed_access_sample_count
            ),
        });
    }

    if health.public_stats_age_ms > TRAINING_PUBLIC_SNAPSHOT_MAX_AGE_MS {
        alerts.push(PublicTrainingLaunchAlert {
            alert_id: "stale_snapshot".to_string(),
            severity: if health.public_stats_age_ms > TRAINING_PUBLIC_MIRROR_MAX_AGE_MS {
                "critical".to_string()
            } else {
                "warning".to_string()
            },
            title: "Public snapshot stale".to_string(),
            detail: format!(
                "Public stats are {} ms old from the {} snapshot path.",
                health.public_stats_age_ms, health.public_snapshot_source
            ),
        });
    }

    if health.public_state_drift_from_kernel_ms > TRAINING_PUBLIC_SNAPSHOT_MAX_AGE_MS {
        alerts.push(PublicTrainingLaunchAlert {
            alert_id: "public_state_drift".to_string(),
            severity: if health.public_state_drift_from_kernel_ms > TRAINING_PUBLIC_MIRROR_MAX_AGE_MS
            {
                "critical".to_string()
            } else {
                "warning".to_string()
            },
            title: "Public-state drift from kernel truth".to_string(),
            detail: format!(
                "The public training state may be drifting by {} ms because the snapshot is being served from cache.",
                health.public_state_drift_from_kernel_ms
            ),
        });
    }

    health.critical_alert_count = alerts
        .iter()
        .filter(|alert| alert.severity == "critical")
        .count() as u64;
    health.active_alert_count = alerts.len() as u64;
    health.overall_status = if health.critical_alert_count > 0 {
        "bad".to_string()
    } else if health.active_alert_count > 0 {
        "warn".to_string()
    } else {
        "good".to_string()
    };
    health.alerts = alerts;
}

fn apply_public_stats_cache_context(
    stats: &mut PublicStatsSnapshot,
    now_unix_ms: u64,
    source: &str,
) {
    let age_ms = now_unix_ms.saturating_sub(stats.as_of_unix_ms);
    let health = &mut stats.training_public_state.launch_health;
    health.generated_at_unix_ms = now_unix_ms;
    health.public_snapshot_source = source.to_string();
    health.public_stats_age_ms = age_ms;
    health.public_state_drift_from_kernel_ms = if source == "live" { 0 } else { age_ms };
    sync_training_launch_health_alerts(health);
}

fn cached_public_stats_snapshot(state: &AppState) -> Option<PublicStatsSnapshot> {
    state
        .public_stats_cache
        .read()
        .ok()
        .map(|snapshot| snapshot.clone())
}

fn refresh_public_stats_cache(state: &AppState, now_unix_ms: u64) -> Option<PublicStatsSnapshot> {
    if let Some(snapshot) = cached_public_stats_snapshot(state) {
        let age_ms = now_unix_ms.saturating_sub(snapshot.as_of_unix_ms);
        if age_ms < PUBLIC_STATS_CACHE_REFRESH_MIN_INTERVAL_MS {
            return Some(snapshot);
        }
    }

    let store = state.store.read().ok()?;
    let launch_metrics = training_launch_live_metrics_snapshot(state);
    let mut snapshot =
        build_public_stats_snapshot(&state.config, &store, &launch_metrics, now_unix_ms);
    drop(store);
    apply_public_stats_cache_context(&mut snapshot, now_unix_ms, "live");
    replace_public_stats_cache(state, snapshot.clone());
    Some(snapshot)
}

fn desktop_session_receipt_context(record: &DesktopSessionRecord) -> AuthorityReceiptContext {
    let mut attributes = std::collections::BTreeMap::new();
    attributes.insert(
        "desktop_client_id".to_string(),
        record.desktop_client_id.clone(),
    );
    if let Some(device_name) = record.device_name.clone() {
        attributes.insert("device_name".to_string(), device_name);
    }
    if let Some(client_version) = record.client_version.clone() {
        attributes.insert("client_version".to_string(), client_version);
    }
    if let Some(bound_nostr_pubkey) = record.bound_nostr_pubkey.clone() {
        attributes.insert("bound_nostr_pubkey".to_string(), bound_nostr_pubkey);
    }
    AuthorityReceiptContext {
        session_id: Some(record.session_id.clone()),
        account_id: Some(record.account_id.clone()),
        status: Some("issued".to_string()),
        attributes,
        ..AuthorityReceiptContext::default()
    }
}

fn sync_token_receipt_context(
    session: &DesktopSessionRecord,
    token: &SyncTokenRecord,
) -> AuthorityReceiptContext {
    let mut attributes = std::collections::BTreeMap::new();
    attributes.insert("rotation_id".to_string(), token.rotation_id.clone());
    attributes.insert("transport".to_string(), "spacetime_ws".to_string());
    attributes.insert(
        "protocol_version".to_string(),
        "spacetime.sync.v1".to_string(),
    );
    AuthorityReceiptContext {
        session_id: Some(session.session_id.clone()),
        account_id: Some(session.account_id.clone()),
        status: Some("issued".to_string()),
        attributes,
        ..AuthorityReceiptContext::default()
    }
}

fn starter_offer_receipt_context(
    session: Option<&DesktopSessionRecord>,
    offer: Option<&StarterDemandOfferRecord>,
    reason: Option<&str>,
    relay_url: Option<&str>,
    payment_pointer: Option<&str>,
) -> AuthorityReceiptContext {
    let mut attributes = std::collections::BTreeMap::new();
    if let Some(session) = session {
        attributes.insert(
            "desktop_client_id".to_string(),
            session.desktop_client_id.clone(),
        );
        if let Some(bound_nostr_pubkey) = session.bound_nostr_pubkey.clone() {
            attributes.insert("bound_nostr_pubkey".to_string(), bound_nostr_pubkey);
        }
    }
    if let Some(offer) = offer {
        attributes.insert("capability".to_string(), offer.capability.clone());
        attributes.insert("requester".to_string(), offer.requester.clone());
        attributes.insert("request_kind".to_string(), offer.request_kind.to_string());
    }
    AuthorityReceiptContext {
        session_id: session.map(|session| session.session_id.clone()),
        account_id: session.map(|session| session.account_id.clone()),
        request_id: offer.map(|offer| offer.request_id.clone()),
        status: offer.map(|offer| offer.status.label().to_string()),
        reason: reason.map(ToOwned::to_owned),
        relay_url: relay_url.map(ToOwned::to_owned),
        amount_sats: offer.map(|offer| offer.price_sats),
        payment_pointer: payment_pointer.map(ToOwned::to_owned),
        attributes,
    }
}

fn parse_u64_env(key: &str, default: u64) -> Result<u64, String> {
    std::env::var(key)
        .ok()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .map_or(Ok(default), |value| {
            value
                .parse::<u64>()
                .map_err(|error| format!("invalid {key}: {error}"))
        })
}

fn bearer_token_from_headers(headers: &HeaderMap) -> Result<&str, ApiError> {
    let header = headers
        .get(axum::http::header::AUTHORIZATION)
        .and_then(|value| value.to_str().ok())
        .ok_or_else(|| ApiError {
            status: StatusCode::UNAUTHORIZED,
            error: "unauthorized",
            reason: "missing_bearer_token".to_string(),
        })?;
    header
        .strip_prefix("Bearer ")
        .or_else(|| header.strip_prefix("bearer "))
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| ApiError {
            status: StatusCode::UNAUTHORIZED,
            error: "unauthorized",
            reason: "invalid_bearer_token".to_string(),
        })
}

fn authenticate_treasury_integration(
    state: &AppState,
    headers: &HeaderMap,
) -> Result<(), ApiError> {
    let expected = state
        .config
        .treasury
        .integration_token
        .as_deref()
        .filter(|value| !value.is_empty())
        .ok_or_else(|| ApiError {
            status: StatusCode::SERVICE_UNAVAILABLE,
            error: "service_unavailable",
            reason: "treasury_integration_disabled".to_string(),
        })?;
    let token = bearer_token_from_headers(headers)?;
    if token != expected {
        return Err(ApiError {
            status: StatusCode::UNAUTHORIZED,
            error: "unauthorized",
            reason: "invalid_treasury_integration_token".to_string(),
        });
    }
    Ok(())
}

fn parse_bool_env(key: &str, default: bool) -> Result<bool, String> {
    std::env::var(key)
        .ok()
        .map(|value| value.trim().to_ascii_lowercase())
        .filter(|value| !value.is_empty())
        .map_or(Ok(default), |value| match value.as_str() {
            "1" | "true" | "yes" | "on" => Ok(true),
            "0" | "false" | "no" | "off" => Ok(false),
            _ => Err(format!("invalid {key}: expected boolean")),
        })
}

fn parse_usize_env(key: &str, default: usize) -> Result<usize, String> {
    std::env::var(key)
        .ok()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .map_or(Ok(default), |value| {
            value
                .parse::<usize>()
                .map_err(|error| format!("invalid {key}: {error}"))
        })
}

fn normalize_required_field(value: &str, reason: &str) -> Result<String, ApiError> {
    let normalized = value.trim();
    if normalized.is_empty() {
        return Err(ApiError {
            status: StatusCode::BAD_REQUEST,
            error: "invalid_request",
            reason: reason.to_string(),
        });
    }
    Ok(normalized.to_string())
}

fn normalize_optional_field(value: Option<&str>) -> Option<String> {
    value
        .map(str::trim)
        .filter(|candidate| !candidate.is_empty())
        .map(ToOwned::to_owned)
}

fn normalize_string_vec(values: Vec<String>) -> Vec<String> {
    let mut normalized = values
        .into_iter()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .collect::<Vec<_>>();
    normalized.sort();
    normalized.dedup();
    normalized
}

fn normalize_provider_diagnostic_summaries(
    values: Vec<ProviderDiagnosticSummary>,
) -> Vec<ProviderDiagnosticSummary> {
    let mut normalized = values
        .into_iter()
        .filter_map(normalize_provider_diagnostic_summary)
        .collect::<Vec<_>>();
    normalized.sort_by(|left, right| {
        right
            .measured_at_unix_ms
            .cmp(&left.measured_at_unix_ms)
            .then_with(|| left.model_id.cmp(&right.model_id))
            .then_with(|| left.status.cmp(&right.status))
    });
    normalized.truncate(MAX_PROVIDER_DIAGNOSTIC_SUMMARIES);
    normalized
}

fn normalize_provider_diagnostic_summary(
    value: ProviderDiagnosticSummary,
) -> Option<ProviderDiagnosticSummary> {
    Some(ProviderDiagnosticSummary {
        diagnostic_id: normalize_optional_field(Some(value.diagnostic_id.as_str()))?,
        model_id: normalize_optional_field(Some(value.model_id.as_str()))?,
        runtime_backend: normalize_optional_field(Some(value.runtime_backend.as_str()))?,
        status: normalize_optional_field(Some(value.status.as_str()))?,
        reason: normalize_optional_field(value.reason.as_deref()),
        measured_at_unix_ms: value.measured_at_unix_ms,
        load_s: value.load_s,
        mean_total_s: value.mean_total_s,
        mean_ttft_s: value.mean_ttft_s,
        mean_decode_tok_s: value.mean_decode_tok_s,
        repeats: value.repeats,
    })
}

fn sanitize_identifier(value: &str) -> String {
    let sanitized = value
        .chars()
        .map(|character| {
            if character.is_ascii_alphanumeric() || character == '-' || character == '_' {
                character
            } else {
                '_'
            }
        })
        .collect::<String>();
    if sanitized.is_empty() {
        "desktop".to_string()
    } else {
        sanitized
    }
}

fn provider_presence_key(nostr_pubkey_hex: &str, session_id: &str) -> String {
    format!("{nostr_pubkey_hex}:{session_id}")
}

fn truncate_nostr_pubkey(nostr_pubkey_hex: &str) -> String {
    if nostr_pubkey_hex.len() <= 16 {
        nostr_pubkey_hex.to_string()
    } else {
        format!(
            "{}…{}",
            &nostr_pubkey_hex[..8],
            &nostr_pubkey_hex[nostr_pubkey_hex.len().saturating_sub(8)..]
        )
    }
}

fn training_run_display_name(run: &ComputeTrainingRun) -> Option<String> {
    ["display_name", "public_display_name", "run_label", "title"]
        .into_iter()
        .find_map(|key| {
            run.metadata
                .get(key)
                .and_then(Value::as_str)
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .map(str::to_string)
        })
}

fn random_token() -> String {
    hex::encode(rand::random::<[u8; 24]>())
}

fn now_unix_ms() -> u64 {
    std::time::SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map_or(0, |duration| duration.as_millis() as u64)
}

